static int colorDistanceRgb(const QColor &a, const QColor &b)
{
    return qAbs(a.red() - b.red()) + qAbs(a.green() - b.green()) + qAbs(a.blue() - b.blue());
}

static QColor averageEdgeColor(const QImage &img)
{
    const int w = img.width();
    const int h = img.height();
    if (w <= 0 || h <= 0) return QColor(Qt::white);

    const int step = qMax(1, qMin(w, h) / 40);
    qint64 r = 0, g = 0, b = 0;
    int cnt = 0;

    auto sample = [&](int x, int y) {
        const QColor c = img.pixelColor(x, y);
        r += c.red(); g += c.green(); b += c.blue(); ++cnt;
    };

    for (int x = 0; x < w; x += step) {
        sample(x, 0);
        sample(x, h - 1);
    }
    for (int y = 0; y < h; y += step) {
        sample(0, y);
        sample(w - 1, y);
    }

    if (cnt <= 0) return QColor(Qt::white);
    return QColor(int(r / cnt), int(g / cnt), int(b / cnt));
}

static int backgroundToleranceFor(const QColor &bg)
{
    const int brightness = (bg.red() + bg.green() + bg.blue()) / 3;
    if (brightness > 220 || brightness < 40) return 75;
    if (brightness > 180 || brightness < 70) return 65;
    return 55;
}

[[maybe_unused]] QImage removeLightBackgroundIfFlat(const QImage &src)
{
    QImage img = src.convertToFormat(QImage::Format_ARGB32);
    const int w = img.width();
    const int h = img.height();
    if (w < 2 || h < 2) return img;

    const QColor c1 = img.pixelColor(0, 0);
    const QColor c2 = img.pixelColor(w - 1, 0);
    const QColor c3 = img.pixelColor(0, h - 1);
    const QColor c4 = img.pixelColor(w - 1, h - 1);

    auto isLight = [](const QColor &c) {
        return c.red() > 220 && c.green() > 220 && c.blue() > 220;
    };

    if (!(isLight(c1) && isLight(c2) && isLight(c3) && isLight(c4))) {
        return img;
    }

    const QColor bg(
        (c1.red() + c2.red() + c3.red() + c4.red()) / 4,
        (c1.green() + c2.green() + c3.green() + c4.green()) / 4,
        (c1.blue() + c2.blue() + c3.blue() + c4.blue()) / 4
    );

    const int tol = 25;
    for (int y = 0; y < h; ++y) {
        QRgb *line = reinterpret_cast<QRgb*>(img.scanLine(y));
        for (int x = 0; x < w; ++x) {
            const QColor c = QColor::fromRgb(line[x]);
            if (qAbs(c.red() - bg.red()) <= tol &&
                qAbs(c.green() - bg.green()) <= tol &&
                qAbs(c.blue() - bg.blue()) <= tol) {
                line[x] = qRgba(c.red(), c.green(), c.blue(), 0);
            }
        }
    }
    return img;
}

[[maybe_unused]] QImage removeBackgroundByFloodFill(const QImage &src)
{
    QImage img = src.convertToFormat(QImage::Format_ARGB32);
    const int w = img.width();
    const int h = img.height();
    if (w < 2 || h < 2) return img;

    const QColor bg = averageEdgeColor(img);
    const int tol = backgroundToleranceFor(bg);

    QVector<uchar> visited(w * h, 0);
    QQueue<QPoint> q;

    auto matches = [&](int x, int y) {
        const QColor c = img.pixelColor(x, y);
        return colorDistanceRgb(c, bg) <= tol;
    };

    auto push = [&](int x, int y) {
        if (x < 0 || x >= w || y < 0 || y >= h) return;
        const int idx = y * w + x;
        if (visited[idx]) return;
        if (!matches(x, y)) return;
        visited[idx] = 1;
        q.enqueue(QPoint(x, y));
    };

    for (int x = 0; x < w; ++x) {
        push(x, 0);
        push(x, h - 1);
    }
    for (int y = 0; y < h; ++y) {
        push(0, y);
        push(w - 1, y);
    }

    while (!q.isEmpty()) {
        const QPoint p = q.dequeue();
        const QColor c = img.pixelColor(p);
        img.setPixelColor(p, QColor(c.red(), c.green(), c.blue(), 0));
        push(p.x() + 1, p.y());
        push(p.x() - 1, p.y());
        push(p.x(), p.y() + 1);
        push(p.x(), p.y() - 1);
    }

    return img;
}

QPixmap renderProduitImage(const QPixmap &src, const QSize &target)
{
    if (src.isNull() || target.isEmpty()) return src;
    QImage base = src.toImage();
    const int maxSide = 900;
    if (base.width() > maxSide || base.height() > maxSide) {
        base = base.scaled(maxSide, maxSide, Qt::KeepAspectRatio, Qt::SmoothTransformation);
    }
    QImage scaled = base.scaled(target, Qt::KeepAspectRatio, Qt::SmoothTransformation);
    return QPixmap::fromImage(scaled);
}

void applyProduitImageLabel(QLabel *lbl, const QString &imagePath, const QString &placeholder)
{
    if (!lbl) return;
    lbl->setAlignment(Qt::AlignCenter);
    int maxHeight = lbl->property("prodImageHeight").toInt();
    if (maxHeight <= 0) maxHeight = 170;
    int maxWidth = lbl->property("prodImageWidth").toInt();
    if (maxWidth <= 0) maxWidth = 260;
    const QSize maxSize(maxWidth, maxHeight);
    const QSize minSize(qMin(180, maxWidth), qMin(120, maxHeight));
    lbl->setSizePolicy(QSizePolicy::Fixed, QSizePolicy::Fixed);
    lbl->setScaledContents(false);

    if (!imagePath.isEmpty() && QFile::exists(imagePath)) {
        QPixmap pix(imagePath);
        if (!pix.isNull()) {
            const QPixmap scaled = renderProduitImage(pix, maxSize);
            const QSize finalSize = scaled.size().expandedTo(minSize);
            lbl->setFixedSize(finalSize);
            lbl->setPixmap(scaled);
            lbl->setText("");
            lbl->setStyleSheet("background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 14px;");
            return;
        }
    }

    lbl->clear();
    lbl->setText(placeholder);
    lbl->setFixedSize(maxSize);
    lbl->setStyleSheet("background: #f8fafc; border: 1px dashed #cbd5e1; border-radius: 14px; color: #94a3b8;");
}

static QList<int> selectedTechIdsFromCombo(QComboBox *combo)
{
    QList<int> ids;
    if (!combo) return ids;
    auto *model = qobject_cast<QStandardItemModel*>(combo->model());
    if (!model) return ids;
    for (int i = 0; i < model->rowCount(); ++i) {
        QStandardItem *item = model->item(i);
        if (!item) continue;
        if (item->checkState() != Qt::Checked) continue;
        const int id = item->data(Qt::UserRole).toInt();
        if (id > 0) ids << id;
    }
    return ids;
}

static QStringList selectedTechNamesFromCombo(QComboBox *combo)
{
    QStringList names;
    if (!combo) return names;
    auto *model = qobject_cast<QStandardItemModel*>(combo->model());
    if (!model) return names;
    for (int i = 0; i < model->rowCount(); ++i) {
        QStandardItem *item = model->item(i);
        if (!item) continue;
        if (item->checkState() != Qt::Checked) continue;
        const QString name = item->data(Qt::UserRole + 1).toString().trimmed();
        names << (name.isEmpty() ? item->text() : name);
    }
    return names;
}

static void clearComboChecks(QComboBox *combo)
{
    if (!combo) return;
    auto *model = qobject_cast<QStandardItemModel*>(combo->model());
    if (!model) return;
    for (int i = 0; i < model->rowCount(); ++i) {
        if (QStandardItem *item = model->item(i)) {
            if (item->flags() & Qt::ItemIsUserCheckable) {
                item->setCheckState(Qt::Unchecked);
            }
        }
    }
}

static void applyMaintenanceImageLabel(QLabel *lbl, const QString &imagePath, const QString &placeholder)
{
    if (!lbl) return;
    lbl->setAlignment(Qt::AlignCenter);
    const QSize targetSize = lbl->size().isEmpty() ? QSize(320, 180) : lbl->size();

    if (!imagePath.isEmpty() && QFile::exists(imagePath)) {
        QPixmap pix(imagePath);
        if (!pix.isNull()) {
            lbl->setPixmap(pix.scaled(targetSize, Qt::KeepAspectRatio, Qt::SmoothTransformation));
            lbl->setText("");
            lbl->setToolTip(imagePath);
            return;
        }
    }

    lbl->setPixmap(QPixmap());
    lbl->setText(placeholder);
    lbl->setToolTip(QString());
}

static void pickMaintenanceImages(MainWindow *w, QLabel *lbl, QString &storePath, bool allowMulti)
{
    if (!w || !lbl) return;
    const QString placeholder = lbl->property("maintPlaceholder").toString().isEmpty()
                                    ? lbl->text()
                                    : lbl->property("maintPlaceholder").toString();
    const QString filter = "Images (*.png *.jpg *.jpeg *.bmp *.webp)";
    QStringList files;
    if (allowMulti) {
        files = QFileDialog::getOpenFileNames(w, "Choisir des images", QString(), filter);
    } else {
        const QString file = QFileDialog::getOpenFileName(w, "Choisir une image", QString(), filter);
        if (!file.isEmpty()) files << file;
    }
    if (files.isEmpty()) return;

    storePath = allowMulti ? files.join(";") : files.first();
    applyMaintenanceImageLabel(lbl, files.first(), placeholder);
    if (allowMulti && files.size() > 1) {
        lbl->setToolTip(QString("%1 images selectionnees").arg(files.size()));
    }
}

static QHash<int, QPair<QString, QString>> m_maintInterventionPhotos;

static QStringList splitMaintenancePhotoPair(const QString &rawPaths)
{
    const QString raw = rawPaths.trimmed();
    if (raw.isEmpty()) {
        return {QString(), QString()};
    }

    QStringList parts = raw.split(';', Qt::KeepEmptyParts);
    if (parts.size() < 2) {
        const QString alt = raw.contains('|') ? raw : QString();
        if (!alt.isEmpty()) {
            parts = raw.split('|', Qt::KeepEmptyParts);
        }
    }

    if (parts.isEmpty()) {
        return {raw, QString()};
    }
    if (parts.size() == 1) {
        return {parts.at(0).trimmed(), QString()};
    }
    return {parts.at(0).trimmed(), parts.at(1).trimmed()};
}

static QString formatMaintenancePhotoPair(const QString &beforePath, const QString &afterPath)
{
    return QString("%1;%2").arg(beforePath.trimmed(), afterPath.trimmed());
}

static void openMaintenancePhotoPreview(QWidget *owner, const QString &path, const QString &title)
{
    const QString cleanPath = path.trimmed();
    if (cleanPath.isEmpty() || !QFile::exists(cleanPath)) {
        QMessageBox::information(owner, "Photo", "Aucune photo disponible.");
        return;
    }

    QPixmap pix(cleanPath);
    if (pix.isNull()) {
        QMessageBox::warning(owner, "Photo", "Impossible de charger l'image.");
        return;
    }

    auto *dlg = new QDialog(owner);
    dlg->setAttribute(Qt::WA_DeleteOnClose);
    dlg->setWindowTitle(title);
    dlg->resize(860, 620);

    auto *layout = new QVBoxLayout(dlg);
    layout->setContentsMargins(12, 12, 12, 12);

    auto *imgLabel = new QLabel(dlg);
    imgLabel->setAlignment(Qt::AlignCenter);
    imgLabel->setStyleSheet("background: #0f172a; border-radius: 8px;");
    imgLabel->setMinimumSize(640, 420);
    imgLabel->setPixmap(pix.scaled(820, 560, Qt::KeepAspectRatio, Qt::SmoothTransformation));

    auto *pathLabel = new QLabel(cleanPath, dlg);
    pathLabel->setWordWrap(true);
    pathLabel->setStyleSheet("color: #475569;");

    layout->addWidget(imgLabel, 1);
    layout->addWidget(pathLabel);
    dlg->show();
}

static QWidget *createMaintenancePhotoCell(MainWindow *owner, const QString &beforePath, const QString &afterPath)
{
    QWidget *container = new QWidget(owner);
    auto *layout = new QHBoxLayout(container);
    layout->setContentsMargins(4, 4, 4, 4);
    layout->setSpacing(6);

    auto buildThumbButton = [&](const QString &path, const QString &fallbackText, const QString &title) {
        auto *btn = new QPushButton(container);
        btn->setFixedSize(38, 38);
        btn->setCursor(Qt::PointingHandCursor);
        btn->setStyleSheet("QPushButton { border: 1px solid #cbd5e1; border-radius: 6px; background: #f8fafc; color: #64748b; font-size: 10px; }");

        const QString cleanPath = path.trimmed();
        if (!cleanPath.isEmpty() && QFile::exists(cleanPath)) {
            QPixmap pix(cleanPath);
            if (!pix.isNull()) {
                btn->setIcon(QIcon(pix));
                btn->setIconSize(QSize(34, 34));
                btn->setToolTip("Cliquer pour ouvrir: " + cleanPath);
                QObject::connect(btn, &QPushButton::clicked, owner, [owner, cleanPath, title]() {
                    openMaintenancePhotoPreview(owner, cleanPath, title);
                });
                return btn;
            }
        }

        btn->setText(fallbackText);
        btn->setToolTip("Aucune photo");
        return btn;
    };

    layout->addWidget(buildThumbButton(beforePath, "AV", "Photo Avant"));
    layout->addWidget(buildThumbButton(afterPath, "AP", "Photo Apres"));
    return container;
}

static QComboBox *ensureMaintenanceTechModCombo(MainWindow *w)
{
    if (!w) return nullptr;
    if (auto *existing = w->findChild<QComboBox*>("cbTechMod")) return existing;
    QLineEdit *editTechMod = w->findChild<QLineEdit*>("editTechMod");
    QWidget *pageMaintMod = w->findChild<QWidget*>("page_Maint_Modif");
    if (!editTechMod) return nullptr;

    QComboBox *combo = new QComboBox(editTechMod->parentWidget());
    combo->setObjectName("cbTechMod");
    combo->setEditable(true);
    combo->setSizePolicy(editTechMod->sizePolicy());
    combo->setMinimumHeight(editTechMod->minimumHeight());
    combo->setStyleSheet(editTechMod->styleSheet());
    if (combo->lineEdit()) {
        combo->lineEdit()->setPlaceholderText(editTechMod->placeholderText());
    }

    QLayout *layout = nullptr;
    if (auto *vbox = w->findChild<QVBoxLayout*>("vboxLayout21")) {
        layout = vbox;
    } else {
        layout = findLayoutContaining(pageMaintMod ? pageMaintMod : editTechMod->parentWidget(), editTechMod);
    }

    if (layout) {
        const int idx = layout->indexOf(editTechMod);
        layout->removeWidget(editTechMod);
        editTechMod->hide();

        if (auto *box = qobject_cast<QBoxLayout*>(layout)) {
            box->insertWidget(idx >= 0 ? idx : box->count(), combo);
        } else if (auto *form = qobject_cast<QFormLayout*>(layout)) {
            const int row = idx >= 0 ? idx : form->rowCount();
            form->insertRow(row, combo);
        } else if (auto *grid = qobject_cast<QGridLayout*>(layout)) {
            const int row = grid->rowCount();
            grid->addWidget(combo, row, 0, 1, 1);
        } else {
            layout->addWidget(combo);
        }
    } else {
        editTechMod->hide();
        combo->setGeometry(editTechMod->geometry());
    }

    return combo;
}

