static void setMaintenanceTypeComboValue(QComboBox *combo, const QString &value)
{
    if (!combo) return;
    const QString normalized = value.trimmed().toLower();
    if (normalized.contains("preven") || normalized.contains("prevent")) {
        combo->setCurrentText("Preventive");
    } else {
        combo->setCurrentText("Curative");
    }
}

static QComboBox *ensureMaintenanceTypeCombo(MainWindow *w, bool modification)
{
    if (!w) return nullptr;

    const QString comboName = modification ? "cbTypeMod" : "cbTypeAdd";
    const bool comboAlreadyExists = (w->findChild<QComboBox*>(comboName) != nullptr);
    QLineEdit *typeEdit = w->findChild<QLineEdit*>(modification ? "editTypeMod" : "editTypeAdd");
    QLabel *typeLabel = w->findChild<QLabel*>(modification ? "lblTypeMod" : "lblTypeAdd");
    QComboBox *prioCombo = w->findChild<QComboBox*>(modification ? "comboPrioMod" : "comboPrioAdd");
    if (!typeEdit || !prioCombo) return nullptr;

    QComboBox *combo = w->findChild<QComboBox*>(comboName);
    if (!combo) {
        combo = new QComboBox(typeEdit->parentWidget());
        combo->setObjectName(comboName);
        combo->setSizePolicy(prioCombo->sizePolicy());
        combo->setMinimumHeight(prioCombo->minimumHeight());
        combo->setStyleSheet(prioCombo->styleSheet());
        combo->addItems({"Curative", "Preventive"});
        combo->setEditable(false);
    }

    const QString containerName = modification ? "maintTypeContainerMod" : "maintTypeContainerAdd";
    QWidget *typeContainer = w->findChild<QWidget*>(containerName);
    if (!typeContainer) {
        typeContainer = new QWidget(typeEdit->parentWidget());
        typeContainer->setObjectName(containerName);
        auto *v = new QVBoxLayout(typeContainer);
        v->setContentsMargins(0, 0, 0, 0);
        v->setSpacing(6);

        auto *runtimeLabel = new QLabel("Type", typeContainer);
        runtimeLabel->setObjectName(modification ? "lblTypeModRuntime" : "lblTypeAddRuntime");
        runtimeLabel->setProperty("class", "formLabel");
        v->addWidget(runtimeLabel);
        v->addWidget(combo);
    } else {
        if (auto *v = qobject_cast<QVBoxLayout*>(typeContainer->layout())) {
            if (combo->parentWidget() != typeContainer) {
                combo->setParent(typeContainer);
                v->addWidget(combo);
            }
        }
    }

    QHBoxLayout *prioLayout = w->findChild<QHBoxLayout*>(modification ? "hlPrioMod" : "hlPrioAdd");
    if (prioLayout) {
        if (auto *parentBox = qobject_cast<QBoxLayout*>(prioLayout->parent())) {
            int prioIndex = -1;
            for (int i = 0; i < parentBox->count(); ++i) {
                if (QLayoutItem *it = parentBox->itemAt(i)) {
                    if (it->layout() == prioLayout) {
                        prioIndex = i;
                        break;
                    }
                }
            }

            if (parentBox->indexOf(typeContainer) < 0) {
                parentBox->insertWidget(prioIndex >= 0 ? prioIndex + 1 : parentBox->count(), typeContainer);
            }
        }
    }

    if (typeLabel) typeLabel->hide();
    typeEdit->hide();
    // Initialize from legacy text only once; do not overwrite user selection on later calls.
    if (!comboAlreadyExists) {
        setMaintenanceTypeComboValue(combo, typeEdit->text());
    }
    return combo;
}

