void setComboTextSafe(QComboBox *combo, const QString &value)
{
    if (!combo) return;
    int idx = combo->findText(value, Qt::MatchFixedString);
    if (idx < 0) idx = combo->findText(value, Qt::MatchContains);
    if (idx < 0) {
        combo->addItem(value);
        idx = combo->findText(value, Qt::MatchFixedString);
    }
    if (idx >= 0) combo->setCurrentIndex(idx);
}

QString produitValidationStyle(QWidget *widget, bool valid)
{
    const QString border = valid ? "#16a34a" : "#dc2626";
    const QString background = valid ? "#f0fdf4" : "#fef2f2";
    QString selector = widget ? widget->metaObject()->className() : QString();

    if (widget && widget->inherits("QAbstractSpinBox")) {
        selector = "QAbstractSpinBox";
    } else if (widget && widget->inherits("QComboBox")) {
        selector = "QComboBox";
    } else if (widget && widget->inherits("QLineEdit")) {
        selector = "QLineEdit";
    }

    if (selector.isEmpty()) {
        return QString("border: 1px solid %1; border-radius: 6px; background-color: %2;")
            .arg(border, background);
    }

    return QString(
               "%1 {"
               " border: 1px solid %2;"
               " border-radius: 6px;"
               " padding: 4px 8px;"
               " background-color: %3;"
               "}"
           ).arg(selector, border, background);
}

