QString generatedProduitBarcodeValue()
{
    int nextId = 1;
    QSqlQuery q;
    if (q.exec("SELECT NVL(MAX(id_bac), 0) + 1 FROM BAC_INTEL") && q.next() && !q.value(0).isNull()) {
        nextId = q.value(0).toInt();
    }
    nextId = qMax(1, nextId);

    auto eanCheckDigit = [](const QString &body12) -> int {
        if (body12.size() != 12) return 0;
        int sumOdd = 0;
        int sumEven = 0;
        for (int i = 0; i < body12.size(); ++i) {
            const int digit = body12.mid(i, 1).toInt();
            if ((i % 2) == 0) sumOdd += digit;
            else sumEven += digit;
        }
        const int total = sumOdd + (sumEven * 3);
        return (10 - (total % 10)) % 10;
    };

    const QString body12 = QString("2%1%2")
        .arg(QDate::currentDate().toString("yyMMdd"))
        .arg(nextId, 5, 10, QChar('0'));

    return body12 + QString::number(eanCheckDigit(body12));
}

bool isValidEan13Code(const QString &code)
{
    if (code.size() != 13) return false;
    for (const QChar ch : code) {
        if (!ch.isDigit()) return false;
    }

    const QString body12 = code.left(12);
    int sumOdd = 0;
    int sumEven = 0;
    for (int i = 0; i < body12.size(); ++i) {
        const int digit = body12.mid(i, 1).toInt();
        if ((i % 2) == 0) sumOdd += digit;
        else sumEven += digit;
    }
    const int total = sumOdd + (sumEven * 3);
    const int checkDigit = (10 - (total % 10)) % 10;
    return code.right(1).toInt() == checkDigit;
}

QPixmap renderEan13BarcodePixmap(const QString &code, const QSize &targetSize = QSize(260, 92))
{
    QPixmap fallback(qMax(160, targetSize.width()), qMax(70, targetSize.height()));
    fallback.fill(Qt::white);

    if (!isValidEan13Code(code)) {
        QPainter fallbackPainter(&fallback);
        fallbackPainter.setPen(QColor("#0f172a"));
        fallbackPainter.setFont(QFont("Consolas", 11, QFont::Bold));
        fallbackPainter.drawText(fallback.rect(), Qt::AlignCenter, code);
        return fallback;
    }

    static const QStringList leftOdd = {
        "0001101", "0011001", "0010011", "0111101", "0100011",
        "0110001", "0101111", "0111011", "0110111", "0001011"
    };
    static const QStringList leftEven = {
        "0100111", "0110011", "0011011", "0100001", "0011101",
        "0111001", "0000101", "0010001", "0001001", "0010111"
    };
    static const QStringList rightCodes = {
        "1110010", "1100110", "1101100", "1000010", "1011100",
        "1001110", "1010000", "1000100", "1001000", "1110100"
    };
    static const QStringList parity = {
        "OOOOOO", "OOEOEE", "OOEEOE", "OOEEEO", "OEOOEE",
        "OEEOOE", "OEEEOO", "OEOEOE", "OEOEEO", "OEEOEO"
    };

    QString pattern = "101";
    const int firstDigit = code.mid(0, 1).toInt();
    const QString parityPattern = parity.value(firstDigit, "OOOOOO");
    for (int i = 1; i <= 6; ++i) {
        const int digit = code.mid(i, 1).toInt();
        pattern += (parityPattern.mid(i - 1, 1) == "E") ? leftEven[digit] : leftOdd[digit];
    }
    pattern += "01010";
    for (int i = 7; i <= 12; ++i) {
        const int digit = code.mid(i, 1).toInt();
        pattern += rightCodes[digit];
    }
    pattern += "101";

    const int quietModules = 10;
    const int totalModules = pattern.size() + (quietModules * 2);
    const int width = qMax(220, targetSize.width());
    const int height = qMax(90, targetSize.height());
    const qreal moduleWidth = qMax<qreal>(1.0, static_cast<qreal>(width - 16) / static_cast<qreal>(totalModules));

    QPixmap pix(width, height);
    pix.fill(Qt::white);

    QPainter p(&pix);
    p.setRenderHint(QPainter::Antialiasing, false);
    p.setPen(Qt::NoPen);
    p.setBrush(Qt::black);

    const int leftMargin = 8;
    const int topMargin = 8;
    const int barTop = topMargin;
    const int barHeight = height - 30;
    const int normalHeight = barHeight - 10;
    const int xStart = leftMargin + static_cast<int>(quietModules * moduleWidth);

    for (int i = 0; i < pattern.size(); ++i) {
        if (pattern.at(i) != '1') continue;
        const bool isGuard =
            (i < 3) ||
            (i >= 45 && i < 50) ||
            (i >= 92);
        const int barX = xStart + static_cast<int>(i * moduleWidth);
        const int barW = qMax(1, static_cast<int>(std::ceil(moduleWidth)));
        const int currentHeight = isGuard ? barHeight : normalHeight;
        p.drawRect(barX, barTop, barW, currentHeight);
    }

    p.setPen(QColor("#0f172a"));
    p.setFont(QFont("Arial", 8));

    const int textBaseline = height - 6;
    p.drawText(QRect(leftMargin, textBaseline - 12, 16, 12), Qt::AlignLeft | Qt::AlignVCenter, code.left(1));

    const int leftDigitsX = xStart + static_cast<int>(3 * moduleWidth);
    const int leftDigitsW = static_cast<int>(42 * moduleWidth);
    const int rightDigitsX = xStart + static_cast<int>(50 * moduleWidth);
    const int rightDigitsW = static_cast<int>(42 * moduleWidth);

    p.drawText(QRect(leftDigitsX, textBaseline - 12, leftDigitsW, 12),
               Qt::AlignJustify | Qt::AlignVCenter, code.mid(1, 6));
    p.drawText(QRect(rightDigitsX, textBaseline - 12, rightDigitsW, 12),
               Qt::AlignJustify | Qt::AlignVCenter, code.mid(7, 6));

    return pix;
}

QLabel *ensureProduitBarcodePreviewLabel(MainWindow *window, bool modification)
{
    if (!window) return nullptr;
    const char *lineName = modification ? "prod_ln_ref_mod" : "prod_ln_ref_add";
    const char *gridName = modification ? "prod_gl_inputs_mod" : "prod_gl_inputs";
    const char *wrapName = modification ? "prod_barcodeWrap_Mod" : "prod_barcodeWrap_Add";
    const char *labelName = modification ? "prod_lblBarcodePreview_Mod" : "prod_lblBarcodePreview_Add";

    if (QLabel *existing = window->findChild<QLabel*>(labelName)) return existing;

    QLineEdit *line = window->findChild<QLineEdit*>(lineName);
    QGridLayout *grid = window->findChild<QGridLayout*>(gridName);
    if (!line || !grid) return nullptr;

    QWidget *wrapper = window->findChild<QWidget*>(wrapName);
    if (!wrapper) {
        const int index = grid->indexOf(line);
        if (index < 0) return nullptr;

        int row = 0;
        int column = 0;
        int rowSpan = 1;
        int colSpan = 1;
        grid->getItemPosition(index, &row, &column, &rowSpan, &colSpan);
        grid->removeWidget(line);

        wrapper = new QWidget(line->parentWidget());
        wrapper->setObjectName(wrapName);
        wrapper->setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Fixed);

        auto *wrapperLayout = new QVBoxLayout(wrapper);
        wrapperLayout->setContentsMargins(0, 0, 0, 0);
        wrapperLayout->setSpacing(4);
        wrapperLayout->addWidget(line);

        grid->addWidget(wrapper, row, column, rowSpan, colSpan);
    }

    QVBoxLayout *layout = qobject_cast<QVBoxLayout*>(wrapper->layout());
    if (!layout) return nullptr;

    QLabel *label = new QLabel(wrapper);
    label->setObjectName(labelName);
    label->setAlignment(Qt::AlignCenter);
    label->setMinimumHeight(56);
    label->setMaximumHeight(64);
    label->setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Fixed);
    label->setStyleSheet(
        "QLabel {"
        " background: #ffffff;"
        " border: 1px solid #dbe4ee;"
        " border-radius: 8px;"
        " padding: 4px 6px;"
        "}"
    );
    layout->addWidget(label);
    return label;
}

