void setProduitValidationState(QWidget *widget, bool valid, const QString &tooltip = QString())
{
    if (!widget) return;
    widget->setStyleSheet(produitValidationStyle(widget, valid));
    widget->setToolTip(tooltip);
}

QString produitModeleSaisi(MainWindow *window, bool modification)
{
    if (!window) return QString();

    const char *lineName = modification ? "prod_ln_model_mod" : "prod_ln_model_add";
    const char *comboName = modification ? "prod_cb_model_mod" : "prod_cb_model_add";

    if (QLineEdit *line = window->findChild<QLineEdit*>(lineName)) {
        const QString text = line->text().trimmed();
        if (!text.isEmpty()) return text;
    }

    if (QComboBox *combo = window->findChild<QComboBox*>(comboName)) {
        return combo->currentText().trimmed();
    }

    return QString();
}

QStringList produitValidationIssues(MainWindow *window, bool modification, bool applyUiFeedback = true)
{
    if (!window) return {};

    const char *refName = modification ? "prod_ln_ref_mod" : "prod_ln_ref_add";
    const char *modelLineName = modification ? "prod_ln_model_mod" : "prod_ln_model_add";
    const char *modelComboName = modification ? "prod_cb_model_mod" : "prod_cb_model_add";
    const char *priceName = modification ? "prod_dsb_price_mod" : "prod_dsb_price_add";
    const char *buttonName = modification ? "prod_btnSave_Mod" : "prod_btnSave_Add";

    QLineEdit *refEdit = window->findChild<QLineEdit*>(refName);
    QLineEdit *modelLine = window->findChild<QLineEdit*>(modelLineName);
    QComboBox *modelCombo = window->findChild<QComboBox*>(modelComboName);
    QDoubleSpinBox *priceSpin = window->findChild<QDoubleSpinBox*>(priceName);
    QPushButton *saveButton = window->findChild<QPushButton*>(buttonName);

    const QString reference = refEdit ? refEdit->text().trimmed() : QString();
    const QString modele = produitModeleSaisi(window, modification);
    const double prix = priceSpin ? priceSpin->value() : 0.0;

    const bool referenceOk = !reference.isEmpty();
    const bool modeleOk = !modele.isEmpty();
    const bool prixOk = prix > 0.0;

    QStringList issues;
    if (!referenceOk) issues << "code-barres obligatoire";
    if (!modeleOk) issues << "modele obligatoire";
    if (!prixOk) issues << "prix strictement positif";

    if (applyUiFeedback) {
        if (refEdit) {
            setProduitValidationState(refEdit, referenceOk, referenceOk ? "Code-barres valide." : "Le code-barres est obligatoire.");
        }

        if (modelLine) {
            setProduitValidationState(modelLine, modeleOk, modeleOk ? "Modele valide." : "Le modele est obligatoire.");
        } else if (modelCombo) {
            setProduitValidationState(modelCombo, modeleOk, modeleOk ? "Modele valide." : "Le modele est obligatoire.");
        }

        if (priceSpin) {
            setProduitValidationState(priceSpin, prixOk, prixOk ? "Prix valide." : "Le prix doit etre strictement positif.");
        }

        if (saveButton) {
            const QString tooltip = issues.isEmpty()
                ? (modification
                       ? "Tous les champs obligatoires sont valides. Cliquez pour sauvegarder."
                       : "Tous les champs obligatoires sont valides. Cliquez pour ajouter.")
                : QString("Champs a corriger : %1.").arg(issues.join(", "));
            saveButton->setToolTip(tooltip);
        }
    }

    return issues;
}

void refreshProduitRealtimeValidation(MainWindow *window, bool modification)
{
    produitValidationIssues(window, modification, true);
}

QString produitValidationMessage(const QStringList &issues)
{
    if (issues.isEmpty()) return QString();
    return "Veuillez corriger les champs suivants :\n- " + issues.join("\n- ");
}

QString firstNonEmptyLineEditText(QWidget *scope, const QStringList &preferredNames)
{
    if (!scope) return QString();

    auto byName = [scope](const QString &name) -> QString {
        if (auto *le = scope->findChild<QLineEdit*>(name)) {
            return le->text().trimmed();
        }
        return QString();
    };

    for (const QString &name : preferredNames) {
        const QString v = byName(name);
        if (!v.isEmpty()) return v;
    }

    const auto edits = scope->findChildren<QLineEdit*>();
    for (QLineEdit *le : edits) {
        if (!le || !le->isVisible()) continue;
        const QString v = le->text().trimmed();
        if (!v.isEmpty()) return v;
    }

    return QString();
}

double parseStockPrice(QString text, bool *okOut = nullptr)
{
    text = text.trimmed();
    text.remove("TND", Qt::CaseInsensitive);
    text.remove("DT", Qt::CaseInsensitive);
    text.remove(' ');
    text.replace(',', '.');
    bool ok = false;
    const double v = text.toDouble(&ok);
    if (okOut) *okOut = ok;
    return v;
}

static constexpr int CMD_BAC_ROLE_ID = Qt::UserRole + 320;
static constexpr int CMD_BAC_ROLE_PRICE = Qt::UserRole + 321;

struct CommandeBacSelection
{
    int idBac = 0;
    int quantite = 0;
    double prixUnitaire = 0.0;
};

bool ensureCommandeBacTableExists(QString *errorText = nullptr)
{
    QSqlDatabase db = QSqlDatabase::database();
    if (!db.isValid() || !db.isOpen()) {
        if (errorText) *errorText = "Connexion a la base de donnees indisponible.";
        return false;
    }

    QSqlQuery query(db);
    const QString driver = db.driverName().toUpper();
    bool ok = false;

    if (driver.contains("OCI") || driver.contains("ODBC") || driver.contains("ORA")) {
        ok = query.exec(
            "BEGIN "
            "  EXECUTE IMMEDIATE 'CREATE TABLE COMMANDE_BAC ("
            "    ID_COMMANDE NUMBER NOT NULL,"
            "    ID_BAC NUMBER NOT NULL,"
            "    QTE NUMBER NOT NULL,"
            "    PRIX_UNITAIRE NUMBER(12,3) DEFAULT 0 NOT NULL,"
            "    CONSTRAINT PK_COMMANDE_BAC PRIMARY KEY (ID_COMMANDE, ID_BAC),"
            "    CONSTRAINT FK_COMMANDE_BAC_CMD FOREIGN KEY (ID_COMMANDE) REFERENCES COMMANDE(ID_COMMANDE) ON DELETE CASCADE,"
            "    CONSTRAINT FK_COMMANDE_BAC_BAC FOREIGN KEY (ID_BAC) REFERENCES BAC_INTEL(ID_BAC),"
            "    CONSTRAINT CK_COMMANDE_BAC_QTE CHECK (QTE > 0),"
            "    CONSTRAINT CK_COMMANDE_BAC_PRIX CHECK (PRIX_UNITAIRE >= 0)"
            "  )';"
            "EXCEPTION "
            "  WHEN OTHERS THEN "
            "    IF SQLCODE != -955 THEN "
            "      RAISE;"
            "    END IF;"
            "END;"
        );
        if (ok) {
            QSqlQuery indexQuery(db);
            indexQuery.exec(
                "BEGIN "
                "  EXECUTE IMMEDIATE 'CREATE INDEX IDX_COMMANDE_BAC_BAC ON COMMANDE_BAC(ID_BAC)';"
                "EXCEPTION "
                "  WHEN OTHERS THEN "
                "    IF SQLCODE != -955 THEN "
                "      RAISE;"
                "    END IF;"
                "END;"
            );
        }
    } else {
        ok = query.exec(
            "CREATE TABLE IF NOT EXISTS COMMANDE_BAC ("
            "  ID_COMMANDE INTEGER NOT NULL,"
            "  ID_BAC INTEGER NOT NULL,"
            "  QTE INTEGER NOT NULL CHECK (QTE > 0),"
            "  PRIX_UNITAIRE REAL NOT NULL DEFAULT 0 CHECK (PRIX_UNITAIRE >= 0),"
            "  PRIMARY KEY (ID_COMMANDE, ID_BAC),"
            "  FOREIGN KEY (ID_COMMANDE) REFERENCES COMMANDE(ID_COMMANDE) ON DELETE CASCADE,"
            "  FOREIGN KEY (ID_BAC) REFERENCES BAC_INTEL(ID_BAC)"
            ")"
        );
        if (ok) {
            QSqlQuery indexQuery(db);
            indexQuery.exec("CREATE INDEX IF NOT EXISTS IDX_COMMANDE_BAC_BAC ON COMMANDE_BAC(ID_BAC)");
        }
    }

    if (!ok && errorText) {
        *errorText = query.lastError().text();
    }
    return ok;
}

QSpinBox *commandeBacSpinBox(QListWidget *list, QListWidgetItem *item)
{
    if (!list || !item) return nullptr;
    QWidget *rowWidget = list->itemWidget(item);
    if (!rowWidget) return nullptr;
    return rowWidget->findChild<QSpinBox*>("cmdBacQtySpin");
}

int commandeBacSpinValue(QListWidget *list, QListWidgetItem *item)
{
    if (QSpinBox *spin = commandeBacSpinBox(list, item)) {
        return spin->value();
    }
    return 0;
}

QWidget *buildCommandeBacRowWidget(const QString &reference,
                                   const QString &modele,
                                   int stockDisponible,
                                   double prixUnitaire,
                                   int maxQuantite,
                                   int quantiteInitiale,
                                   const std::function<void()> &onQuantityChanged)
{
    auto *container = new QWidget();
    container->setStyleSheet(
        "QWidget { background-color: #f8fafc; border: 1px solid #e2e8f0; border-radius: 10px; }"
        "QLabel { border: none; background: transparent; color: #0f172a; }"
        "QSpinBox { min-width: 76px; padding: 4px 6px; border: 1px solid #cbd5e1; border-radius: 8px; background: white; }"
    );

    auto *layout = new QHBoxLayout(container);
    layout->setContentsMargins(12, 10, 12, 10);
    layout->setSpacing(12);

    auto *textLayout = new QVBoxLayout();
    textLayout->setSpacing(2);

    auto *title = new QLabel(QString("%1 - %2")
                                 .arg(reference.isEmpty() ? "Bac" : reference)
                                 .arg(modele.isEmpty() ? "Modele" : modele),
                             container);
    QFont titleFont = title->font();
    titleFont.setBold(true);
    title->setFont(titleFont);

    const QString details = QString("Stock disponible: %1    |    Prix unitaire: %2 TND")
                                .arg(stockDisponible)
                                .arg(QLocale(QLocale::French).toString(prixUnitaire, 'f', 2));
    auto *detailLabel = new QLabel(details, container);
    detailLabel->setStyleSheet("color: #475569;");

    textLayout->addWidget(title);
    textLayout->addWidget(detailLabel);
    layout->addLayout(textLayout, 1);

    auto *qtyLabel = new QLabel("Quantite", container);
    qtyLabel->setStyleSheet("font-weight: 600; color: #1e3a5f;");
    auto *spin = new QSpinBox(container);
    spin->setObjectName("cmdBacQtySpin");
    spin->setRange(0, qMax(0, maxQuantite));
    spin->setValue(qBound(0, quantiteInitiale, qMax(0, maxQuantite)));
    spin->setButtonSymbols(QAbstractSpinBox::PlusMinus);
    spin->setToolTip(QString("Maximum autorise pour ce bac: %1").arg(maxQuantite));

    layout->addWidget(qtyLabel, 0, Qt::AlignVCenter);
    layout->addWidget(spin, 0, Qt::AlignVCenter);

    QObject::connect(spin, qOverload<int>(&QSpinBox::valueChanged), container, [onQuantityChanged](int) {
        if (onQuantityChanged) onQuantityChanged();
    });

    return container;
}

void collectCommandeBacSelections(QListWidget *list,
                                  QList<CommandeBacSelection> &selections,
                                  int &totalQuantite,
                                  double &totalPrix)
{
    selections.clear();
    totalQuantite = 0;
    totalPrix = 0.0;
    if (!list) return;

    for (int i = 0; i < list->count(); ++i) {
        QListWidgetItem *item = list->item(i);
        if (!item) continue;

        const int quantite = commandeBacSpinValue(list, item);
        if (quantite <= 0) continue;

        CommandeBacSelection selection;
        selection.idBac = item->data(CMD_BAC_ROLE_ID).toInt();
        selection.quantite = quantite;
        selection.prixUnitaire = item->data(CMD_BAC_ROLE_PRICE).toDouble();
        if (selection.idBac <= 0) continue;

        selections.append(selection);
        totalQuantite += selection.quantite;
        totalPrix += selection.quantite * selection.prixUnitaire;
    }
}

bool restoreCommandeBacSelectionsToStock(int idCmd, QString *errorText = nullptr)
{
    if (idCmd <= 0) return true;

    if (!ensureCommandeBacTableExists(errorText)) {
        return false;
    }

    QSqlDatabase db = QSqlDatabase::database();
    QSqlQuery restoreQuery(db);
    restoreQuery.prepare(
        "UPDATE BAC_INTEL "
        "SET STOCK = NVL(STOCK, 0) + ("
        "    SELECT NVL(SUM(cb.QTE), 0) "
        "    FROM COMMANDE_BAC cb "
        "    WHERE cb.ID_COMMANDE = :id_cmd AND cb.ID_BAC = BAC_INTEL.ID_BAC"
        ") "
        "WHERE EXISTS ("
        "    SELECT 1 FROM COMMANDE_BAC cb "
        "    WHERE cb.ID_COMMANDE = :id_cmd AND cb.ID_BAC = BAC_INTEL.ID_BAC"
        ")"
    );
    restoreQuery.bindValue(":id_cmd", idCmd);
    if (!restoreQuery.exec()) {
        if (errorText) *errorText = restoreQuery.lastError().text();
        return false;
    }

    QSqlQuery deleteQuery(db);
    deleteQuery.prepare("DELETE FROM COMMANDE_BAC WHERE ID_COMMANDE = :id_cmd");
    deleteQuery.bindValue(":id_cmd", idCmd);
    if (!deleteQuery.exec()) {
        if (errorText) *errorText = deleteQuery.lastError().text();
        return false;
    }

    QSqlQuery legacyReset(db);
    legacyReset.prepare("UPDATE BAC_INTEL SET ID_COMMANDE = NULL WHERE ID_COMMANDE = :id_cmd");
    legacyReset.bindValue(":id_cmd", idCmd);
    legacyReset.exec();
    return true;
}

bool applyCommandeBacSelections(int idCmd, const QList<CommandeBacSelection> &selections, QString *errorText = nullptr)
{
    if (idCmd <= 0) {
        if (errorText) *errorText = "Commande invalide.";
        return false;
    }
    if (!ensureCommandeBacTableExists(errorText)) {
        return false;
    }

    QSqlDatabase db = QSqlDatabase::database();
    QSqlQuery stockQuery(db);
    QSqlQuery updateStock(db);
    QSqlQuery insertLine(db);

    for (const CommandeBacSelection &selection : selections) {
        stockQuery.prepare("SELECT NVL(STOCK, 0) FROM BAC_INTEL WHERE ID_BAC = :id_bac");
        stockQuery.bindValue(":id_bac", selection.idBac);
        if (!stockQuery.exec() || !stockQuery.next()) {
            if (errorText) *errorText = stockQuery.lastError().text();
            return false;
        }
        if (stockQuery.value(0).toInt() < selection.quantite) {
            if (errorText) {
                *errorText = QString("Stock insuffisant pour le bac ID %1.").arg(selection.idBac);
            }
            return false;
        }

        updateStock.prepare(
            "UPDATE BAC_INTEL "
            "SET STOCK = NVL(STOCK, 0) - :qte "
            "WHERE ID_BAC = :id_bac"
        );
        updateStock.bindValue(":qte", selection.quantite);
        updateStock.bindValue(":id_bac", selection.idBac);
        if (!updateStock.exec()) {
            if (errorText) *errorText = updateStock.lastError().text();
            return false;
        }

        insertLine.prepare(
            "INSERT INTO COMMANDE_BAC (ID_COMMANDE, ID_BAC, QTE, PRIX_UNITAIRE) "
            "VALUES (:id_cmd, :id_bac, :qte, :prix)"
        );
        insertLine.bindValue(":id_cmd", idCmd);
        insertLine.bindValue(":id_bac", selection.idBac);
        insertLine.bindValue(":qte", selection.quantite);
        insertLine.bindValue(":prix", selection.prixUnitaire);
        if (!insertLine.exec()) {
            if (errorText) *errorText = insertLine.lastError().text();
            return false;
        }
    }

    return true;
}

QString stockSeuilLabel(int quantite, int seuilCritique)
{
    Q_UNUSED(seuilCritique);
    if (quantite < 10) return "CRITIQUE";
    if (quantite <= 20) return "MOYEN";
    return "OK";
}

[[maybe_unused]] int defaultSeuilCritique(int quantite)
{
    return qMax(5, quantite / 5);
}

[[maybe_unused]] void setStockSeuilBadge(QTableWidget *table, int row, const QString &seuil)
{
    if (!table || row < 0 || row >= table->rowCount()) return;

    QLabel *badge = new QLabel(seuil);
    badge->setAlignment(Qt::AlignCenter);
    badge->setFixedSize(90, 25);

    QString style = "border-radius: 5px; font-weight: bold;";
    if (seuil == "CRITIQUE") style += "background-color: #dc3545; color: white;";
    else if (seuil == "MOYEN") style += "background-color: #ffc107; color: #333;";
    else style += "background-color: #28a745; color: white;";
    badge->setStyleSheet(style);

    QWidget *badgeWidget = new QWidget();
    auto *badgeLayout = new QHBoxLayout(badgeWidget);
    badgeLayout->addWidget(badge);
    badgeLayout->setAlignment(Qt::AlignCenter);
    badgeLayout->setContentsMargins(0, 0, 0, 0);
    table->setCellWidget(row, 3, badgeWidget);
}

[[maybe_unused]] int spinBoxValueByNames(QWidget *scope, const QStringList &names, int fallback = 0)
{
    if (!scope) return fallback;
    for (const QString &name : names) {
        if (auto *sb = scope->findChild<QSpinBox*>(name)) {
            return sb->value();
        }
    }
    return fallback;
}

[[maybe_unused]] void setSpinBoxValueByNames(QWidget *scope, const QStringList &names, int value)
{
    if (!scope) return;
    for (const QString &name : names) {
        if (auto *sb = scope->findChild<QSpinBox*>(name)) {
            sb->setValue(value);
            return;
        }
    }
}


bool isValidCinInput(const QString &cin)
{
    const QString v = cin.trimmed();
    if (v.isEmpty()) return true;
    static const QRegularExpression re(R"(^\d{8}$)");
    return re.match(v).hasMatch();
}

void setValidationStyle(QLineEdit *field, bool valid, const QString &message)
{
    if (!field) return;
    if (valid) {
        field->setStyleSheet("border: 1px solid #16a34a; border-radius: 4px; padding: 4px;");
        field->setToolTip(QString());
    } else {
        field->setStyleSheet("border: 1px solid #dc2626; border-radius: 4px; padding: 4px;");
        field->setToolTip(message);
    }
}

QString stockTypeCapteurPrefix()
{
    return "Capteur ";
}

bool stockTypeIsCapteur(QComboBox *combo)
{
    return combo && combo->currentData().toString() == "capteur";
}

void applyStockTypeToNameField(QComboBox *combo, QLineEdit *field)
{
    if (!combo || !field) return;

    const QString prefix = stockTypeCapteurPrefix();
    const bool capteurMode = stockTypeIsCapteur(combo);
    const QString currentText = field->text();

    if (capteurMode) {
        QString suffix = currentText.trimmed();
        if (suffix.startsWith(prefix, Qt::CaseInsensitive)) {
            suffix = suffix.mid(prefix.size()).trimmed();
        } else if (suffix.compare(prefix.trimmed(), Qt::CaseInsensitive) == 0) {
            suffix.clear();
        }

        const QString normalized = prefix + suffix;
        field->setProperty("stockLockedPrefixEnabled", true);
        field->setProperty("stockLockedPrefixValue", prefix);
        field->setPlaceholderText("Capteur ...");

        if (field->text() != normalized) {
            QSignalBlocker blocker(field);
            field->setText(normalized);
        }
        if (field->cursorPosition() < prefix.size()) {
            field->setCursorPosition(field->text().size());
        }
        return;
    }

    QString unlockedText = currentText;
    const bool wasLocked = field->property("stockLockedPrefixEnabled").toBool();
    if (wasLocked) {
        if (unlockedText.trimmed().compare(prefix.trimmed(), Qt::CaseInsensitive) == 0) {
            unlockedText.clear();
        } else if (unlockedText.startsWith(prefix, Qt::CaseInsensitive)) {
            unlockedText = unlockedText.mid(prefix.size()).trimmed();
        }
    }

    field->setProperty("stockLockedPrefixEnabled", false);
    field->setProperty("stockLockedPrefixValue", QString());
    field->setPlaceholderText("Nom du Composant");

    if (wasLocked && field->text() != unlockedText) {
        QSignalBlocker blocker(field);
        field->setText(unlockedText);
    }
}

void syncStockTypeComboFromName(QComboBox *combo, QLineEdit *field)
{
    if (!combo || !field) return;

    const QString prefix = stockTypeCapteurPrefix();
    const QString text = field->text().trimmed();
    const bool isCapteurName =
        text.compare(prefix.trimmed(), Qt::CaseInsensitive) == 0 ||
        text.startsWith(prefix, Qt::CaseInsensitive);

    {
        QSignalBlocker blocker(combo);
        combo->setCurrentIndex(isCapteurName ? 0 : 1);
    }
    applyStockTypeToNameField(combo, field);
}

QComboBox *ensureStockTypeCombo(MainWindow *window, bool modify)
{
    if (!window) return nullptr;

    const QString comboName = modify ? "stockTypeCombo_mod" : "stockTypeCombo_add";
    if (auto *existing = window->findChild<QComboBox*>(comboName)) {
        return existing;
    }

    const QString layoutName = modify ? "layoutRefNom_mod" : "layoutRefNom_add";
    const QString fieldName = modify ? "inputNom_mod" : "inputNom_add";
    auto *layout = window->findChild<QHBoxLayout*>(layoutName);
    auto *field = window->findChild<QLineEdit*>(fieldName);
    if (!layout || !field) return nullptr;

    auto *combo = new QComboBox(field->parentWidget());
    combo->setObjectName(comboName);
    combo->addItem("Capteur", "capteur");
    combo->addItem("Autres", "autres");
    combo->setCurrentIndex(1);
    combo->setMinimumWidth(130);
    combo->setStyleSheet(
        "QComboBox {"
        " background-color: #f8fafc;"
        " border: 1px solid #dce1e6;"
        " border-radius: 8px;"
        " padding: 0 28px 0 10px;"
        " color: #1f2d3d;"
        " min-height: 40px;"
        "}"
        "QComboBox:focus {"
        " border: 1px solid #2563eb;"
        " background-color: #ffffff;"
        "}"
        "QComboBox::drop-down {"
        " border: none;"
        " width: 24px;"
        "}"
    );

    int insertIndex = layout->count();
    for (int i = 0; i < layout->count(); ++i) {
        QWidget *widget = layout->itemAt(i) ? layout->itemAt(i)->widget() : nullptr;
        if (widget == field) {
            insertIndex = i;
            break;
        }
    }
    layout->insertWidget(insertIndex, combo);

    QObject::connect(combo, QOverload<int>::of(&QComboBox::currentIndexChanged), field, [combo, field](int) {
        applyStockTypeToNameField(combo, field);
    });
    QObject::connect(field, &QLineEdit::textChanged, field, [combo, field](const QString &) {
        if (stockTypeIsCapteur(combo)) {
            applyStockTypeToNameField(combo, field);
        }
    });
    QObject::connect(field, &QLineEdit::cursorPositionChanged, field, [combo, field](int, int newPos) {
        if (!stockTypeIsCapteur(combo)) return;
        const int minPos = stockTypeCapteurPrefix().size();
        if (newPos < minPos) {
            QSignalBlocker blocker(field);
            field->setCursorPosition(minPos);
        }
    });

    syncStockTypeComboFromName(combo, field);
    return combo;
}

QString normalizedStatus(QString value)
{
    return value.normalized(QString::NormalizationForm_D).toLower().trimmed();
}

QString toDbDisponibilite(const QString &statusUi)
{
    const QString s = normalizedStatus(statusUi);
    if (s.contains("conge") && s.contains("malad")) return "CONGE_MALADIE";
    if (s.contains("conge")) return "CONGE_NORMALE";
    if (s.contains("intervention")) return "EN_INTERVENTION";
    if (s.contains("non") && s.contains("disponible")) return "INDISPONIBLE";
    if (s.contains("indispon")) return "INDISPONIBLE";
    if (s.contains("mission")) return "INDISPONIBLE";
    if (s.contains("disponible")) return "DISPONIBLE";
    return "INDISPONIBLE";
}

QString fromDbDisponibiliteLabel(const QString &statusDb)
{
    const QString s = normalizedStatus(statusDb);
    if (s.contains("conge") && s.contains("malad")) return "En conge maladie";
    if (s.contains("conge")) return "En conge normale";
    if (s.contains("intervention")) return "En intervention";
    if ((s.contains("non") && s.contains("disponible")) || s.contains("indispon")) return "Non disponible";
    if (s.contains("disponible")) return "Disponible";
    return statusDb.trimmed();
}

QString friendlySqlErrorMessage(const QString &rawError, const QString &action)
{
    const QString upper = rawError.toUpper();

    if (upper.contains("ORA-00001")) {
        return QString("Impossible de %1: matricule, CIN ou email deja utilise.").arg(action);
    }
    if (upper.contains("ORA-01400")) {
        return QString("Impossible de %1: un champ obligatoire est vide.").arg(action);
    }
    if (upper.contains("ORA-02291")) {
        return QString("Impossible de %1: reference inexistante.").arg(action);
    }
    if (upper.contains("ORA-02292")) {
        return QString("Impossible de %1: element utilise dans d'autres donnees.").arg(action);
    }
    if (upper.contains("ORA-00054") || upper.contains("ORA-30006")) {
        return QString("Impossible de %1: fiche employe verrouillee par une autre session. Reessayez dans quelques secondes.").arg(action);
    }
    if (upper.contains("ORA-03114") || upper.contains("ORA-03113") || upper.contains("ORA-01012")) {
        return QString("Impossible de %1: session Oracle coupee. Reconnexion automatique requise.").arg(action);
    }
    if (upper.contains("HYT00") || upper.contains("HYT01") || upper.contains("TIMEOUT")) {
        return QString("Impossible de %1: delai depasse (base lente ou bloquee). Reessayez.").arg(action);
    }
    if (upper.contains("DRIVER NOT LOADED")) {
        return "Connexion base indisponible: driver SQL non charge.";
    }
    if (upper.contains("ORA-00942")) {
        return "Table introuvable dans la base de donnees.";
    }
    return QString("Impossible de %1. Verifiez les donnees saisies.").arg(action);
}

QString cleanSqlErrorDetails(const QString &rawError)
{
    QStringList oraLines;
    const QRegularExpression oraRe(R"((ORA-\d{5}:[^\r\n]*))", QRegularExpression::CaseInsensitiveOption);
    QRegularExpressionMatchIterator it = oraRe.globalMatch(rawError);
    while (it.hasNext()) {
        const QString line = it.next().captured(1).trimmed();
        if (!line.isEmpty() && !oraLines.contains(line)) {
            oraLines << line;
        }
    }
    if (!oraLines.isEmpty()) {
        return oraLines.join("\n");
    }

    QString out;
    out.reserve(rawError.size());
    for (const QChar ch : rawError) {
        const ushort u = ch.unicode();
        if (ch == '\n' || ch == '\r' || ch == '\t' || (u >= 32 && u != 0xFFFD)) {
            out.append(ch);
        }
    }
    return out.trimmed();
}

void showFriendlySqlError(QWidget *parent, const QString &action, const QString &rawError)
{
    QMessageBox msg(parent);
    msg.setIcon(QMessageBox::Critical);
    msg.setWindowTitle("Erreur SQL");
    msg.setText(friendlySqlErrorMessage(rawError, action));
    const QString details = cleanSqlErrorDetails(rawError);
    if (!details.isEmpty()) {
        msg.setDetailedText(details);
    }
    msg.exec();
}

bool isMissingPhotoColumnError(const QString &errorText)
{
    const QString upper = errorText.toUpper();
    return upper.contains("ORA-00904")
        || upper.contains("INVALID IDENTIFIER")
        || upper.contains("NO SUCH COLUMN")
        || upper.contains("UNKNOWN COLUMN");
}

bool isMissingTableError(const QString &errorText)
{
    const QString upper = errorText.toUpper();
    return upper.contains("ORA-00942")
        || upper.contains("NO SUCH TABLE")
        || upper.contains("DOESN'T EXIST");
}

bool isDisconnectedSessionError(const QString &errorText)
{
    const QString upper = errorText.toUpper();
    return upper.contains("ORA-03114")
        || upper.contains("ORA-03113")
        || upper.contains("ORA-01012")
        || upper.contains("NOT CONNECTED TO ORACLE")
        || upper.contains("CONNECTION IS BROKEN")
        || upper.contains("COMMUNICATION LINK FAILURE")
        || upper.contains("END-OF-FILE ON COMMUNICATION CHANNEL");
}

bool pingCurrentDbSession(QString &errorText)
{
    errorText.clear();
    QSqlQuery ping;
    if (ping.exec("SELECT 1")) {
        return true;
    }
    if (ping.exec("SELECT 1 FROM DUAL")) {
        return true;
    }
    errorText = ping.lastError().text();
    return false;
}

bool ensureMainWindowDbSessionAlive(QString &errorText)
{
    errorText.clear();

    Connection *connection = Connection::instance();
    if (!connection) {
        errorText = "Connexion base introuvable.";
        return false;
    }

    if (!connection->isOpen()) {
        if (!connection->createConnect()) {
            errorText = connection->lastError();
            return false;
        }
        return true;
    }

    QString pingError;
    if (pingCurrentDbSession(pingError)) {
        return true;
    }
    if (!isDisconnectedSessionError(pingError)) {
        errorText = pingError;
        return false;
    }

    connection->closeConnection();
    if (!connection->createConnect()) {
        errorText = connection->lastError();
        return false;
    }

    if (!pingCurrentDbSession(pingError)) {
        errorText = pingError;
        return false;
    }
    return true;
}

bool isColumnAlreadyExistsError(const QString &errorText)
{
    const QString upper = errorText.toUpper();
    return upper.contains("ORA-01430")
        || upper.contains("ORA-00957")
        || upper.contains("DUPLICATE COLUMN")
        || upper.contains("ALREADY EXISTS");
}

struct AssignedTaskItem
{
    int idAffect = 0;
    QString missionText;
    double score = 0.0;
    double rewardAmount = 0.0;
    int experienceGain = 0;
    QString assignedAt;
    QString status;
    QString completedAt;
};

bool isMissionTaskDoneStatus(const QString &status)
{
    QString s = status;
    s = s.normalized(QString::NormalizationForm_D).toLower().trimmed();
    return s.contains("termine")
        || s.contains("deja fait")
        || s.contains("fait")
        || s.contains("done")
        || s.contains("complete");
}

int missionDifficultyLevel(const QString &missionText);
QStringList missionSpecialityHints(const QString &missionText);

int missionDifficultyForRewards(const QString &missionText)
{
    int level = missionDifficultyLevel(missionText);
    const int hintCount = missionSpecialityHints(missionText).size();
    if (hintCount >= 2) {
        level = qMin(3, level + 1);
    }
    return qBound(1, level, 3);
}

double missionTaskMonthlyBonusFromScore(double score, const QString &missionText)
{
    const double bounded = qBound(0.0, score, 100.0);
    const int difficulty = missionDifficultyForRewards(missionText);

    if (difficulty <= 1) {
        // Mission facile: prime tres faible, souvent 0.
        if (bounded < 75.0) return 0.0;
        if (bounded < 90.0) return 5.0;
        return 10.0;
    }

    if (difficulty == 2) {
        if (bounded < 60.0) return 8.0;
        return qRound((12.0 + (bounded * 0.48)) * 100.0) / 100.0; // ~12 .. 60
    }

    // Mission difficile/urgente: prime plus elevee selon performance.
    if (bounded < 55.0) return 25.0;
    return qRound((35.0 + (bounded * 0.95)) * 100.0) / 100.0; // ~35 .. 130
}

int missionTaskExperienceGainFromScore(double score, const QString &missionText)
{
    const double bounded = qBound(0.0, score, 100.0);
    const int difficulty = missionDifficultyForRewards(missionText);

    if (difficulty <= 1) {
        if (bounded < 90.0) return 0;
        return 1;
    }

    if (difficulty == 2) {
        if (bounded < 60.0) return 0;
        if (bounded < 85.0) return 1;
        return 2;
    }

    if (bounded < 50.0) return 1;
    if (bounded < 75.0) return 2;
    if (bounded < 90.0) return 3;
    return 4;
}

QDateTime parseSqlDateTimeValue(const QVariant &value)
{
    const QDateTime asDt = value.toDateTime();
    if (asDt.isValid()) return asDt;

    const QString raw = value.toString().trimmed();
    if (raw.isEmpty()) return QDateTime();

    const QStringList formats = {
        "yyyy-MM-dd HH:mm:ss",
        "yyyy-MM-dd HH:mm",
        "yyyy-MM-ddTHH:mm:ss",
        "yyyy-MM-ddTHH:mm:ssZ",
        "dd/MM/yyyy HH:mm:ss",
        "dd/MM/yyyy HH:mm",
        "yyyy-MM-dd"
    };
    for (const QString &fmt : formats) {
        QDateTime dt = QDateTime::fromString(raw, fmt);
        if (dt.isValid()) return dt;
    }

    QDateTime iso = QDateTime::fromString(raw, Qt::ISODate);
    if (iso.isValid()) return iso;
    iso = QDateTime::fromString(raw, Qt::ISODateWithMs);
    return iso;
}

bool ensureEmployeExperienceColumnExists(QString &errorText)
{
    errorText.clear();

    QSqlQuery probe;
    if (probe.exec("SELECT experience FROM EMPLOYE WHERE 1=0")) {
        return true;
    }
    if (!isMissingPhotoColumnError(probe.lastError().text())) {
        errorText = probe.lastError().text();
        return false;
    }

    QSqlQuery alterOracle;
    if (alterOracle.exec("ALTER TABLE EMPLOYE ADD (experience NUMBER(6) DEFAULT 0)")) {
        return true;
    }
    if (isColumnAlreadyExistsError(alterOracle.lastError().text())) {
        return true;
    }

    QSqlQuery alterFallback;
    if (alterFallback.exec("ALTER TABLE EMPLOYE ADD COLUMN experience INTEGER DEFAULT 0")) {
        return true;
    }
    if (isColumnAlreadyExistsError(alterFallback.lastError().text())) {
        return true;
    }

    errorText = alterOracle.lastError().text();
    if (errorText.trimmed().isEmpty()) {
        errorText = alterFallback.lastError().text();
    }
    return false;
}

bool ensureEmployeDisponibiliteStatusesReady(QString &errorText)
{
    static bool checked = false;
    if (checked) return true;

    errorText.clear();

    const QSqlDatabase db = QSqlDatabase::database();
    if (!db.isValid() || !db.isOpen()) {
        errorText = "Connexion base indisponible.";
        return false;
    }

    const QString driverName = db.driverName().trimmed().toUpper();
    if (!driverName.contains("ODBC") && !driverName.contains("OCI")) {
        checked = true;
        return true;
    }

    QStringList constraintNames;
    QSqlQuery findConstraints;
    if (!findConstraints.exec(
            "SELECT uc.constraint_name "
            "FROM user_constraints uc "
            "JOIN user_cons_columns ucc ON uc.constraint_name = ucc.constraint_name "
            "WHERE uc.table_name = 'EMPLOYE' "
            "AND ucc.table_name = 'EMPLOYE' "
            "AND ucc.column_name = 'DISPONIBILITE' "
            "AND uc.constraint_type = 'C'")) {
        errorText = findConstraints.lastError().text();
        return false;
    }

    while (findConstraints.next()) {
        const QString constraintName = findConstraints.value(0).toString().trimmed();
        if (!constraintName.isEmpty()) {
            constraintNames << constraintName;
        }
    }
    constraintNames.removeDuplicates();

    for (const QString &constraintName : constraintNames) {
        QSqlQuery dropConstraint;
        if (!dropConstraint.exec(QString("ALTER TABLE EMPLOYE DROP CONSTRAINT %1").arg(constraintName))) {
            const QString dropError = dropConstraint.lastError().text();
            if (!dropError.toUpper().contains("ORA-02443")) {
                errorText = dropError;
                return false;
            }
        }
    }

    QStringList allowedStatuses = {
        "DISPONIBLE",
        "INDISPONIBLE",
        "EN_INTERVENTION",
        "CONGE_NORMALE",
        "CONGE_MALADIE",
        "EN_CONGE",
        "EN_CONGE_MALADIE"
    };
    QSqlQuery loadLegacyStatuses;
    if (loadLegacyStatuses.exec(
            "SELECT DISTINCT UPPER(TRIM(disponibilite)) "
            "FROM EMPLOYE "
            "WHERE disponibilite IS NOT NULL")) {
        while (loadLegacyStatuses.next()) {
            const QString legacyStatus = loadLegacyStatuses.value(0).toString().trimmed();
            if (!legacyStatus.isEmpty() && !allowedStatuses.contains(legacyStatus)) {
                allowedStatuses << legacyStatus;
            }
        }
    } else {
        qWarning() << "Unable to inspect legacy employee statuses:" << loadLegacyStatuses.lastError().text();
    }
    QStringList escapedStatuses;
    for (QString statusValue : allowedStatuses) {
        escapedStatuses << statusValue.replace('\'', "''");
    }
    const QString addConstraintSql =
        QString("ALTER TABLE EMPLOYE ADD CONSTRAINT EMPLOYE_DISPONIBILITE_CK "
                "CHECK (DISPONIBILITE IN ('%1'))")
            .arg(escapedStatuses.join("','"));

    QSqlQuery addConstraint;
    if (!addConstraint.exec(addConstraintSql)) {
        const QString addError = addConstraint.lastError().text();
        const QString addErrorUpper = addError.toUpper();
        if (!addErrorUpper.contains("ORA-02264") && !addErrorUpper.contains("ORA-00955")) {
            errorText = addError;
            return false;
        }

        QSqlQuery dropNamedConstraint;
        dropNamedConstraint.exec("ALTER TABLE EMPLOYE DROP CONSTRAINT EMPLOYE_DISPONIBILITE_CK");

        QSqlQuery retryAddConstraint;
        if (!retryAddConstraint.exec(addConstraintSql)) {
            errorText = retryAddConstraint.lastError().text();
            return false;
        }
    }

    checked = true;
    return true;
}

bool ensureMissionAffectationColumns(QString &errorText)
{
    static bool checked = false;
    if (checked) return true;

    errorText.clear();

    QSqlQuery probeAll;
    if (probeAll.exec(
            "SELECT status, completed_at, reward_amount, experience_gain "
            "FROM MISSION_AFFECTATION WHERE 1=0")) {
        checked = true;
        return true;
    }
    if (!isMissingPhotoColumnError(probeAll.lastError().text())) {
        errorText = probeAll.lastError().text();
        return false;
    }
    probeAll.finish();

    auto addColumn = [&](const QString &oracleSql, const QString &sqliteSql) -> bool {
        QSqlQuery q;
        if (q.exec(oracleSql)) return true;
        if (isColumnAlreadyExistsError(q.lastError().text())) return true;

        QSqlQuery fallback;
        if (fallback.exec(sqliteSql)) return true;
        if (isColumnAlreadyExistsError(fallback.lastError().text())) return true;

        errorText = q.lastError().text();
        if (errorText.trimmed().isEmpty()) {
            errorText = fallback.lastError().text();
        }
        return false;
    };

    if (!addColumn(
            "ALTER TABLE MISSION_AFFECTATION ADD (status VARCHAR2(20) DEFAULT 'EN_ATTENTE')",
            "ALTER TABLE MISSION_AFFECTATION ADD COLUMN status TEXT DEFAULT 'EN_ATTENTE'")) {
        return false;
    }

    if (!addColumn(
            "ALTER TABLE MISSION_AFFECTATION ADD (completed_at DATE)",
            "ALTER TABLE MISSION_AFFECTATION ADD COLUMN completed_at TEXT")) {
        return false;
    }

    if (!addColumn(
            "ALTER TABLE MISSION_AFFECTATION ADD (reward_amount NUMBER(10,2) DEFAULT 0)",
            "ALTER TABLE MISSION_AFFECTATION ADD COLUMN reward_amount REAL DEFAULT 0")) {
        return false;
    }

    if (!addColumn(
            "ALTER TABLE MISSION_AFFECTATION ADD (experience_gain NUMBER(5) DEFAULT 0)",
            "ALTER TABLE MISSION_AFFECTATION ADD COLUMN experience_gain INTEGER DEFAULT 0")) {
        return false;
    }

    QSqlQuery normalize;
    normalize.exec("UPDATE MISSION_AFFECTATION SET status='EN_ATTENTE' WHERE status IS NULL OR TRIM(status)=''");
    normalize.exec("UPDATE MISSION_AFFECTATION SET reward_amount=0 WHERE reward_amount IS NULL");
    normalize.exec("UPDATE MISSION_AFFECTATION SET experience_gain=0 WHERE experience_gain IS NULL");
    checked = true;
    return true;
}

bool ensureMissionAffectationTableExists(QString &errorText)
{
    errorText.clear();

    QSqlQuery probe;
    if (probe.exec("SELECT id_emp, mission_text, score, assigned_at FROM MISSION_AFFECTATION WHERE 1=0")) {
        return ensureMissionAffectationColumns(errorText);
    }
    if (!isMissingTableError(probe.lastError().text())) {
        errorText = probe.lastError().text();
        return false;
    }

    QSqlQuery createOracle;
    const bool oracleTableReady = createOracle.exec(
                                      "CREATE TABLE MISSION_AFFECTATION ("
                                      "id_affect NUMBER PRIMARY KEY, "
                                      "id_emp NUMBER NOT NULL, "
                                      "mission_text VARCHAR2(1000), "
                                      "score NUMBER(6,2), "
                                      "assigned_at DATE DEFAULT SYSDATE, "
                                      "status VARCHAR2(20) DEFAULT 'EN_ATTENTE', "
                                      "completed_at DATE, "
                                      "reward_amount NUMBER(10,2) DEFAULT 0, "
                                      "experience_gain NUMBER(5) DEFAULT 0)")
                                  || createOracle.lastError().text().toUpper().contains("ORA-00955");
    if (oracleTableReady) {
        QSqlQuery createSeq;
        if (!createSeq.exec(
                "CREATE SEQUENCE MISSION_AFFECTATION_SEQ "
                "START WITH 1 INCREMENT BY 1 NOCACHE")
            && !createSeq.lastError().text().toUpper().contains("ORA-00955")) {
            errorText = createSeq.lastError().text();
            return false;
        }
        QSqlQuery createTrigger;
        if (!createTrigger.exec(
                "CREATE OR REPLACE TRIGGER MISSION_AFFECTATION_BI "
                "BEFORE INSERT ON MISSION_AFFECTATION "
                "FOR EACH ROW "
                "WHEN (NEW.id_affect IS NULL) "
                "BEGIN "
                "SELECT MISSION_AFFECTATION_SEQ.NEXTVAL INTO :NEW.id_affect FROM DUAL; "
                "END;")) {
            // Not blocking: insert() also tries explicit sequence usage.
        }
        return ensureMissionAffectationColumns(errorText);
    }

    QSqlQuery createFallback;
    if (createFallback.exec(
            "CREATE TABLE MISSION_AFFECTATION ("
            "id_affect INTEGER PRIMARY KEY AUTOINCREMENT, "
            "id_emp INTEGER NOT NULL, "
            "mission_text TEXT, "
            "score REAL, "
            "assigned_at TEXT DEFAULT CURRENT_TIMESTAMP, "
            "status TEXT DEFAULT 'EN_ATTENTE', "
            "completed_at TEXT, "
            "reward_amount REAL DEFAULT 0, "
            "experience_gain INTEGER DEFAULT 0)")) {
        return ensureMissionAffectationColumns(errorText);
    }
    if (createFallback.lastError().text().toUpper().contains("ALREADY EXISTS")) {
        return ensureMissionAffectationColumns(errorText);
    }

    errorText = createOracle.lastError().text();
    if (errorText.trimmed().isEmpty()) {
        errorText = createFallback.lastError().text();
    }
    return false;
}

bool insertMissionAffectationRow(int idEmp, const QString &missionText, double score, QString &errorText)
{
    errorText.clear();
    if (!ensureMissionAffectationTableExists(errorText)) {
        return false;
    }

    QSqlQuery insertOracleSeq;
    insertOracleSeq.prepare(
        "INSERT INTO MISSION_AFFECTATION (id_affect, id_emp, mission_text, score, assigned_at, status, completed_at, reward_amount, experience_gain) "
        "VALUES (MISSION_AFFECTATION_SEQ.NEXTVAL, :id_emp, :mission_text, :score, SYSDATE, 'EN_ATTENTE', NULL, 0, 0)");
    insertOracleSeq.bindValue(":id_emp", idEmp);
    insertOracleSeq.bindValue(":mission_text", missionText);
    insertOracleSeq.bindValue(":score", score);
    if (insertOracleSeq.exec()) {
        return true;
    }

    QSqlQuery insertOracle;
    insertOracle.prepare(
        "INSERT INTO MISSION_AFFECTATION (id_emp, mission_text, score, assigned_at, status, completed_at, reward_amount, experience_gain) "
        "VALUES (:id_emp, :mission_text, :score, SYSDATE, 'EN_ATTENTE', NULL, 0, 0)");
    insertOracle.bindValue(":id_emp", idEmp);
    insertOracle.bindValue(":mission_text", missionText);
    insertOracle.bindValue(":score", score);
    if (insertOracle.exec()) {
        return true;
    }

    QSqlQuery insertFallback;
    insertFallback.prepare(
        "INSERT INTO MISSION_AFFECTATION (id_emp, mission_text, score, assigned_at, status, completed_at, reward_amount, experience_gain) "
        "VALUES (:id_emp, :mission_text, :score, CURRENT_TIMESTAMP, 'EN_ATTENTE', NULL, 0, 0)");
    insertFallback.bindValue(":id_emp", idEmp);
    insertFallback.bindValue(":mission_text", missionText);
    insertFallback.bindValue(":score", score);
    if (insertFallback.exec()) {
        return true;
    }

    // Last resort: Oracle without sequence — use MAX(id_affect)+1 to avoid ORA-01400
    QSqlQuery insertMaxId;
    insertMaxId.prepare(
        "INSERT INTO MISSION_AFFECTATION (id_affect, id_emp, mission_text, score, assigned_at, status, completed_at, reward_amount, experience_gain) "
        "VALUES ((SELECT NVL(MAX(id_affect),0)+1 FROM MISSION_AFFECTATION), :id_emp, :mission_text, :score, SYSDATE, 'EN_ATTENTE', NULL, 0, 0)");
    insertMaxId.bindValue(":id_emp", idEmp);
    insertMaxId.bindValue(":mission_text", missionText);
    insertMaxId.bindValue(":score", score);
    if (insertMaxId.exec()) {
        return true;
    }

    errorText = insertOracleSeq.lastError().text();
    if (errorText.trimmed().isEmpty()) errorText = insertOracle.lastError().text();
    if (errorText.trimmed().isEmpty()) errorText = insertFallback.lastError().text();
    if (errorText.trimmed().isEmpty()) errorText = insertMaxId.lastError().text();
    return false;
}

bool loadEmployeeAssignedTasks(const QString &email,
                               QVector<AssignedTaskItem> &pending,
                               QVector<AssignedTaskItem> &done,
                               QString &errorText)
{
    pending.clear();
    done.clear();
    errorText.clear();

    const QString normalizedEmail = email.trimmed();
    if (normalizedEmail.isEmpty()) {
        errorText = "Email employe manquant.";
        return false;
    }

    for (int attempt = 0; attempt < 2; ++attempt) {
        QString sessionError;
        if (!ensureMainWindowDbSessionAlive(sessionError)) {
            errorText = sessionError;
            return false;
        }

        if (!ensureMissionAffectationTableExists(errorText)) {
            if (attempt == 0 && isDisconnectedSessionError(errorText)) {
                continue;
            }
            return false;
        }

        QSqlQuery query;
        query.prepare(
            "SELECT a.id_affect, a.mission_text, a.score, "
            "COALESCE(a.reward_amount,0), COALESCE(a.experience_gain,0), "
            "a.assigned_at, COALESCE(a.status, 'EN_ATTENTE') AS status, a.completed_at "
            "FROM MISSION_AFFECTATION a "
            "JOIN EMPLOYE e ON e.id_emp = a.id_emp "
            "WHERE LOWER(TRIM(e.email)) = LOWER(TRIM(:email)) "
            "ORDER BY a.assigned_at DESC");
        query.bindValue(":email", normalizedEmail);
        if (!query.exec()) {
            errorText = query.lastError().text();
            if (attempt == 0 && isDisconnectedSessionError(errorText)) {
                continue;
            }
            return false;
        }

        auto stringifyTime = [](const QVariant &value) -> QString {
            if (!value.isValid() || value.isNull()) return QString();
            const QDateTime dt = parseSqlDateTimeValue(value);
            if (dt.isValid()) return dt.toString("yyyy-MM-dd HH:mm");
            return value.toString();
        };

        while (query.next()) {
            AssignedTaskItem task;
            task.idAffect = query.value(0).toInt();
            task.missionText = query.value(1).toString().trimmed();
            task.score = query.value(2).toDouble();
            task.rewardAmount = query.value(3).toDouble();
            task.experienceGain = query.value(4).toInt();
            task.assignedAt = stringifyTime(query.value(5));
            task.status = query.value(6).toString().trimmed();
            if (task.status.isEmpty()) task.status = "EN_ATTENTE";
            task.completedAt = stringifyTime(query.value(7));

            if (isMissionTaskDoneStatus(task.status)) {
                done.push_back(task);
            } else {
                pending.push_back(task);
            }
        }

        return true;
    }
    return false;
}

double computeEmployeeMonthlyTaskBonus(int idEmp, const QDate &periodStart, const QDate &periodEnd, QString &errorText)
{
    errorText.clear();
    if (idEmp <= 0) return 0.0;
    if (!periodStart.isValid() || !periodEnd.isValid()) return 0.0;

    for (int attempt = 0; attempt < 2; ++attempt) {
        QString sessionError;
        if (!ensureMainWindowDbSessionAlive(sessionError)) {
            errorText = sessionError;
            return 0.0;
        }

        if (!ensureMissionAffectationTableExists(errorText)) {
            if (attempt == 0 && isDisconnectedSessionError(errorText)) {
                continue;
            }
            return 0.0;
        }

        QSqlQuery query;
        query.prepare(
            "SELECT mission_text, score, COALESCE(reward_amount,0), completed_at, COALESCE(status,'EN_ATTENTE') "
            "FROM MISSION_AFFECTATION "
            "WHERE id_emp=:id");
        query.bindValue(":id", idEmp);
        if (!query.exec()) {
            errorText = query.lastError().text();
            if (attempt == 0 && isDisconnectedSessionError(errorText)) {
                continue;
            }
            return 0.0;
        }

        double total = 0.0;
        while (query.next()) {
            const QString missionText = query.value(0).toString();
            const QString status = query.value(4).toString();
            if (!isMissionTaskDoneStatus(status)) continue;

            const QDateTime completedAt = parseSqlDateTimeValue(query.value(3));
            if (!completedAt.isValid()) continue;
            const QDate doneDate = completedAt.date();
            if (doneDate < periodStart || doneDate > periodEnd) continue;

            double reward = query.value(2).toDouble();
            if (reward <= 0.0) {
                reward = missionTaskMonthlyBonusFromScore(query.value(1).toDouble(), missionText);
            }
            total += reward;
        }

        errorText.clear();
        return qRound(total * 100.0) / 100.0;
    }
    return 0.0;
}

bool markMissionTaskAsDoneById(int idAffect, QString &errorText, double *appliedBonus = nullptr, int *appliedExperienceGain = nullptr)
{
    errorText.clear();
    if (appliedBonus) *appliedBonus = 0.0;
    if (appliedExperienceGain) *appliedExperienceGain = 0;
    if (idAffect <= 0) {
        errorText = "Tache invalide.";
        return false;
    }

    QString lastError;
    for (int attempt = 0; attempt < 2; ++attempt) {
        QString sessionError;
        if (!ensureMainWindowDbSessionAlive(sessionError)) {
            errorText = sessionError;
            return false;
        }

        if (!ensureMissionAffectationTableExists(lastError)) {
            if (attempt == 0 && isDisconnectedSessionError(lastError)) continue;
            errorText = lastError;
            return false;
        }
        if (!ensureEmployeExperienceColumnExists(lastError)) {
            if (attempt == 0 && isDisconnectedSessionError(lastError)) continue;
            errorText = lastError;
            return false;
        }

        QSqlQuery readTask;
        readTask.prepare(
            "SELECT id_emp, mission_text, COALESCE(score,0), COALESCE(status,'EN_ATTENTE') "
            "FROM MISSION_AFFECTATION WHERE id_affect=:id");
        readTask.bindValue(":id", idAffect);
        if (!readTask.exec()) {
            lastError = readTask.lastError().text();
            if (attempt == 0 && isDisconnectedSessionError(lastError)) continue;
            errorText = lastError;
            return false;
        }
        if (!readTask.next()) {
            errorText = "Tache introuvable.";
            return false;
        }

        const int idEmp = readTask.value(0).toInt();
        const QString missionText = readTask.value(1).toString();
        const double taskScore = readTask.value(2).toDouble();
        const QString currentStatus = readTask.value(3).toString();
        if (isMissionTaskDoneStatus(currentStatus)) {
            return true;
        }

        const double reward = missionTaskMonthlyBonusFromScore(taskScore, missionText);
        const int expGain = missionTaskExperienceGainFromScore(taskScore, missionText);

        QSqlDatabase db = QSqlDatabase::database();
        bool txStarted = false;
        if (db.isValid()) {
            txStarted = db.transaction();
            if (!txStarted) {
                lastError = db.lastError().text();
                if (attempt == 0 && isDisconnectedSessionError(lastError)) {
                    continue;
                }
            }
        }

        bool updatedTask = false;
        QSqlQuery updateOracle;
        updateOracle.prepare(
            "UPDATE MISSION_AFFECTATION "
            "SET status='TERMINEE', completed_at=SYSDATE, reward_amount=:reward, experience_gain=:exp "
            "WHERE id_affect=:id");
        updateOracle.bindValue(":reward", reward);
        updateOracle.bindValue(":exp", expGain);
        updateOracle.bindValue(":id", idAffect);
        if (updateOracle.exec() && updateOracle.numRowsAffected() != 0) {
            updatedTask = true;
        } else {
            QSqlQuery updateFallback;
            updateFallback.prepare(
                "UPDATE MISSION_AFFECTATION "
                "SET status='TERMINEE', completed_at=CURRENT_TIMESTAMP, reward_amount=:reward, experience_gain=:exp "
                "WHERE id_affect=:id");
            updateFallback.bindValue(":reward", reward);
            updateFallback.bindValue(":exp", expGain);
            updateFallback.bindValue(":id", idAffect);
            if (updateFallback.exec() && updateFallback.numRowsAffected() != 0) {
                updatedTask = true;
            } else {
                lastError = updateOracle.lastError().text();
                if (lastError.trimmed().isEmpty()) {
                    lastError = updateFallback.lastError().text();
                }
            }
        }

        if (!updatedTask) {
            if (txStarted) db.rollback();
            if (attempt == 0 && isDisconnectedSessionError(lastError)) {
                continue;
            }
            if (lastError.trimmed().isEmpty()) lastError = "Mise a jour de la tache impossible.";
            errorText = lastError;
            return false;
        }

        if (idEmp > 0 && expGain > 0) {
            QSqlQuery incExp;
            incExp.prepare(
                "UPDATE EMPLOYE "
                "SET experience = COALESCE(experience,0) + :gain "
                "WHERE id_emp=:id");
            incExp.bindValue(":gain", expGain);
            incExp.bindValue(":id", idEmp);
            if (!incExp.exec()) {
                lastError = incExp.lastError().text();
                if (txStarted) db.rollback();
                if (attempt == 0 && isDisconnectedSessionError(lastError)) {
                    continue;
                }
                errorText = lastError;
                return false;
            }
        }

        if (txStarted && !db.commit()) {
            lastError = db.lastError().text();
            if (attempt == 0 && isDisconnectedSessionError(lastError)) {
                continue;
            }
            errorText = lastError;
            return false;
        }

        if (appliedBonus) *appliedBonus = reward;
        if (appliedExperienceGain) *appliedExperienceGain = expGain;
        return true;
    }

    errorText = lastError.trimmed().isEmpty()
                    ? QString("Session Oracle coupee. Reessayez.")
                    : lastError;
    return false;
}

