class EmployeeLeaveRequestDialog : public QDialog
{
public:
    explicit EmployeeLeaveRequestDialog(const QString &employeeEmail, QWidget *parent = nullptr)
        : QDialog(parent)
        , m_email(employeeEmail.trimmed())
    {
        setWindowTitle("Demande de conge IA");
        setModal(true);

        QRect avail = QApplication::primaryScreen() ? QApplication::primaryScreen()->availableGeometry() : QRect();
        if (!avail.isValid() && parent) {
            avail = parent->geometry();
        }
        const int targetW = avail.isValid() ? qBound(960, static_cast<int>(avail.width() * 0.88), 1240) : 1040;
        const int targetH = avail.isValid() ? qBound(620, static_cast<int>(avail.height() * 0.86), 820) : 700;
        resize(targetW, targetH);
        setMinimumSize(900, 600);
        setStyleSheet(
            "QDialog { background: #edf4f7; }"
            "QFrame#heroLeave { background:qlineargradient(x1:0,y1:0,x2:1,y2:1,stop:0 #0f2b4c, stop:0.55 #1d4f91, stop:1 #3173b7); border-radius:24px; }"
            "QLabel#heroLeaveTitle { color:#ffffff; font-size:24px; font-weight:900; }"
            "QLabel#heroLeaveSub { color:#dbeafe; font-size:12px; font-weight:600; }"
            "QFrame#formCard, QFrame#sideCard, QFrame#resultCard { background:#ffffff; border:1px solid #dbe7ef; border-radius:22px; }"
            "QLabel#sectionTitle { color:#0f172a; font-size:16px; font-weight:800; }"
            "QLabel#sectionHint { color:#64748b; font-size:12px; line-height:1.45; }"
            "QLabel#badgeLabel { color:#0f172a; font-size:12px; font-weight:700; }"
            "QLabel#statusInfo { color:#334155; font-size:12px; line-height:1.45; }"
            "QLabel#summaryText { color:#1e293b; font-size:12px; line-height:1.5; }"
            "QTextEdit { background:#f8fbfd; border:1px solid #cfe0ea; border-radius:16px; padding:12px; color:#0f172a; selection-background-color:#bfdbfe; }"
            "QTextEdit:focus { border:1px solid #3173b7; background:#ffffff; }"
            "QDateEdit { background:#f8fbfd; border:1px solid #cfe0ea; border-radius:12px; padding:8px 12px; color:#0f172a; min-height:20px; }"
            "QDateEdit:focus { border:1px solid #3173b7; background:#ffffff; }"
            "QPushButton#btnUploadJustif { background:#e0f2fe; color:#0f4c81; border:1px solid #bae6fd; border-radius:12px; padding:10px 14px; font-weight:800; }"
            "QPushButton#btnUploadJustif:hover { background:#bae6fd; }"
            "QPushButton#btnSubmitLeave { background:#1e9d63; color:white; border:none; border-radius:14px; padding:12px 18px; font-weight:900; }"
            "QPushButton#btnSubmitLeave:hover { background:#168455; }"
            "QPushButton#btnSubmitLeave:disabled { background:#9bd5bb; color:#effaf4; }"
            "QPushButton#btnCloseLeave { background:#ffffff; color:#334155; border:1px solid #cbd5e1; border-radius:14px; padding:12px 18px; font-weight:800; }"
            "QPushButton#btnCloseLeave:hover { background:#f8fafc; }");

        QString contextError;
        if (!loadEmployeeLeaveValidationContextByEmail(m_email, m_employeeContext, contextError)) {
            m_employeeContext.email = m_email;
            m_employeeContext.employeeName = "Employe";
        }

        auto *dialogRoot = new QVBoxLayout(this);
        dialogRoot->setContentsMargins(8, 8, 8, 8);
        dialogRoot->setSpacing(0);

        auto *scroll = new QScrollArea(this);
        scroll->setWidgetResizable(true);
        scroll->setFrameShape(QFrame::NoFrame);
        scroll->setHorizontalScrollBarPolicy(Qt::ScrollBarAlwaysOff);
        dialogRoot->addWidget(scroll);

        auto *contentHost = new QWidget(scroll);
        scroll->setWidget(contentHost);

        auto *root = new QVBoxLayout(contentHost);
        root->setContentsMargins(20, 20, 20, 20);
        root->setSpacing(16);

        auto *hero = new QFrame(this);
        hero->setObjectName("heroLeave");
        hero->setAttribute(Qt::WA_StyledBackground, true);
        auto *heroLayout = new QVBoxLayout(hero);
        heroLayout->setContentsMargins(22, 20, 22, 20);
        heroLayout->setSpacing(8);
        auto *heroTop = new QHBoxLayout();
        heroTop->setSpacing(12);

        auto *heroBadge = new QLabel("Controle RH guide par IA", hero);
        heroBadge->setStyleSheet("background:rgba(255,255,255,38); color:#eff6ff; border:1px solid rgba(255,255,255,52); border-radius:999px; padding:6px 12px; font-size:11px; font-weight:800;");

        auto *heroTitle = new QLabel("Envoyer une demande de conge claire et complete", hero);
        heroTitle->setObjectName("heroLeaveTitle");

        QString heroIdentity = QString("%1  |  %2")
                                   .arg(m_employeeContext.employeeName.isEmpty() ? "Employe" : m_employeeContext.employeeName,
                                        m_employeeContext.email.isEmpty() ? m_email : m_employeeContext.email);
        if (!m_employeeContext.matricule.isEmpty()) {
            heroIdentity += QString("  |  Matricule %1").arg(m_employeeContext.matricule);
        }

        auto *heroSub = new QLabel(heroIdentity, hero);
        heroSub->setObjectName("heroLeaveSub");

        auto *heroHint = new QLabel(
            "Le systeme verifie le justificatif, la coherence des dates, l'identite visible et la compatibilite avec la duree demandee.",
            hero);
        heroHint->setStyleSheet("color:#e2e8f0; font-size:13px; line-height:1.45;");
        heroHint->setWordWrap(true);

        heroTop->addWidget(heroBadge, 0, Qt::AlignLeft | Qt::AlignTop);
        heroTop->addStretch();

        heroLayout->addLayout(heroTop);
        heroLayout->addWidget(heroTitle);
        heroLayout->addWidget(heroSub);
        heroLayout->addWidget(heroHint);
        root->addWidget(hero);

        auto *content = new QHBoxLayout();
        content->setSpacing(16);

        auto *card = new QFrame(this);
        card->setObjectName("formCard");
        card->setAttribute(Qt::WA_StyledBackground, true);
        auto *cardLayout = new QVBoxLayout(card);
        cardLayout->setContentsMargins(20, 20, 20, 20);
        cardLayout->setSpacing(18);

        auto *formTitle = new QLabel("1. Preparer la demande", card);
        formTitle->setObjectName("sectionTitle");
        auto *formHint = new QLabel(
            "Expliquez la raison, choisissez la bonne periode et ajoutez un justificatif lisible. Plus votre dossier est propre, plus la validation sera fiable.",
            card);
        formHint->setObjectName("sectionHint");
        formHint->setWordWrap(true);
        cardLayout->addWidget(formTitle);
        cardLayout->addWidget(formHint);

        auto *reasonBlock = new QFrame(card);
        reasonBlock->setAttribute(Qt::WA_StyledBackground, true);
        reasonBlock->setStyleSheet("QFrame { background:#f8fbfd; border:1px solid #dceaf1; border-radius:18px; }");
        auto *reasonLayout = new QVBoxLayout(reasonBlock);
        reasonLayout->setContentsMargins(16, 16, 16, 16);
        reasonLayout->setSpacing(10);
        auto *reasonTitle = new QLabel("Motif de l'absence", reasonBlock);
        reasonTitle->setObjectName("badgeLabel");
        auto *reasonHint = new QLabel("Exemple: arret maladie, consultation, accident, repos prescrit.", reasonBlock);
        reasonHint->setObjectName("sectionHint");
        m_reason = new QTextEdit(reasonBlock);
        m_reason->setPlaceholderText("Ex: Arret maladie suite a une infection respiratoire avec certificat medical...");
        m_reason->setMinimumHeight(120);
        m_lblReasonMeta = new QLabel("Minimum recommande: 8 caracteres", reasonBlock);
        m_lblReasonMeta->setObjectName("statusInfo");
        reasonLayout->addWidget(reasonTitle);
        reasonLayout->addWidget(reasonHint);
        reasonLayout->addWidget(m_reason);
        reasonLayout->addWidget(m_lblReasonMeta);
        cardLayout->addWidget(reasonBlock);

        auto *form = new QFormLayout();
        form->setLabelAlignment(Qt::AlignLeft | Qt::AlignVCenter);
        form->setFormAlignment(Qt::AlignTop);
        form->setHorizontalSpacing(14);
        form->setVerticalSpacing(14);

        auto *datesRow = new QHBoxLayout();
        m_startDate = new QDateEdit(QDate::currentDate(), card);
        m_endDate = new QDateEdit(QDate::currentDate().addDays(2), card);
        m_startDate->setCalendarPopup(true);
        m_endDate->setCalendarPopup(true);
        m_startDate->setDisplayFormat("dd/MM/yyyy");
        m_endDate->setDisplayFormat("dd/MM/yyyy");
        auto *lblFrom = new QLabel("Du", card);
        lblFrom->setObjectName("badgeLabel");
        auto *lblTo = new QLabel("Au", card);
        lblTo->setObjectName("badgeLabel");
        datesRow->addWidget(lblFrom);
        datesRow->addWidget(m_startDate);
        datesRow->addSpacing(12);
        datesRow->addWidget(lblTo);
        datesRow->addWidget(m_endDate);
        datesRow->addStretch();
        form->addRow("Periode demandee", datesRow);

        m_lblDuration = new QLabel("-", card);
        m_lblDuration->setObjectName("statusInfo");
        m_lblDuration->setTextFormat(Qt::RichText);
        form->addRow("Resume periode", m_lblDuration);

        auto *uploadRow = new QHBoxLayout();
        m_btnUpload = new QPushButton("Uploader justificatif", card);
        m_btnUpload->setObjectName("btnUploadJustif");
        m_lblFile = new QLabel("Aucun fichier charge pour le moment.", card);
        m_lblFile->setObjectName("statusInfo");
        m_lblFile->setWordWrap(true);
        m_lblFile->setTextFormat(Qt::RichText);
        uploadRow->addWidget(m_btnUpload);
        uploadRow->addWidget(m_lblFile, 1);
        form->addRow("Justificatif", uploadRow);

        cardLayout->addLayout(form);

        m_lblAttachmentHint = new QLabel(
            "Formats conseilles: PDF, JPG, PNG. Utilisez un document net, complet et si possible nominatif.",
            card);
        m_lblAttachmentHint->setObjectName("sectionHint");
        m_lblAttachmentHint->setWordWrap(true);
        cardLayout->addWidget(m_lblAttachmentHint);

        auto *resultCard = new QFrame(card);
        resultCard->setObjectName("resultCard");
        resultCard->setAttribute(Qt::WA_StyledBackground, true);
        auto *resultLayout = new QVBoxLayout(resultCard);
        resultLayout->setContentsMargins(16, 16, 16, 16);
        resultLayout->setSpacing(8);
        auto *resultTitle = new QLabel("2. Lecture du controle IA", resultCard);
        resultTitle->setObjectName("sectionTitle");
        auto *resultHint = new QLabel(
            "Le moteur IA explique ce qu'il a compris du document, du nom et des dates avant envoi a l'admin.",
            resultCard);
        resultHint->setObjectName("sectionHint");
        resultHint->setWordWrap(true);
        m_lblAiResult = new QLabel("Resultat IA: en attente d'analyse.", resultCard);
        m_lblAiResult->setObjectName("statusInfo");
        m_lblAiResult->setWordWrap(true);
        m_lblAiResult->setTextFormat(Qt::RichText);
        resultLayout->addWidget(resultTitle);
        resultLayout->addWidget(resultHint);
        resultLayout->addWidget(m_lblAiResult);
        cardLayout->addWidget(resultCard);

        auto *actions = new QHBoxLayout();
        m_btnClose = new QPushButton("Fermer", card);
        m_btnClose->setObjectName("btnCloseLeave");
        m_btnSubmit = new QPushButton("Analyser et envoyer a l'admin", card);
        m_btnSubmit->setObjectName("btnSubmitLeave");
        actions->addWidget(m_btnClose);
        actions->addStretch();
        actions->addWidget(m_btnSubmit);
        cardLayout->addLayout(actions);

        content->addWidget(card, 7);

        auto *sideCard = new QFrame(this);
        sideCard->setObjectName("sideCard");
        sideCard->setAttribute(Qt::WA_StyledBackground, true);
        sideCard->setMinimumWidth(290);
        sideCard->setMaximumWidth(360);
        auto *sideLayout = new QVBoxLayout(sideCard);
        sideLayout->setContentsMargins(18, 18, 18, 18);
        sideLayout->setSpacing(14);

        auto *sideTitle = new QLabel("Dossier en cours", sideCard);
        sideTitle->setObjectName("sectionTitle");
        auto *sideHint = new QLabel(
            "Cette colonne vous aide a voir en un coup d'oeil si votre demande est suffisamment solide avant l'analyse.",
            sideCard);
        sideHint->setObjectName("sectionHint");
        sideHint->setWordWrap(true);
        sideLayout->addWidget(sideTitle);
        sideLayout->addWidget(sideHint);

        m_lblIdentityCard = new QLabel(sideCard);
        m_lblIdentityCard->setObjectName("summaryText");
        m_lblIdentityCard->setWordWrap(true);
        m_lblIdentityCard->setTextFormat(Qt::RichText);
        m_lblIdentityCard->setStyleSheet("QLabel { background:#f8fbfd; border:1px solid #dceaf1; border-radius:16px; padding:14px; }");
        sideLayout->addWidget(m_lblIdentityCard);

        m_lblChecklist = new QLabel(sideCard);
        m_lblChecklist->setObjectName("summaryText");
        m_lblChecklist->setWordWrap(true);
        m_lblChecklist->setTextFormat(Qt::RichText);
        m_lblChecklist->setStyleSheet("QLabel { background:#fffaf0; border:1px solid #fde68a; border-radius:16px; padding:14px; }");
        sideLayout->addWidget(m_lblChecklist);

        m_lblReview = new QLabel(sideCard);
        m_lblReview->setObjectName("summaryText");
        m_lblReview->setWordWrap(true);
        m_lblReview->setTextFormat(Qt::RichText);
        m_lblReview->setStyleSheet("QLabel { background:#f8fbfd; border:1px solid #dceaf1; border-radius:16px; padding:14px; }");
        sideLayout->addWidget(m_lblReview);

        sideLayout->addStretch();
        content->addWidget(sideCard, 3);

        root->addLayout(content, 1);

        applySoftCardShadow(hero, QColor(15, 23, 42, 42), 34, QPoint(0, 14));
        applySoftCardShadow(card, QColor(15, 23, 42, 22), 28, QPoint(0, 10));
        applySoftCardShadow(sideCard, QColor(15, 23, 42, 18), 24, QPoint(0, 8));

        connect(m_reason, &QTextEdit::textChanged, this, [this]() {
            updateReasonMeta();
            updateReviewPanel();
            updateSubmitAvailability();
        });
        connect(m_startDate, &QDateEdit::dateChanged, this, [this]() { updateDuration(); });
        connect(m_endDate, &QDateEdit::dateChanged, this, [this]() { updateDuration(); });
        connect(m_btnUpload, &QPushButton::clicked, this, [this]() { chooseAttachment(); });
        connect(m_btnSubmit, &QPushButton::clicked, this, [this]() { submitLeaveRequest(); });
        connect(m_btnClose, &QPushButton::clicked, this, &QDialog::reject);

        updateIdentityPanel();
        updateReasonMeta();
        updateDuration();
        updateAttachmentHint();
        updateReviewPanel();
        updateSubmitAvailability();
    }

private:
    QString decisionToneColor(const QString &decision) const
    {
        if (decision == "JUSTIFIE") return "#166534";
        if (decision == "INSUFFISANT") return "#92400e";
        return "#b91c1c";
    }

    QString decisionToneBg(const QString &decision) const
    {
        if (decision == "JUSTIFIE") return "#ecfdf3";
        if (decision == "INSUFFISANT") return "#fff7ed";
        return "#fef2f2";
    }

    QString decisionToneBorder(const QString &decision) const
    {
        if (decision == "JUSTIFIE") return "#bbf7d0";
        if (decision == "INSUFFISANT") return "#fed7aa";
        return "#fecaca";
    }

    void updateIdentityPanel()
    {
        const QString employeeName = m_employeeContext.employeeName.isEmpty() ? "Employe" : m_employeeContext.employeeName;
        const QString employeeEmail = m_employeeContext.email.isEmpty() ? m_email : m_employeeContext.email;
        const QString matricule = m_employeeContext.matricule.isEmpty() ? "-" : m_employeeContext.matricule;
        const QString specialite = m_employeeContext.specialite.isEmpty() ? "-" : m_employeeContext.specialite;

        m_lblIdentityCard->setText(
            QString("<div style='font-size:13px; font-weight:800; color:#0f172a; margin-bottom:8px;'>Profil detecte</div>"
                    "<div><b>Nom :</b> %1</div>"
                    "<div><b>Email :</b> %2</div>"
                    "<div><b>Matricule :</b> %3</div>"
                    "<div><b>Specialite :</b> %4</div>")
                .arg(employeeName, employeeEmail, matricule, specialite));

        m_lblChecklist->setText(
            "<div style='font-size:13px; font-weight:800; color:#7c2d12; margin-bottom:8px;'>Conseils avant envoi</div>"
            "<div>1. Decrivez clairement la raison.</div>"
            "<div>2. Choisissez exactement la bonne plage de dates.</div>"
            "<div>3. Ajoutez un justificatif lisible et, si possible, nominatif.</div>"
            "<div>4. Evitez les captures coupees ou les documents flous.</div>");
    }

    void updateReasonMeta()
    {
        const int chars = m_reason ? m_reason->toPlainText().trimmed().size() : 0;
        QString text;
        QString color = "#92400e";
        if (chars == 0) {
            text = "Ajoutez la raison du conge et le contexte visible sur le justificatif.";
        } else if (chars < 8) {
            text = QString("Motif saisi: %1 caracteres. Ajoutez quelques details avant l'envoi.").arg(chars);
        } else if (chars < 35) {
            color = "#0f4c81";
            text = QString("Motif saisi: %1 caracteres. C'est valide, mais un peu plus de precision aidera l'admin.").arg(chars);
        } else {
            color = "#166534";
            text = QString("Motif saisi: %1 caracteres. Niveau de detail tres correct.").arg(chars);
        }
        m_lblReasonMeta->setText(text);
        m_lblReasonMeta->setStyleSheet(QString("color:%1; font-weight:700;").arg(color));
    }

    void updateDuration()
    {
        const QDate s = m_startDate ? m_startDate->date() : QDate();
        const QDate e = m_endDate ? m_endDate->date() : QDate();
        if (!s.isValid() || !e.isValid()) {
            m_lblDuration->setText("-");
            updateReviewPanel();
            updateSubmitAvailability();
            return;
        }
        const int days = s.daysTo(e) + 1;
        if (days <= 0) {
            m_lblDuration->setText("<span style='color:#b91c1c; font-weight:800;'>Periode invalide</span>");
            updateReviewPanel();
            updateSubmitAvailability();
            return;
        }
        const QString toneColor = days <= 2 ? "#166534" : (days <= 7 ? "#0f4c81" : "#92400e");
        const QString toneBg = days <= 2 ? "#ecfdf3" : (days <= 7 ? "#eff6ff" : "#fff7ed");
        m_lblDuration->setText(
            QString("<span style='background:%1; color:%2; border:1px solid rgba(15,23,42,0.08); border-radius:999px; padding:5px 10px; font-weight:800;'>"
                    "%3 jour(s) du %4 au %5</span>")
                .arg(toneBg,
                     toneColor,
                     QString::number(days),
                     s.toString("dd/MM/yyyy"),
                     e.toString("dd/MM/yyyy")));
        updateReviewPanel();
        updateSubmitAvailability();
    }

    void updateAttachmentHint()
    {
        if (!m_lblAttachmentHint) return;

        if (m_attachmentPath.trimmed().isEmpty()) {
            m_lblAttachmentHint->setText(
                "Formats conseilles: PDF, JPG, PNG. Utilisez un document net, complet et si possible nominatif.");
            m_lblAttachmentHint->setStyleSheet("color:#64748b; font-size:12px;");
            return;
        }

        const QFileInfo fi(m_attachmentPath);
        const QString suffix = fi.suffix().trimmed().isEmpty() ? "DOCUMENT" : fi.suffix().trimmed().toUpper();
        m_lblAttachmentHint->setText(
            QString("Justificatif pret: %1 detecte. Verifiez que le nom et les dates soient bien visibles pour une validation plus fiable.")
                .arg(suffix));
        m_lblAttachmentHint->setStyleSheet("color:#166534; font-size:12px; font-weight:700;");
    }

    void updateReviewPanel()
    {
        const QString reason = m_reason ? m_reason->toPlainText().trimmed() : QString();
        const QDate s = m_startDate ? m_startDate->date() : QDate();
        const QDate e = m_endDate ? m_endDate->date() : QDate();
        const int days = (s.isValid() && e.isValid()) ? (s.daysTo(e) + 1) : 0;
        const bool validPeriod = s.isValid() && e.isValid() && days > 0;
        const bool hasReason = reason.size() >= 8;
        const bool hasAttachment = !m_attachmentPath.trimmed().isEmpty();
        const int completedBlocks = (hasReason ? 1 : 0) + (validPeriod ? 1 : 0) + (hasAttachment ? 1 : 0);

        const QString periodLabel = validPeriod
                                        ? QString("%1 -> %2 (%3 jour(s))")
                                              .arg(s.toString("dd/MM/yyyy"),
                                                   e.toString("dd/MM/yyyy"),
                                                   QString::number(days))
                                        : "Periode incomplete ou invalide";
        const QString attachmentLabel = hasAttachment
                                            ? QFileInfo(m_attachmentPath).fileName()
                                            : "Aucun justificatif joint";
        const QString nextAction = !hasReason
                                       ? "preciser le motif"
                                       : (!validPeriod ? "corriger la periode"
                                                       : (!hasAttachment ? "joindre le justificatif" : "lancer l'analyse IA"));
        const QString readyLabel = (hasReason && validPeriod && hasAttachment)
                                       ? "Le dossier est pret pour l'analyse IA."
                                       : "Le dossier est encore incomplet.";
        const QString readyColor = (hasReason && validPeriod && hasAttachment) ? "#166534" : "#92400e";
        const QString chipBg = (completedBlocks == 3) ? "#ecfdf3" : ((completedBlocks == 2) ? "#eff6ff" : "#fff7ed");
        const QString chipColor = (completedBlocks == 3) ? "#166534" : ((completedBlocks == 2) ? "#0f4c81" : "#92400e");
        const QString chipBorder = (completedBlocks == 3) ? "#bbf7d0" : ((completedBlocks == 2) ? "#bfdbfe" : "#fed7aa");

        m_lblReview->setText(
            QString("<div style='font-size:13px; font-weight:800; color:#0f172a; margin-bottom:8px;'>Etat du dossier</div>"
                    "<div style='margin-bottom:10px;'><span style='background:%1; color:%2; border:1px solid %3; border-radius:999px; padding:5px 10px; font-weight:800;'>Preparation %4/3</span></div>"
                    "<div><b>Motif :</b> %5</div>"
                    "<div><b>Periode :</b> %6</div>"
                    "<div><b>Justificatif :</b> %7</div>"
                    "<div><b>Prochaine action :</b> %8</div>"
                    "<div style='margin-top:10px; color:%9; font-weight:800;'>%10</div>")
                .arg(chipBg)
                .arg(chipColor)
                .arg(chipBorder)
                .arg(QString::number(completedBlocks))
                .arg(hasReason ? "renseigne" : "a completer")
                .arg(periodLabel)
                .arg(attachmentLabel)
                .arg(nextAction)
                .arg(readyColor)
                .arg(readyLabel));
    }

    void updateSubmitAvailability()
    {
        const QString reason = m_reason ? m_reason->toPlainText().trimmed() : QString();
        const QDate s = m_startDate ? m_startDate->date() : QDate();
        const QDate e = m_endDate ? m_endDate->date() : QDate();
        const bool ready = reason.size() >= 8
                           && s.isValid()
                           && e.isValid()
                           && s.daysTo(e) >= 0
                           && !m_attachmentPath.trimmed().isEmpty();
        if (m_btnSubmit) {
            m_btnSubmit->setEnabled(ready);
            m_btnSubmit->setToolTip(ready ? QString() : "Ajoutez le motif, une periode valide et un justificatif.");
        }
    }

    void chooseAttachment()
    {
        const QString file = QFileDialog::getOpenFileName(
            this,
            "Choisir un justificatif",
            QString(),
            "Documents (*.png *.jpg *.jpeg *.bmp *.webp *.pdf)");
        if (file.isEmpty()) return;

        QString attachmentType;
        QString checkError;
        if (!isSupportedLeaveAttachment(file, attachmentType, checkError)) {
            QMessageBox::warning(this, "Justificatif", checkError);
            return;
        }
        QFileInfo fi(file);
        if (fi.size() > (12 * 1024 * 1024)) {
            QMessageBox::warning(this, "Justificatif", "Fichier trop volumineux (max 12 MB).");
            return;
        }

        m_attachmentPath = file;
        m_lblFile->setText(
            QString("<span style='color:#0f4c81; font-weight:800;'>%1</span><br>"
                    "<span style='color:#64748b;'>Type: %2 | Taille: %3 KB</span>")
                .arg(fi.fileName(),
                     attachmentType,
                     QString::number(qMax<qint64>(1, fi.size() / 1024))));
        updateAttachmentHint();
        updateReviewPanel();
        updateSubmitAvailability();
    }

    void renderAiResultCard(const LeaveAiDecision &ai, const QString &decisionLabel, bool usedFallback)
    {
        const QString decisionKey = ai.decision.trimmed().toUpper();
        const QString chipColor = decisionToneColor(decisionKey);
        const QString chipBg = decisionToneBg(decisionKey);
        const QString chipBorder = decisionToneBorder(decisionKey);
        const QString modeLabel = usedFallback ? "Analyse locale" : "Analyse API";
        const QString docType = ai.documentType.isEmpty() ? "inconnu" : leaveDocumentTypeDisplayLabel(ai.documentType);
        const QString identityStatus = ai.employeeMatch.isEmpty() ? "inconnu" : leaveCheckStatusDisplayLabel(ai.employeeMatch);
        const QString dateStatus = ai.dateMatch.isEmpty() ? "inconnu" : leaveCheckStatusDisplayLabel(ai.dateMatch);
        const QString summary = ai.summary.trimmed().isEmpty() ? "Aucun commentaire detaille fourni." : ai.summary.trimmed();

        QString details;
        details += QString("<div><b>Type de justificatif :</b> %1</div>").arg(docType);
        details += QString("<div><b>Identite employe :</b> %1</div>").arg(identityStatus);
        details += QString("<div><b>Dates du justificatif :</b> %1</div>").arg(dateStatus);
        if (!ai.extractedEmployeeName.trimmed().isEmpty()) {
            details += QString("<div><b>Nom detecte :</b> %1</div>").arg(ai.extractedEmployeeName.toHtmlEscaped());
        }
        if (!ai.extractedDates.isEmpty()) {
            details += QString("<div><b>Dates detectees :</b> %1</div>").arg(ai.extractedDates.join(", ").toHtmlEscaped());
        }
        if (!ai.mismatchFlags.isEmpty()) {
            details += QString("<div><b>Points sensibles :</b> %1</div>").arg(ai.mismatchFlags.join(", ").toHtmlEscaped());
        }

        m_lblAiResult->setText(
            QString("<div style='margin-bottom:10px;'>"
                    "<span style='display:inline-block; background:%1; color:%2; border:1px solid %3; border-radius:999px; padding:6px 12px; font-weight:900;'>%4</span>"
                    "<span style='display:inline-block; margin-left:8px; color:#64748b; font-weight:700;'>Confiance %5%% | %6</span>"
                    "</div>"
                    "<div style='color:#1e293b; line-height:1.55;'>%7</div>"
                    "<div style='margin-top:10px; color:#334155; line-height:1.55;'>%8</div>")
                .arg(chipBg,
                     chipColor,
                     chipBorder,
                     decisionLabel,
                     QString::number(ai.confidence, 'f', 1),
                     modeLabel,
                     summary.toHtmlEscaped(),
                     details));
        m_lblAiResult->setStyleSheet("color:#1e293b; font-size:12px; line-height:1.5;");
    }

    void submitLeaveRequest()
    {
        const QString reason = m_reason ? m_reason->toPlainText().trimmed() : QString();
        const QDate start = m_startDate ? m_startDate->date() : QDate();
        const QDate end = m_endDate ? m_endDate->date() : QDate();
        const int durationDays = start.daysTo(end) + 1;

        if (m_email.isEmpty()) {
            QMessageBox::warning(this, "Demande de conge IA", "Email employe introuvable.");
            return;
        }
        if (reason.size() < 8) {
            QMessageBox::warning(this, "Demande de conge IA", "Veuillez decrire clairement la raison de l'absence.");
            return;
        }
        if (!start.isValid() || !end.isValid() || durationDays <= 0) {
            QMessageBox::warning(this, "Demande de conge IA", "Periode d'absence invalide.");
            return;
        }
        if (m_attachmentPath.trimmed().isEmpty()) {
            QMessageBox::warning(this, "Demande de conge IA", "Veuillez uploader un justificatif (photo ou PDF).");
            return;
        }

        QString attachmentType;
        QString checkError;
        if (!isSupportedLeaveAttachment(m_attachmentPath, attachmentType, checkError)) {
            QMessageBox::warning(this, "Demande de conge IA", checkError);
            return;
        }

        QString sessionError;
        if (!ensureMainWindowDbSessionAlive(sessionError)) {
            showFriendlySqlError(this, "analyser la demande d'absence", sessionError);
            return;
        }

        EmployeeLeaveValidationContext employeeContext;
        QString empError;
        if (!loadEmployeeLeaveValidationContextByEmail(m_email, employeeContext, empError)) {
            showFriendlySqlError(this, "resoudre l'employe", empError);
            return;
        }

        m_btnSubmit->setEnabled(false);
        const bool forceLocalMode = isLocalLeaveAiForced();
        m_lblAiResult->setText(forceLocalMode
                                   ? "<span style='color:#92400e; font-weight:800;'>Mode local actif: analyse du justificatif en cours...</span>"
                                   : "<span style='color:#0f4c81; font-weight:800;'>Analyse IA du justificatif en cours...</span>");
        qApp->processEvents();

        LeaveAiDecision ai;
        QString aiError;
        bool usedFallback = false;
        bool apiOk = false;
        if (!forceLocalMode) {
            apiOk = analyzeLeaveRequestWithApi(
                employeeContext, reason, start, end, durationDays, m_attachmentPath, attachmentType, ai, aiError);

            if (!apiOk && aiError.contains("HTTP 429", Qt::CaseInsensitive)) {
                QThread::msleep(900);
                qApp->processEvents();
                apiOk = analyzeLeaveRequestWithApi(
                    employeeContext, reason, start, end, durationDays, m_attachmentPath, attachmentType, ai, aiError);
            }
        }

        if (!apiOk) {
            if (forceLocalMode && aiError.trimmed().isEmpty()) {
                aiError = "Mode local gratuit force (WASTEGUARD_FORCE_LOCAL_AI=1)";
            }
            if (!forceLocalMode && aiError.trimmed().isEmpty()) {
                aiError = "Analyse API indisponible, bascule automatique sur IA locale.";
            }
            ai = buildLeaveHeuristicDecision(reason,
                                            start,
                                            end,
                                            durationDays,
                                            m_attachmentPath,
                                            attachmentType,
                                            aiError);
            usedFallback = true;
        }

        QString insertError;
        if (!insertEmployeeLeaveRequestRow(employeeContext.idEmp,
                                           m_email,
                                           reason,
                                           start,
                                           end,
                                           durationDays,
                                           m_attachmentPath,
                                           attachmentType,
                                           ai,
                                           insertError)) {
            m_btnSubmit->setEnabled(true);
            showFriendlySqlError(this, "enregistrer la demande d'absence", insertError);
            return;
        }

        bool autoStatusApplied = false;
        QString autoStatusUi;
        QString autoStatusErr;
        const QString autoStatusDb = inferLeaveDbStatusFromDecision(reason, ai);
        if (!autoStatusDb.isEmpty()) {
            autoStatusUi = fromDbDisponibiliteLabel(autoStatusDb);
            if (updateEmployeeDisponibiliteById(employeeContext.idEmp, autoStatusDb, autoStatusErr)) {
                autoStatusApplied = true;
            } else {
                qWarning() << "Employee status auto-update failed:" << autoStatusErr;
            }
        }

        const QString decisionLabel =
            (ai.decision == "JUSTIFIE") ? "Verifiee"
                                        : (ai.decision == "INSUFFISANT" ? "A verifier" : "Refusee");

        const QString notifTitle = QString("Absence employee: %1").arg(employeeContext.employeeName);
        QString notifBody =
            QString("L'employe %1 (%2) demande une absence du %3 au %4 (%5 jour(s)).\n"
                    "Matricule: %6\n"
                    "CIN: %7\n"
                    "Raison: %8\n"
                    "Decision IA: %9 (%10%)\n"
                    "Resume IA: %11")
                .arg(employeeContext.employeeName)
                .arg(m_email)
                .arg(start.toString("yyyy-MM-dd"))
                .arg(end.toString("yyyy-MM-dd"))
                .arg(QString::number(durationDays))
                .arg(employeeContext.matricule.isEmpty() ? "-" : employeeContext.matricule)
                .arg(employeeContext.cin.isEmpty() ? "-" : employeeContext.cin)
                .arg(reason)
                .arg(decisionLabel)
                .arg(QString::number(ai.confidence, 'f', 1))
                .arg(ai.summary);
        if (autoStatusApplied) {
            notifBody += QString("\nStatut employe auto: %1").arg(autoStatusUi);
        } else if (!autoStatusDb.isEmpty() && !autoStatusErr.trimmed().isEmpty()) {
            notifBody += QString("\nAttention: statut employe non mis a jour (%1)").arg(autoStatusErr);
        }

        QString notifError;
        if (!insertAdminNotificationRow("admin@wasteguard.com",
                                        notifTitle,
                                        notifBody,
                                        "LEAVE_REQUEST",
                                        0,
                                        notifError)) {
            qWarning() << "Admin notification insert failed:" << notifError;
        }

        renderAiResultCard(ai, decisionLabel, usedFallback);

        if (usedFallback) {
            QMessageBox::information(
                this,
                "Demande envoyee",
                QString("Demande enregistree en mode local gratuit.\n"
                        "Decision automatique: %1.\n%2\nL'admin (%3) a ete notifie.")
                    .arg(decisionLabel,
                         autoStatusApplied ? QString("Statut applique: %1").arg(autoStatusUi)
                                           : QString("Statut employe conserve"),
                         "admin@wasteguard.com"));
        } else {
            QMessageBox::information(
                this,
                "Demande envoyee",
                QString("Demande enregistree avec succes.\nDecision IA: %1.\n%2\nL'admin (%3) a ete notifie.")
                    .arg(decisionLabel,
                         autoStatusApplied ? QString("Statut applique: %1").arg(autoStatusUi)
                                           : QString("Statut employe conserve"),
                         "admin@wasteguard.com"));
        }

        m_btnSubmit->setEnabled(true);
    }

private:
    QString m_email;
    QString m_attachmentPath;
    EmployeeLeaveValidationContext m_employeeContext;
    QTextEdit *m_reason = nullptr;
    QDateEdit *m_startDate = nullptr;
    QDateEdit *m_endDate = nullptr;
    QLabel *m_lblDuration = nullptr;
    QPushButton *m_btnUpload = nullptr;
    QLabel *m_lblFile = nullptr;
    QLabel *m_lblAttachmentHint = nullptr;
    QLabel *m_lblReasonMeta = nullptr;
    QLabel *m_lblIdentityCard = nullptr;
    QLabel *m_lblChecklist = nullptr;
    QLabel *m_lblReview = nullptr;
    QLabel *m_lblAiResult = nullptr;
    QPushButton *m_btnClose = nullptr;
    QPushButton *m_btnSubmit = nullptr;
};

[[maybe_unused]] void ensureEmployePhotoColumnExists()
{
    static bool checked = false;
    if (checked) return;

    const QSqlDatabase db = QSqlDatabase::database();
    if (!db.isValid() || !db.isOpen()) {
        return;
    }

    QSqlQuery probe;
    if (probe.exec("SELECT photo FROM EMPLOYE WHERE 1=0")) {
        checked = true;
        return;
    }

    if (!isMissingPhotoColumnError(probe.lastError().text())) {
        checked = true;
        return;
    }

    QSqlQuery alter;
    if (alter.exec("ALTER TABLE EMPLOYE ADD (photo BLOB)")) {
        checked = true;
        return;
    }

    QSqlQuery alterFallback;
    alterFallback.exec("ALTER TABLE EMPLOYE ADD photo BLOB");
    checked = true;
}

void ensureEmployeFaceColumnsExist()
{
    static bool checked = false;
    if (checked) return;

    const QSqlDatabase db = QSqlDatabase::database();
    if (!db.isValid() || !db.isOpen()) {
        return;
    }

    QSqlQuery probe;
    if (probe.exec("SELECT face_template, face_template_updated_at, face_enabled FROM EMPLOYE WHERE 1=0")) {
        checked = true;
        return;
    }

    if (!isMissingPhotoColumnError(probe.lastError().text())) {
        checked = true;
        return;
    }

    QSqlQuery q;
    q.exec("ALTER TABLE EMPLOYE ADD (face_template CLOB)");
    q.exec("ALTER TABLE EMPLOYE ADD (face_template_updated_at DATE)");
    q.exec("ALTER TABLE EMPLOYE ADD (face_enabled NUMBER(1) DEFAULT 1)");
    q.exec("UPDATE EMPLOYE SET face_enabled = 1 WHERE face_enabled IS NULL");
    checked = true;
}

QImage makeFaceCropForTemplate(const QImage &src)
{
    if (src.isNull()) return QImage();

    QImage gray = src.convertToFormat(QImage::Format_Grayscale8);
    const int minSide = qMin(gray.width(), gray.height());
    if (minSide < 40) return QImage();

    const int cropSide = qMax(40, static_cast<int>(minSide * 0.62));
    const int x = (gray.width() - cropSide) / 2;
    const int y = (gray.height() - cropSide) / 2;
    const QRect roi(x, y, cropSide, cropSide);
    return gray.copy(roi).scaled(64, 64, Qt::IgnoreAspectRatio, Qt::SmoothTransformation);
}

QVector<float> computeFaceDescriptorForTemplate(const QImage &src)
{
    QImage img = makeFaceCropForTemplate(src);
    if (img.isNull()) return {};

    QVector<float> descriptor;
    descriptor.reserve(16 + 64);

    float hist[16] = {0.0f};
    for (int y = 0; y < img.height(); ++y) {
        const uchar *row = img.constScanLine(y);
        for (int x = 0; x < img.width(); ++x) {
            const int bin = row[x] / 16;
            hist[bin] += 1.0f;
        }
    }

    const float totalPix = static_cast<float>(img.width() * img.height());
    for (float &v : hist) {
        descriptor.append(v / totalPix);
    }

    const int cell = 8;
    for (int gy = 0; gy < 8; ++gy) {
        for (int gx = 0; gx < 8; ++gx) {
            float sum = 0.0f;
            for (int y = gy * cell; y < (gy + 1) * cell; ++y) {
                const uchar *row = img.constScanLine(y);
                for (int x = gx * cell; x < (gx + 1) * cell; ++x) {
                    sum += static_cast<float>(row[x]) / 255.0f;
                }
            }
            descriptor.append(sum / static_cast<float>(cell * cell));
        }
    }

    float norm = 0.0f;
    for (const float v : descriptor) norm += v * v;
    norm = std::sqrt(norm);
    if (norm > 1e-6f) {
        for (float &v : descriptor) v /= norm;
    }
    return descriptor;
}

QString faceDescriptorToString(const QVector<float> &desc)
{
    QStringList parts;
    parts.reserve(desc.size());
    for (const float v : desc) {
        parts << QString::number(static_cast<double>(v), 'f', 6);
    }
    return parts.join(';');
}

QVector<float> faceDescriptorFromString(const QString &rawTemplate)
{
    const QString normalized = rawTemplate.trimmed();
    if (normalized.isEmpty()) return {};

    const QStringList parts = normalized.split(';', Qt::SkipEmptyParts);
    QVector<float> out;
    out.reserve(parts.size());
    for (const QString &p : parts) {
        bool ok = false;
        const float v = p.trimmed().toFloat(&ok);
        if (!ok) return {};
        out.push_back(v);
    }
    return out;
}

double faceDescriptorCosineSimilarity(const QVector<float> &a, const QVector<float> &b)
{
    if (a.isEmpty() || b.isEmpty() || a.size() != b.size()) {
        return -1.0;
    }

    double dot = 0.0;
    double normA = 0.0;
    double normB = 0.0;
    for (int i = 0; i < a.size(); ++i) {
        const double av = static_cast<double>(a.at(i));
        const double bv = static_cast<double>(b.at(i));
        dot += av * bv;
        normA += av * av;
        normB += bv * bv;
    }

    if (normA <= 1e-12 || normB <= 1e-12) {
        return -1.0;
    }

    return dot / (std::sqrt(normA) * std::sqrt(normB));
}

bool verifyEmployeeFaceForTaskCompletion(const QString &email, QWidget *parent, QString &errorText)
{
    errorText.clear();

    const QString cleanEmail = email.trimmed();
    if (cleanEmail.isEmpty()) {
        errorText = "Email employe introuvable pour verification faciale.";
        return false;
    }

    ensureEmployeFaceColumnsExist();

    QString storedTemplate;
    bool faceEnabled = true;

    QSqlQuery q;
    q.prepare("SELECT face_template, face_enabled FROM EMPLOYE "
              "WHERE LOWER(TRIM(email)) = LOWER(TRIM(:email))");
    q.bindValue(":email", cleanEmail);
    if (!q.exec()) {
        QSqlQuery fallback;
        fallback.prepare("SELECT face_template FROM EMPLOYE "
                         "WHERE LOWER(TRIM(email)) = LOWER(TRIM(:email))");
        fallback.bindValue(":email", cleanEmail);
        if (!fallback.exec()) {
            errorText = q.lastError().text().trimmed();
            if (errorText.isEmpty()) errorText = fallback.lastError().text().trimmed();
            if (errorText.isEmpty()) errorText = "Lecture du profil employe impossible.";
            return false;
        }
        if (!fallback.next()) {
            errorText = "Employe introuvable pour verification faciale.";
            return false;
        }
        storedTemplate = fallback.value(0).toString().trimmed();
    } else {
        if (!q.next()) {
            errorText = "Employe introuvable pour verification faciale.";
            return false;
        }
        storedTemplate = q.value(0).toString().trimmed();
        if (!q.value(1).isNull()) {
            faceEnabled = (q.value(1).toInt() != 0);
        }
    }

    if (!faceEnabled) {
        errorText = "Verification faciale desactivee pour cet employe.";
        return false;
    }

    if (storedTemplate.isEmpty()) {
        errorText = "Aucun visage enregistre. Capturez d'abord le visage dans le module employes.";
        return false;
    }

    QString capturedTemplate;
    QString captureError;
    const QByteArray capturedPhoto = captureEmployeePhotoFromCamera(parent, capturedTemplate, captureError);
    if (capturedPhoto.isEmpty() || capturedTemplate.trimmed().isEmpty()) {
        errorText = captureError.trimmed().isEmpty()
                        ? "Verification faciale annulee."
                        : captureError.trimmed();
        return false;
    }

    const QVector<float> storedDesc = faceDescriptorFromString(storedTemplate);
    const QVector<float> liveDesc = faceDescriptorFromString(capturedTemplate);
    if (storedDesc.isEmpty() || liveDesc.isEmpty()) {
        errorText = "Template facial invalide. Re-enregistrez le visage de l'employe.";
        return false;
    }

    const double similarity = faceDescriptorCosineSimilarity(storedDesc, liveDesc);
    if (similarity < 0.0) {
        errorText = "Comparaison faciale impossible. Reessayez.";
        return false;
    }

    static const double kMinSimilarity = 0.90;
    if (similarity < kMinSimilarity) {
        errorText = QString("Visage non reconnu (score=%1, seuil=%2). Rapprochez-vous et reessayez.")
                        .arg(QString::number(similarity, 'f', 3))
                        .arg(QString::number(kMinSimilarity, 'f', 2));
        return false;
    }

    return true;
}

QPixmap circularPixmap(const QPixmap &source, int diameter)
{
    if (source.isNull() || diameter <= 0) {
        return QPixmap();
    }

    const QPixmap scaled = source.scaled(
        diameter,
        diameter,
        Qt::KeepAspectRatioByExpanding,
        Qt::SmoothTransformation
        );

    QPixmap result(diameter, diameter);
    result.fill(Qt::transparent);

    QPainter painter(&result);
    painter.setRenderHint(QPainter::Antialiasing, true);
    QPainterPath clipPath;
    clipPath.addEllipse(0, 0, diameter, diameter);
    painter.setClipPath(clipPath);
    const int x = (diameter - scaled.width()) / 2;
    const int y = (diameter - scaled.height()) / 2;
    painter.drawPixmap(x, y, scaled);
    return result;
}

QIcon employeePhotoIcon(const QByteArray &photoData, int diameter)
{
    if (photoData.isEmpty()) {
        return QIcon();
    }

    QPixmap pixmap;
    if (!pixmap.loadFromData(photoData)) {
        return QIcon();
    }

    return QIcon(circularPixmap(pixmap, diameter));
}

void setEmployeePhotoPreview(QLabel *label, const QByteArray &photoData)
{
    if (!label) return;

    if (photoData.isEmpty()) {
        label->setPixmap(QPixmap());
        label->setText("Photo");
        return;
    }

    QPixmap photo;
    if (!photo.loadFromData(photoData)) {
        label->setPixmap(QPixmap());
        label->setText("Photo");
        return;
    }

    QSize targetSize = label->size();
    if (targetSize.width() <= 0 || targetSize.height() <= 0) {
        targetSize = label->minimumSize();
    }
    if (targetSize.width() <= 0 || targetSize.height() <= 0) {
        targetSize = QSize(200, 300);
    }

    const QPixmap scaled = photo.scaled(
        targetSize,
        Qt::KeepAspectRatio,
        Qt::SmoothTransformation
        );
    label->setText(QString());
    label->setPixmap(scaled);
}

bool validateEmployeePhotoQuality(const QImage &image, QString &reason)
{
    reason.clear();
    if (image.isNull()) {
        reason = "Image invalide.";
        return false;
    }

    if (image.width() < 320 || image.height() < 320) {
        reason = "Image trop petite (minimum 320x320).";
        return false;
    }

    const QImage gray = image.convertToFormat(QImage::Format_Grayscale8);
    const int w = gray.width();
    const int h = gray.height();
    const int step = 2;

    const int roiW = qMax(160, static_cast<int>(w * 0.58));
    const int roiH = qMax(160, static_cast<int>(h * 0.58));
    const int roiX = qMax(0, (w - roiW) / 2);
    const int roiY = qMax(0, (h - roiH) / 2);
    const QRect roi(roiX, roiY, qMin(roiW, w - roiX), qMin(roiH, h - roiY));

    double sum = 0.0;
    double sumSq = 0.0;
    int count = 0;

    for (int y = roi.top(); y < roi.bottom(); y += step) {
        const uchar *row = gray.constScanLine(y);
        for (int x = roi.left(); x < roi.right(); x += step) {
            const double v = static_cast<double>(row[x]);
            sum += v;
            sumSq += v * v;
            ++count;
        }
    }

    if (count <= 0) {
        reason = "Image non exploitable.";
        return false;
    }

    const double mean = sum / static_cast<double>(count);
    const double variance = qMax(0.0, (sumSq / static_cast<double>(count)) - (mean * mean));
    const double stddev = std::sqrt(variance);

    if (mean < 30.0) {
        reason = "Image trop sombre. Augmentez la lumiere.";
        return false;
    }
    if (mean > 235.0) {
        reason = "Image surexposee. Reduisez la lumiere.";
        return false;
    }
    if (stddev < 10.0) {
        reason = "Contraste trop faible. Utilisez un fond plus net.";
        return false;
    }

    double edgeSum = 0.0;
    int edgeCount = 0;
    for (int y = qMax(1, roi.top() + 1); y < qMin(h - 1, roi.bottom() - 1); y += step) {
        const uchar *prev = gray.constScanLine(y - 1);
        const uchar *curr = gray.constScanLine(y);
        const uchar *next = gray.constScanLine(y + 1);
        for (int x = qMax(1, roi.left() + 1); x < qMin(w - 1, roi.right() - 1); x += step) {
            const double gx = std::abs(static_cast<double>(curr[x + 1]) - static_cast<double>(curr[x - 1]));
            const double gy = std::abs(static_cast<double>(next[x]) - static_cast<double>(prev[x]));
            edgeSum += (gx + gy) * 0.5;
            ++edgeCount;
        }
    }

    if (edgeCount <= 0) {
        reason = "Image non exploitable.";
        return false;
    }

    const double sharpness = edgeSum / static_cast<double>(edgeCount);
    const double sharpnessThreshold = 3.0;
    if (sharpness < sharpnessThreshold) {
        reason = "Image floue. Approchez-vous un peu et gardez le visage stable 1 seconde.";
        return false;
    }

    return true;
}

QByteArray captureEmployeePhotoFromCamera(QWidget *parent, QString &faceTemplate, QString &errorText)
{
    faceTemplate.clear();
    errorText.clear();

    const QList<QCameraDevice> cameras = QMediaDevices::videoInputs();
    if (cameras.isEmpty()) {
        errorText = "Aucune camera detectee sur ce poste.";
        return QByteArray();
    }

    QDialog dialog(parent);
    dialog.setWindowTitle("Capture visage employe");
    dialog.setModal(true);
    dialog.resize(760, 560);

    auto *layout = new QVBoxLayout(&dialog);
    layout->setContentsMargins(12, 12, 12, 12);
    layout->setSpacing(10);

    auto *title = new QLabel("Cadrez le visage puis cliquez Capturer");
    title->setStyleSheet("font-weight: 700; font-size: 14px;");
    layout->addWidget(title);

    auto *preview = new QLabel(&dialog);
    preview->setMinimumSize(700, 420);
    preview->setAlignment(Qt::AlignCenter);
    preview->setStyleSheet("background:#0b1220; color:#cbd5e1; border:1px solid #334155; border-radius:8px;");
    preview->setText("Initialisation camera...");
    layout->addWidget(preview);

    auto *status = new QLabel("Verifiez l'eclairage et gardez le visage net.");
    status->setStyleSheet("color:#475569;");
    layout->addWidget(status);

    auto *buttonRow = new QHBoxLayout();
    auto *btnRetry = new QPushButton("Recharger camera", &dialog);
    auto *btnCapture = new QPushButton("Capturer", &dialog);
    auto *btnCancel = new QPushButton("Annuler", &dialog);
    
    QString btnStyle = "QPushButton { background-color: #e2e8f0; color: #0f172a; border: 1px solid #cbd5e1; border-radius: 4px; padding: 6px 14px; font-weight: 600; } "
                       "QPushButton:hover { background-color: #cbd5e1; }";
    QString btnPrimaryStyle = "QPushButton { background-color: #0ea5e9; color: white; border: none; border-radius: 4px; padding: 6px 18px; font-weight: 700; } "
                              "QPushButton:hover { background-color: #0284c7; } "
                              "QPushButton:disabled { background-color: #bae6fd; }";

    btnRetry->setStyleSheet(btnStyle);
    btnCancel->setStyleSheet(btnStyle);
    btnCapture->setStyleSheet(btnPrimaryStyle);

    btnRetry->setCursor(Qt::PointingHandCursor);
    btnCancel->setCursor(Qt::PointingHandCursor);
    btnCapture->setCursor(Qt::PointingHandCursor);

    btnCapture->setEnabled(false);
    btnCapture->setDefault(true);
    buttonRow->addWidget(btnRetry);
    buttonRow->addStretch();
    buttonRow->addWidget(btnCancel);
    buttonRow->addWidget(btnCapture);
    layout->addLayout(buttonRow);

    QMediaCaptureSession session;
    QCamera camera(cameras.first(), &dialog);
    QVideoSink sink(&dialog);
    session.setCamera(&camera);
    session.setVideoSink(&sink);

    QImage lastFrame;
    QByteArray capturedBytes;
    int frameCount = 0;

    QObject::connect(&sink, &QVideoSink::videoFrameChanged, &dialog, [&](const QVideoFrame &frame) {
        if (!frame.isValid()) return;
        const QImage img = frame.toImage();
        if (img.isNull()) return;
        lastFrame = img;
        ++frameCount;
        preview->setPixmap(QPixmap::fromImage(img).scaled(preview->size(), Qt::KeepAspectRatio, Qt::SmoothTransformation));
        if (frameCount >= 1 && !btnCapture->isEnabled()) {
            btnCapture->setEnabled(true);
        }
        if (frameCount > 10) {
            status->setText("Camera prete. Gardez le visage stable puis capturez.");
        }
    });

    QObject::connect(btnRetry, &QPushButton::clicked, &dialog, [&]() {
        camera.stop();
        camera.start();
        frameCount = 0;
        btnCapture->setEnabled(false);
        status->setText("Camera rechargee. Recadrez le visage.");
    });

    QObject::connect(btnCancel, &QPushButton::clicked, &dialog, [&]() {
        dialog.reject();
    });

    QObject::connect(btnCapture, &QPushButton::clicked, &dialog, [&]() {
        if (lastFrame.isNull()) {
            status->setText("Aucune image recue. Verifiez la camera.");
            return;
        }

        QString qualityReason;
        if (!validateEmployeePhotoQuality(lastFrame, qualityReason)) {
            const bool isSoftWarning =
                qualityReason.contains("floue", Qt::CaseInsensitive) ||
                qualityReason.contains("contraste", Qt::CaseInsensitive) ||
                qualityReason.contains("sombre", Qt::CaseInsensitive);
            if (isSoftWarning) {
                const auto answer = QMessageBox::question(
                    &dialog,
                    "Qualite limite",
                    qualityReason + "\n\nVoulez-vous capturer quand meme ?",
                    QMessageBox::Yes | QMessageBox::No,
                    QMessageBox::No);
                if (answer != QMessageBox::Yes) {
                    status->setText(qualityReason);
                    return;
                }
            } else {
                status->setText(qualityReason);
                return;
            }
        }

        const QVector<float> descriptor = computeFaceDescriptorForTemplate(lastFrame);
        if (descriptor.isEmpty()) {
            status->setText("Visage non detecte. Recadrez le visage et reessayez.");
            return;
        }

        QByteArray jpegData;
        QBuffer buffer(&jpegData);
        if (!buffer.open(QIODevice::WriteOnly) || !lastFrame.save(&buffer, "JPG", 92)) {
            status->setText("Capture impossible. Reessayez.");
            return;
        }

        capturedBytes = jpegData;
        faceTemplate = faceDescriptorToString(descriptor);
        dialog.accept();
    });

    camera.start();
    if (camera.error() != QCamera::NoError) {
        errorText = camera.errorString().trimmed().isEmpty()
                        ? "Impossible de demarrer la camera."
                        : camera.errorString().trimmed();
        camera.stop();
        return QByteArray();
    }
    const int rc = dialog.exec();
    camera.stop();

    if (rc != QDialog::Accepted || capturedBytes.isEmpty()) {
        if (errorText.isEmpty()) {
            errorText = "Capture annulee.";
        }
        faceTemplate.clear();
        return QByteArray();
    }

    return capturedBytes;
}

QByteArray chooseEmployeePhotoBytes(QWidget *parent)
{
    const QString filePath = QFileDialog::getOpenFileName(
        parent,
        "Choisir une photo",
        QString(),
        "Images (*.png *.jpg *.jpeg *.bmp *.webp)"
        );
    if (filePath.isEmpty()) {
        return QByteArray();
    }

    QFile file(filePath);
    if (!file.open(QIODevice::ReadOnly)) {
        QMessageBox::warning(parent, "Photo", "Impossible de lire le fichier image.");
        return QByteArray();
    }

    const QByteArray data = file.readAll();
    QImage validation;
    if (!validation.loadFromData(data)) {
        QMessageBox::warning(parent, "Photo", "Image invalide. Choisissez un autre fichier.");
        return QByteArray();
    }

    QString qualityReason;
    if (!validateEmployeePhotoQuality(validation, qualityReason)) {
        QMessageBox::warning(parent, "Qualite photo", qualityReason);
        return QByteArray();
    }

    return data;
}

QString foldTextKey(QString value)
{
    value = value.normalized(QString::NormalizationForm_D).toLower().trimmed();
    QString out;
    out.reserve(value.size());
    for (const QChar ch : value) {
        const QChar::Category cat = ch.category();
        if (cat == QChar::Mark_NonSpacing ||
            cat == QChar::Mark_SpacingCombining ||
            cat == QChar::Mark_Enclosing) {
            continue;
        }
        if (ch.isLetterOrNumber() || ch == QChar(' ')) {
            out.append(ch);
        }
    }
    return out.simplified();
}

QString moduleKeyFromSpecialiteComboLabel(const QString &specialite)
{
    const QString s = foldTextKey(specialite);
    if (s == "admin") return "admin";
    if (s.contains("responsable produits")) return "produits";
    if (s.contains("responsable commandes")) return "commandes";
    if (s.contains("responsable stock")) return "stock";
    if (s.contains("responsable clients")) return "clients";
    if (s.contains("responsable employes") || s.contains("responsable rh")) return "employes";
    if (s.contains("responsable maintenances") || s.contains("responsable maintenance") || s.contains("responsable maitenance")) return "maintenance";
    return QString();
}

bool specialityMatchesComboResponsibleType(const QString &specialite, const QString &moduleKey)
{
    const QString s = foldTextKey(specialite);
    const QString key = moduleKey.trimmed().toLower();
    if (key == "commandes") return s.contains("responsable commandes");
    if (key == "clients") return s.contains("responsable clients");
    if (key == "stock") return s.contains("responsable stock");
    if (key == "produits") return s.contains("responsable produits");
    if (key == "maintenance") return s.contains("responsable maintenance") || s.contains("responsable maintenances") || s.contains("responsable maitenance");
    if (key == "employes") return s.contains("responsable employes") || s.contains("responsable rh");
    return false;
}

QString moduleKeyForSpecialite(const QString &specialite)
{
    const QString comboMapped = moduleKeyFromSpecialiteComboLabel(specialite);
    if (!comboMapped.isEmpty()) return comboMapped;

    const QString s = foldTextKey(specialite);

    if (s.contains("admin")) return "admin";

    // Nouveaux formats
    if (s.contains("produit")) return "produits";
    if (s.contains("fabrication") || s.contains("assemblage") || s.contains("atelier")) return "produits";
    if (s.contains("commande") || s.contains("vente") || s.contains("livraison") || s.contains("transport")) return "commandes";
    if (s.contains("stock")) return "stock";
    if (s.contains("entrepot") || s.contains("depot") || s.contains("magasin") || s.contains("approvision")) return "stock";
    if (s.contains("mainten") || s.contains("maiten") || s.contains("maintenance")) return "maintenance";
    if (s.contains("intervention") || s.contains("depannage") || s.contains("reparation")) return "maintenance";
    if (s.contains("sav") || s.contains("service apres vente") || s.contains("relation client") || s.contains("client")) return "clients";
    if (s.contains("employe") || s.contains("rh")) return "employes";

    // Anciennes valeurs de compatibilitÃƒÂ©
    if (s.contains("mecanicien") || s.contains("production") || s.contains("atelier")) {
        return "produits";
    }
    if (s.contains("electronicien") || s.contains("electricien") || s.contains("technicien")) {
        return "maintenance";
    }
    if (s.contains("logisticien") || s.contains("logistique") || s.contains("magasinier")) {
        return "stock";
    }
    if (s.contains("chauffeur") || s.contains("livreur") || s.contains("transport")) {
        return "commandes";
    }
    if (s.contains("commercial")) {
        return "commandes";
    }

    return QString();
}

QString moduleDisplayName(const QString &moduleKey)
{
    const QString k = moduleKey.trimmed().toLower();
    if (k == "maintenance") return "Maintenances";
    if (k == "stock") return "Stock";
    if (k == "produits") return "Produits";
    if (k == "commandes") return "Commandes";
    if (k == "clients") return "Clients";
    if (k == "employes") return "Employes";
    if (k == "accueil") return "Accueil";
    if (k == "taches") return "Mes taches";
    if (k == "conge") return "Demande conge";
    return "Module";
}

QString moduleKeyForPageObjectName(const QString &objectName)
{
    const QString name = objectName.trimmed().toLower();
    if (name.isEmpty()) return QString();

    if (name == "dashboardaccueil" || name == "home" || name == "accueil") return "accueil";
    if (name == "mission") return "taches";
    if (name == "pointage") return "conge";
    if (name == "statistiques") return "statistiques";

    if (name == "affichage" || name == "ajout" || name == "modification" || name.contains("employe")) return "employes";
    if (name.contains("pagestock") || name == "stock") return "stock";
    if (name.contains("pageproduit") || name.contains("produit")) return "produits";
    if (name.contains("pageclient") || name == "client") return "clients";
    if (name.contains("maintenance") || name.contains("maint")) return "maintenance";
    if (name.contains("pagecmd") || name.contains("commande")) return "commandes";

    return QString();
}

int missionDifficultyLevel(const QString &missionText)
{
    const QString t = foldTextKey(missionText);
    const QStringList veryHardWords = {
        "tres difficile", "tres complexe", "extreme", "urgence absolue", "bloquant total",
        "incident majeur", "panne generale", "multi site", "multisite", "crise"
    };
    for (const QString &w : veryHardWords) {
        if (t.contains(w)) return 4;
    }
    const QStringList hardWords = {"urgent", "critique", "complexe", "majeur", "magistral", "magistrale", "grave", "bloquant", "immediat"};
    for (const QString &w : hardWords) {
        if (t.contains(w)) return 3;
    }
    const QStringList mediumWords = {"moyen", "normale", "standard", "planifie", "diagnostic",
                                     "reparation", "maintenance", "depannage", "panne"};
    for (const QString &w : mediumWords) {
        if (t.contains(w)) return 2;
    }
    return 1;
}

QString difficultyLabel(int level)
{
    switch (level) {
    case 4: return "Tres elevee";
    case 3: return "Elevee";
    case 2: return "Moyenne";
    default: return "Faible";
    }
}

