QString missionTargetModuleKey(const QString &missionText)
{
    if (missionLooksMaintenanceRelated(missionText)) return "maintenance";

    const QString t = foldTextKey(missionText);

    const QStringList savTokens = {
        "sav", "service apres vente", "service client", "relation client", "reclamation", "support client"
    };
    for (const QString &token : savTokens) {
        if (t.contains(token)) return "clients";
    }

    const QStringList salesTokens = {
        "vente", "commande", "devis", "livraison", "transport", "expedition"
    };
    for (const QString &token : salesTokens) {
        if (t.contains(token)) return "commandes";
    }

    const QStringList stockTokens = {
        "stock", "inventaire", "magasin", "approvisionnement", "fournisseur",
        "matiere premiere", "seuil", "rupture", "entrepot"
    };
    for (const QString &token : stockTokens) {
        if (t.contains(token)) return "stock";
    }

    const QStringList productTokens = {
        "fabrication", "production", "assemblage", "atelier", "chaine", "produit", "usine"
    };
    for (const QString &token : productTokens) {
        if (t.contains(token)) return "produits";
    }

    const QStringList interventionTokens = {
        "intervention", "maintenance", "depannage", "reparation", "panne", "diagnostic", "curatif", "preventif"
    };
    for (const QString &token : interventionTokens) {
        if (t.contains(token)) return "maintenance";
    }

    return QString();
}

bool missionLooksInDomain(const QString &missionText, const QStringList &requiredHints)
{
    if (!requiredHints.isEmpty()) return true;

    const QString t = foldTextKey(missionText);
    const QStringList domainTokens = {
        "maintenance", "maitenance", "maintennance", "intervention", "reparation", "repartation", "depannage", "panne", "diagnostic",
        "sav", "service client", "relation client", "reclamation", "client",
        "vente", "commande", "livraison", "devis", "expedition", "facturation",
        "collecte", "dechet", "camion", "benne", "bac", "capteur", "electrique",
        "mecanique", "soudure", "atelier", "reseau", "iot", "logiciel", "systeme",
        "installation", "controle", "supervision", "inspection", "curatif", "preventif"
    };

    for (const QString &token : domainTokens) {
        if (t.contains(token)) return true;
    }
    return false;
}

bool isEmployeeAvailable(const QString &status)
{
    const QString s = foldTextKey(status);
    if (s.contains("indispon")) return false;
    if (s.contains("mission")) return false;
    if (s.contains("interven")) return false;   // EN_INTERVENTION
    if (s.contains("conge")) return false;
    if (s.contains("maladie")) return false;
    if (s.contains("absent")) return false;
    // Explicitly available
    if (s.contains("dispon")) return true;
    // Unknown / empty status: treat as available so employees without a status are not silently excluded
    return true;
}

bool specialityMatches(const QString &employeeSpeciality, const QStringList &requiredHints)
{
    if (requiredHints.isEmpty()) return true;
    const QString spec = foldTextKey(employeeSpeciality);
    for (const QString &hint : requiredHints) {
        if (hint == "commandes") {
            if (spec.contains("commande") || spec.contains("vente") || spec.contains("livraison")
                || spec.contains("logist") || spec.contains("transport") || spec.contains("commercial")) return true;
            continue;
        }
        if (hint == "clients") {
            if (spec.contains("client") || spec.contains("sav") || spec.contains("support")
                || spec.contains("relation")) return true;
            continue;
        }
        if (hint == "stock") {
            if (spec.contains("stock") || spec.contains("logist") || spec.contains("magasin") || spec.contains("approvision")) return true;
            continue;
        }
        if (hint == "produits") {
            if (spec.contains("produit") || spec.contains("production") || spec.contains("fabric") || spec.contains("atelier") || spec.contains("mecan")) return true;
            continue;
        }
        if (hint == "intervention") {
            if (spec.contains("interven") || spec.contains("mainten") || spec.contains("techn") || spec.contains("depann") || spec.contains("repar") || spec.contains("mecan") || spec.contains("electri")) return true;
            continue;
        }
        if (hint == "electricite") {
            if (spec.contains("electri") || spec.contains("electro")) return true;
            continue;
        }
        if (hint == "mecanique") {
            if (spec.contains("mecan")) return true;
            continue;
        }
        if (hint == "conduite") {
            if (spec.contains("chauff") || spec.contains("conduct")) return true;
            continue;
        }
        if (hint == "soudure") {
            if (spec.contains("soud")) return true;
            continue;
        }
        if (hint == "it") {
            if (spec.contains("techn") || spec.contains("informat") || spec.contains("reseau")) return true;
            continue;
        }
        if (hint == "management") {
            if (spec.contains("respons") || spec.contains("chef") || spec.contains("manager")) return true;
            continue;
        }
        if (spec.contains(hint) || hint.contains(spec)) return true;
    }
    return false;
}

QString normalizeApiHint(const QString &raw)
{
    const QString h = foldTextKey(raw);
    if (h.contains("commande") || h.contains("vente") || h.contains("livraison") || h.contains("logist") || h.contains("transport")) return "commandes";
    if (h.contains("client") || h.contains("sav") || h.contains("support") || h.contains("reclamation") || h.contains("relation")) return "clients";
    if (h.contains("stock") || h.contains("invent") || h.contains("magasin") || h.contains("approvision") || h.contains("fournisseur")) return "stock";
    if (h.contains("produit") || h.contains("fabric") || h.contains("product") || h.contains("assembl") || h.contains("atelier")) return "produits";
    if (h.contains("interven") || h.contains("mainten") || h.contains("depann") || h.contains("repar")) return "intervention";
    if (h.contains("electr") || h.contains("eclair") || h.contains("ampoule") || h.contains("electro")) return "electricite";
    if (h.contains("mecan")) return "mecanique";
    if (h.contains("chauff") || h.contains("condu") || h.contains("transport")) return "conduite";
    if (h.contains("soud")) return "soudure";
    if (h.contains("informat") || h.contains("techn") || h.contains("reseau") || h.contains("iot")) return "it";
    if (h.contains("manag") || h.contains("chef") || h.contains("respons")) return "management";
    return QString();
}

int normalizeApiDifficulty(const QString &raw, int fallback)
{
    const QString d = foldTextKey(raw);
    if (d.contains("veryhigh") || d.contains("very high") || d.contains("very hard") || d.contains("tres elevee") || d.contains("extreme")) return 4;
    if (d.contains("high") || d.contains("elevee") || d.contains("urgent") || d.contains("critique")) return 3;
    if (d.contains("medium") || d.contains("moyenne") || d.contains("normal") || d.contains("standard")) return 2;
    if (d.contains("low") || d.contains("faible")) return 1;
    return fallback;
}

QString responsibleTitleForModule(const QString &moduleKey)
{
    const QString k = moduleKey.trimmed().toLower();
    if (k == "commandes") return "Responsable Commandes";
    if (k == "clients") return "Responsable Clients";
    if (k == "maintenance") return "Responsable Intervention";
    if (k == "stock") return "Responsable Stock";
    if (k == "produits") return "Responsable Produits";
    if (k == "employes") return "Responsable RH";
    return QString();
}

bool specialityMatchesResponsibleModule(const QString &employeeSpeciality, const QString &moduleKey)
{
    if (moduleKey.trimmed().isEmpty()) return false;

    if (specialityMatchesComboResponsibleType(employeeSpeciality, moduleKey)) {
        return true;
    }

    const QString spec = foldTextKey(employeeSpeciality);
    const bool hasLeadRole = spec.contains("responsable") || spec.contains("chef") || spec.contains("manager") || spec.contains("superviseur");
    if (!hasLeadRole) return false;

    const QString key = moduleKey.trimmed().toLower();
    if (key == "commandes") {
        return spec.contains("commande") || spec.contains("vente") || spec.contains("livraison") || spec.contains("logist") || spec.contains("transport");
    }
    if (key == "clients") {
        return spec.contains("client") || spec.contains("sav") || spec.contains("support") || spec.contains("relation");
    }
    if (key == "maintenance") {
        return spec.contains("intervention") || spec.contains("maintenance") || spec.contains("depann") || spec.contains("repar") || spec.contains("technique");
    }
    if (key == "stock") {
        return spec.contains("stock") || spec.contains("magasin") || spec.contains("invent") || spec.contains("approvision");
    }
    if (key == "produits") {
        return spec.contains("produit") || spec.contains("production") || spec.contains("atelier") || spec.contains("fabric");
    }
    if (key == "employes") {
        return spec.contains("rh") || spec.contains("employe") || spec.contains("ressources humaines");
    }
    return false;
}

bool inferMissionByApi(const QString &missionText,
                       int &difficulty,
                       QStringList &hints,
                       QString &sourceNote,
                       QString &errorText)
{
    static const QString kGeminiDefaultModel = "gemini-2.0-flash";
    static const QString kGeminiDefaultBaseUrl = "https://generativelanguage.googleapis.com/v1beta/openai/";
    static const QString kOpenAiDefaultModel = "gpt-4o-mini";
    static const QString kOpenAiDefaultBaseUrl = "https://api.openai.com/v1";
    static const QString kDeepSeekDefaultModel = "deepseek-chat";
    static const QString kDeepSeekDefaultBaseUrl = "https://api.deepseek.com/v1";
    static const QString kOllamaDefaultModel = "qwen2.5:3b";
    static const QString kOllamaDefaultBaseUrl = "http://127.0.0.1:11434/v1";

    const QProcessEnvironment env = QProcessEnvironment::systemEnvironment();
    const QString geminiApiKey = env.value("GEMINI_API_KEY").trimmed();
    const QString openAiApiKey = env.value("OPENAI_API_KEY").trimmed();
    const QString deepSeekApiKey = env.value("DEEPSEEK_API_KEY").trimmed();
    const QString ollamaApiKey = env.value("OLLAMA_API_KEY").trimmed();
    const QString providerPreference = env.value("WASTEGUARD_AI_PROVIDER").trimmed().toLower();

    QString apiKey;
    QString baseUrl;
    QString model;
    QString providerLabel;
    QString openAiProjectId;
    QString openAiOrgId;
    bool providerRequiresApiKey = true;

    const auto pickOpenAi = [&]() {
        apiKey = openAiApiKey;
        baseUrl = env.value("OPENAI_BASE_URL").trimmed();
        if (baseUrl.isEmpty()) baseUrl = kOpenAiDefaultBaseUrl;
        model = env.value("OPENAI_MODEL").trimmed();
        if (model.isEmpty()) model = kOpenAiDefaultModel;
        providerLabel = "OpenAI";
        openAiProjectId = env.value("OPENAI_PROJECT_ID").trimmed();
        openAiOrgId = env.value("OPENAI_ORG_ID").trimmed();
        providerRequiresApiKey = true;
    };
    const auto pickDeepSeek = [&]() {
        apiKey = deepSeekApiKey;
        baseUrl = env.value("DEEPSEEK_BASE_URL").trimmed();
        if (baseUrl.isEmpty()) baseUrl = kDeepSeekDefaultBaseUrl;
        model = env.value("DEEPSEEK_MODEL").trimmed();
        if (model.isEmpty()) model = kDeepSeekDefaultModel;
        providerLabel = "DeepSeek";
        openAiProjectId.clear();
        openAiOrgId.clear();
        providerRequiresApiKey = true;
    };
    const auto pickOllama = [&]() {
        apiKey = ollamaApiKey;
        baseUrl = env.value("OLLAMA_BASE_URL").trimmed();
        if (baseUrl.isEmpty()) baseUrl = kOllamaDefaultBaseUrl;
        model = env.value("OLLAMA_MODEL").trimmed();
        if (model.isEmpty()) model = kOllamaDefaultModel;
        providerLabel = "Ollama";
        openAiProjectId.clear();
        openAiOrgId.clear();
        providerRequiresApiKey = false;
    };
    const auto pickGemini = [&]() {
        apiKey = geminiApiKey;
        baseUrl = env.value("GEMINI_BASE_URL").trimmed();
        if (baseUrl.isEmpty()) baseUrl = kGeminiDefaultBaseUrl;
        model = env.value("GEMINI_MODEL").trimmed();
        if (model.isEmpty()) model = kGeminiDefaultModel;
        providerLabel = "Gemini";
        openAiProjectId.clear();
        openAiOrgId.clear();
        providerRequiresApiKey = true;
    };

    if (providerPreference == "gemini") {
        if (!geminiApiKey.isEmpty()) pickGemini();
        else if (!deepSeekApiKey.isEmpty()) pickDeepSeek();
        else if (!openAiApiKey.isEmpty()) pickOpenAi();
        else pickOllama();
    } else if (providerPreference == "ollama") {
        pickOllama();
    } else if (providerPreference == "deepseek") {
        if (!deepSeekApiKey.isEmpty()) pickDeepSeek();
        else if (!openAiApiKey.isEmpty()) pickOpenAi();
        else if (!geminiApiKey.isEmpty()) pickGemini();
        else pickOllama();
    } else {
        // Default behavior: prioritize OpenAI if configured.
        if (!openAiApiKey.isEmpty()) pickOpenAi();
        else if (!deepSeekApiKey.isEmpty()) pickDeepSeek();
        else if (!geminiApiKey.isEmpty()) pickGemini();
        else pickOllama();
    }

    if (providerLabel.isEmpty()) {
        errorText = "Aucun provider IA detecte. Configurez WASTEGUARD_AI_PROVIDER (openai, deepseek, gemini ou ollama).";
        return false;
    }

    if (providerRequiresApiKey && apiKey.isEmpty()) {
        errorText = "Aucune cle API configuree. Definissez OPENAI_API_KEY, DEEPSEEK_API_KEY ou GEMINI_API_KEY.";
        return false;
    }

    if (baseUrl.endsWith('/')) baseUrl.chop(1);

    QUrl url(baseUrl + "/chat/completions");
    if (!url.isValid()) {
        errorText = "Endpoint API invalide (mission IA).";
        return false;
    }

    QJsonObject systemMsg{
        {"role", "system"},
        {"content",
         "Tu es un classifieur de missions RH/maintenance. "
         "Reponds strictement en JSON avec les champs: "
            "difficulty (low|medium|high|very_high), specialties (array), confidence (0..1), rationale (court). "
            "specialties doit privilegier: commandes, clients, stock, produits, intervention, electricite, mecanique, conduite, soudure, it, management."}
    };
    QJsonObject userMsg{
        {"role", "user"},
        {"content", QString("Mission: %1").arg(missionText)}
    };

    QJsonObject payload{
        {"model", model},
        {"temperature", 0.1},
        {"messages", QJsonArray{systemMsg, userMsg}}
    };
    if (providerLabel != "DeepSeek") {
        payload.insert("response_format", QJsonObject{{"type", "json_object"}});
    }

    QNetworkRequest req(url);
    req.setHeader(QNetworkRequest::ContentTypeHeader, "application/json");
    if (!apiKey.isEmpty()) {
        req.setRawHeader("Authorization", ("Bearer " + apiKey).toUtf8());
    }
    if (providerLabel == "OpenAI") {
        if (!openAiProjectId.isEmpty()) req.setRawHeader("OpenAI-Project", openAiProjectId.toUtf8());
        if (!openAiOrgId.isEmpty()) req.setRawHeader("OpenAI-Organization", openAiOrgId.toUtf8());
    }

    QNetworkAccessManager nam;
    QNetworkReply *reply = nam.post(req, QJsonDocument(payload).toJson(QJsonDocument::Compact));

    QEventLoop loop;
    QTimer timeout;
    timeout.setSingleShot(true);
    QObject::connect(&timeout, &QTimer::timeout, &loop, &QEventLoop::quit);
    QObject::connect(reply, &QNetworkReply::finished, &loop, &QEventLoop::quit);
    timeout.start(10000);
    loop.exec();

    if (timeout.isActive() == false && reply->isFinished() == false) {
        reply->abort();
    }

    if (reply->error() != QNetworkReply::NoError) {
        const QByteArray errorBytes = reply->readAll();
        errorText = formatApiReplyError(reply, errorBytes);
        reply->deleteLater();
        return false;
    }

    const QByteArray responseBytes = reply->readAll();
    reply->deleteLater();

    QJsonParseError parseErr;
    const QJsonDocument responseDoc = QJsonDocument::fromJson(responseBytes, &parseErr);
    if (parseErr.error != QJsonParseError::NoError || !responseDoc.isObject()) {
        errorText = QString("Reponse API non JSON.\nPayload brut:\n%1")
                        .arg(QString::fromUtf8(responseBytes.left(1000)));
        return false;
    }

    const QJsonObject responseObj = responseDoc.object();
    const QJsonArray choices = responseObj.value("choices").toArray();
    if (choices.isEmpty()) {
        errorText = "Aucun choix retourne";
        return false;
    }

    const auto extractContentText = [](const QJsonValue &contentVal) -> QString {
        if (contentVal.isString()) {
            return contentVal.toString();
        }
        if (contentVal.isArray()) {
            QStringList chunks;
            const QJsonArray arr = contentVal.toArray();
            for (const QJsonValue &entry : arr) {
                if (entry.isString()) {
                    const QString s = entry.toString().trimmed();
                    if (!s.isEmpty()) chunks << s;
                    continue;
                }
                if (!entry.isObject()) continue;
                const QJsonObject obj = entry.toObject();
                const QString type = obj.value("type").toString().trimmed().toLower();
                if (type == "text") {
                    const QString s = obj.value("text").toString().trimmed();
                    if (!s.isEmpty()) chunks << s;
                }
            }
            return chunks.join("\n");
        }
        if (contentVal.isObject()) {
            return contentVal.toObject().value("text").toString().trimmed();
        }
        return QString();
    };

    const QJsonObject firstChoice = choices.first().toObject();
    const QJsonObject firstMessage = firstChoice.value("message").toObject();
    QString content = extractContentText(firstMessage.value("content")).trimmed();
    if (content.isEmpty()) {
        content = firstChoice.value("text").toString().trimmed();
    }
    if (content.trimmed().isEmpty()) {
        errorText = "Contenu vide";
        return false;
    }

    QJsonDocument contentDoc = QJsonDocument::fromJson(content.toUtf8(), &parseErr);
    if (parseErr.error != QJsonParseError::NoError || !contentDoc.isObject()) {
        const QRegularExpression jsonRe(R"(\{[\s\S]*\})");
        const QRegularExpressionMatch m = jsonRe.match(content);
        if (m.hasMatch()) {
            contentDoc = QJsonDocument::fromJson(m.captured(0).toUtf8(), &parseErr);
        }
    }
    if (parseErr.error != QJsonParseError::NoError || !contentDoc.isObject()) {
        errorText = "JSON modele invalide";
        return false;
    }

    const QJsonObject aiObj = contentDoc.object();
    const int inferredDifficulty = qBound(1, normalizeApiDifficulty(aiObj.value("difficulty").toString(), difficulty), 4);
    QStringList inferredHints;
    for (const QString &hintValue : jsonValueToStringList(aiObj.value("specialties"))) {
        const QString normalized = normalizeApiHint(hintValue);
        if (!normalized.isEmpty() && !inferredHints.contains(normalized)) inferredHints << normalized;
    }

    difficulty = inferredDifficulty;
    if (!inferredHints.isEmpty()) hints = inferredHints;
    sourceNote = QString("IA API (%1)").arg(model);
    errorText.clear();
    return true;
}

int fallbackExperienceYears(int idEmp, const QString &matricule)
{
    int seed = qAbs(idEmp);
    if (seed <= 0) {
        QString digits;
        for (const QChar ch : matricule) {
            if (ch.isDigit()) digits.append(ch);
        }
        seed = digits.isEmpty() ? 1 : digits.toInt();
    }
    return 1 + (seed % 9);
}

void enableStyledBgRecursive(QWidget *root)

{

    if (!root) return;



    root->setAttribute(Qt::WA_StyledBackground, true);



    const auto childs = root->findChildren<QWidget*>(QString(), Qt::FindDirectChildrenOnly);

    for (QWidget *c : childs)

        enableStyledBgRecursive(c);

}



void repolishRecursive(QWidget *root)

{

    if (!root) return;



    root->style()->unpolish(root);

    root->style()->polish(root);

    root->update();



    const auto childs = root->findChildren<QWidget*>(QString(), Qt::FindDirectChildrenOnly);

    for (QWidget *c : childs)

        repolishRecursive(c);

}



