bool MainWindow::isModuleAccessAllowed(const QString &moduleKey) const
{
    const QString key = moduleKey.trimmed().toLower();
    if (key.isEmpty()) return false;
    if (m_isAdminSession) return true;
    if (key == "accueil" || key == "taches" || key == "conge") return true;
    return !m_employeeAllowedModule.trimmed().isEmpty()
        && key == m_employeeAllowedModule.trimmed().toLower();
}

bool MainWindow::guardModuleAccess(const QString &moduleKey, const QString &moduleLabel)
{
    if (isModuleAccessAllowed(moduleKey)) {
        return true;
    }

    const QString spec = m_sessionSpecialite.trimmed().isEmpty()
        ? "Non defini"
        : m_sessionSpecialite.trimmed();
    const QString allowedLabel = moduleDisplayName(m_employeeAllowedModule);

    QMessageBox::information(
        this,
        "Acces limite",
        QString("Acces refuse a \"%1\".\nVotre specialite: %2\nModule autorise: %3")
            .arg(moduleLabel, spec, allowedLabel));
    return false;
}

void MainWindow::applySessionAccessControl()
{
    if (!ui) return;

    struct SidebarAccess {
        QString key;
        QPushButton *btn;
    };

    const QList<SidebarAccess> entries = {
        {"accueil", ui ? ui->btnAccueil : nullptr},
        {"stock", ui ? ui->btnStock : nullptr},
        {"produits", ui ? ui->btnProduits : nullptr},
        {"clients", ui ? ui->btnClient : nullptr},
        {"employes", ui ? ui->btnEmployes : nullptr},
        {"maintenance", ui ? ui->btnMaintenance : nullptr},
        {"commandes", findChild<QPushButton*>("btnCommandes")}
    };

    for (const SidebarAccess &entry : entries) {
        if (!entry.btn) continue;
        const bool allowed = isModuleAccessAllowed(entry.key);
        const bool visibleForSession = m_isAdminSession || allowed;
        entry.btn->setVisible(visibleForSession);
        entry.btn->setEnabled(allowed);
        if (allowed || m_isAdminSession) {
            entry.btn->setToolTip(QString());
        } else {
            entry.btn->setToolTip(
                QString("Acces reserve. Module autorise: %1")
                    .arg(moduleDisplayName(m_employeeAllowedModule)));
            entry.btn->setChecked(false);
        }
    }

    auto applyQuickButtonState = [&](QPushButton *btn, bool enabled, const QString &lockedTooltip) {
        if (!btn) return;
        if (!btn->property("defaultText").isValid()) {
            btn->setProperty("defaultText", btn->text());
        }
        btn->setEnabled(enabled);
        btn->setToolTip(enabled ? QString() : lockedTooltip);
    };

    QPushButton *btnMission = findChild<QPushButton*>("btnGoMission");
    QPushButton *btnPointage = findChild<QPushButton*>("btnGoPointage");
    QPushButton *btnStats = findChild<QPushButton*>("btnGoStats");
    QPushButton *btnFiche = findChild<QPushButton*>("btnFichePaie");
    QPushButton *btnExport = findChild<QPushButton*>("btnExport");

    const QString lockTip = "Acces reserve au compte administrateur.";
    applyQuickButtonState(btnMission, true, QString());
    applyQuickButtonState(btnPointage, true, QString());
    applyQuickButtonState(btnStats, m_isAdminSession, lockTip);
    applyQuickButtonState(btnFiche, m_isAdminSession, lockTip);
    applyQuickButtonState(btnExport, m_isAdminSession, lockTip);

    if (btnMission && btnMission->property("defaultText").isValid()) {
        const QString defaultText = btnMission->property("defaultText").toString();
        btnMission->setText(m_isAdminSession ? defaultText : "Mes taches IA");
        btnMission->setToolTip(m_isAdminSession
                                   ? QString()
                                   : "Retrouver vos taches, missions et recommandations du jour.");
    }
    if (btnPointage && btnPointage->property("defaultText").isValid()) {
        const QString defaultText = btnPointage->property("defaultText").toString();
        btnPointage->setText(m_isAdminSession ? defaultText : "Demande de conge IA");
        btnPointage->setToolTip(m_isAdminSession
                                    ? QString()
                                    : "Envoyer une demande de conge avec controle automatique du justificatif.");
    }

    QPushButton *btnEmployeeTasks = findChild<QPushButton*>("btnMesTachesIA");
    if (btnEmployeeTasks) {
        btnEmployeeTasks->setVisible(!m_isAdminSession);
        btnEmployeeTasks->setEnabled(!m_isAdminSession);
        btnEmployeeTasks->setToolTip("Ouvrir le suivi IA de vos taches et priorites.");
    }

    QPushButton *btnEmployeeLeave = findChild<QPushButton*>("btnDemandeCongeIA");
    if (btnEmployeeLeave) {
        btnEmployeeLeave->setVisible(!m_isAdminSession);
        btnEmployeeLeave->setEnabled(!m_isAdminSession);
        btnEmployeeLeave->setToolTip("Creer une demande de conge avec verification IA des dates et du justificatif.");
    }

    if (!m_isAdminSession && ui && ui->btnAccueil) {
        ui->btnAccueil->setChecked(true);
    }

    if (ui->sidebar) {
        updateSidebarState();
    }
}

void MainWindow::installPageAccessGuard()
{
    QStackedWidget *sw = mainStacked();
    if (!sw) return;
    if (sw->property("accessGuardInstalled").toBool()) return;

    connect(sw, &QStackedWidget::currentChanged, this, [this, sw](int idx) {
        if (m_isAdminSession) return;
        if (idx < 0) return;
        if (sw->property("accessGuardRedirecting").toBool()) return;

        QWidget *page = sw->widget(idx);
        if (!page) return;

        const QString moduleKey = moduleKeyForPageObjectName(page->objectName());
        if (moduleKey.isEmpty()) return;
        if (isModuleAccessAllowed(moduleKey)) return;

        sw->setProperty("accessGuardRedirecting", true);
        showDashboardHome();
        sw->setProperty("accessGuardRedirecting", false);

        guardModuleAccess(moduleKey, moduleDisplayName(moduleKey));
    });

    sw->setProperty("accessGuardInstalled", true);
}

bool MainWindow::eventFilter(QObject *obj, QEvent *event)
{
    if (event && event->type() == QEvent::MouseButtonRelease) {
        if (auto *frame = qobject_cast<QFrame*>(obj)) {
            const QString name = frame->objectName();
            if (name == "themeCardDefault" || name == "themeCardDark" || name == "themeCardCustom") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    bool ok = false;
                    int id = frame->property("themeModeId").toInt(&ok);
                    if (ok) {
                        ThemeManager::instance()->setMode(static_cast<ThemeManager::Mode>(id));
                        applyThemeFromManager();
                        rebuildSettingsCustomColorsList();
                    }
                    return true;
                }
            }
        }
        if (auto *lbl = qobject_cast<QLabel*>(obj)) {
            const QString objName = lbl->objectName();
            if (objName == "prod_l5" || objName == "prod_l5_m") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    openStockMap3D();
                    return true;
                }
            }
            if (objName == "prod_lblImgPreview_Add") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    on_prod_btnUpload_Add_clicked();
                    return true;
                }
            }
            if (objName == "prod_imgBin") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    on_prod_btnUpload_Mod_clicked();
                    return true;
                }
            }
            if (objName == "lblImgPreview_Add") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    pickMaintenanceImages(this, lbl, m_photoAvantPath, false);
                    return true;
                }
            }
            if (objName == "lblImgPreview2_Add") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    pickMaintenanceImages(this, lbl, m_photoApresPath, false);
                    return true;
                }
            }
            if (objName == "lblImgPreview_Mod") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    QString pickedBefore;
                    pickMaintenanceImages(this, lbl, pickedBefore, false);
                    if (!pickedBefore.trimmed().isEmpty()) {
                        const QStringList current = splitMaintenancePhotoPair(m_photoModPath);
                        m_photoModPath = formatMaintenancePhotoPair(pickedBefore, current.value(1));
                    }
                    return true;
                }
            }
            if (objName == "lblImgPreview2_Mod") {
                auto *me = static_cast<QMouseEvent*>(event);
                if (me->button() == Qt::LeftButton) {
                    QString pickedAfter;
                    pickMaintenanceImages(this, lbl, pickedAfter, false);
                    if (!pickedAfter.trimmed().isEmpty()) {
                        const QStringList current = splitMaintenancePhotoPair(m_photoModPath);
                        m_photoModPath = formatMaintenancePhotoPair(current.value(0), pickedAfter);
                    }
                    return true;
                }
            }
        }
    }
    return QMainWindow::eventFilter(obj, event);
}

void MainWindow::setSessionContext(bool isAdmin, const QString &email)
{
    Q_UNUSED(isAdmin);
    m_sessionEmail = email.trimmed();
    m_isAdminSession = (m_sessionEmail.compare("admin@wasteguard.com", Qt::CaseInsensitive) == 0);
    m_sessionSpecialite.clear();
    m_employeeAllowedModule.clear();

    if (!m_isAdminSession) {
        QString dbError;
        if (ensureMainWindowDbSessionAlive(dbError)) {
            QSqlQuery q;
            q.prepare("SELECT specialite FROM EMPLOYE WHERE LOWER(TRIM(email)) = LOWER(TRIM(:email))");
            q.bindValue(":email", m_sessionEmail);
            if (q.exec() && q.next()) {
                m_sessionSpecialite = q.value(0).toString().trimmed();
            } else if (!q.lastError().text().trimmed().isEmpty()) {
                qWarning() << "Unable to resolve employee speciality:" << q.lastError().text();
            }
        } else {
            qWarning() << "Unable to load session context from DB:" << dbError;
        }

        m_employeeAllowedModule = moduleKeyForSpecialite(m_sessionSpecialite);
        if (m_employeeAllowedModule.isEmpty()) {
            qWarning() << "Employee access module unresolved for email" << m_sessionEmail
                       << "specialite=" << m_sessionSpecialite;
        }
    }

    QPushButton *btnEmployeeTasks = findChild<QPushButton*>("btnMesTachesIA");
    QPushButton *btnEmployeeLeave = findChild<QPushButton*>("btnDemandeCongeIA");
    if (!m_isAdminSession) {
        if (!btnEmployeeTasks && ui && ui->sidebar) {
            btnEmployeeTasks = new QPushButton("Mes taches IA", ui->sidebar);
            btnEmployeeTasks->setObjectName("btnMesTachesIA");
            btnEmployeeTasks->setCheckable(true);
            btnEmployeeTasks->setCursor(Qt::PointingHandCursor);
            btnEmployeeTasks->setToolTip("Ouvrir vos taches prioritaires et les suggestions IA.");

            if (auto *layout = qobject_cast<QVBoxLayout*>(ui->sidebar->layout())) {
                int insertIndex = layout->count();
                for (int i = 0; i < layout->count(); ++i) {
                    QLayoutItem *item = layout->itemAt(i);
                    if (item && item->spacerItem()) {
                        insertIndex = i;
                        break;
                    }
                }
                layout->insertWidget(insertIndex, btnEmployeeTasks);
            }
            if (sidebarGroup) {
                sidebarGroup->addButton(btnEmployeeTasks);
            }
        }

        if (!btnEmployeeLeave && ui && ui->sidebar) {
            btnEmployeeLeave = new QPushButton("Demande de conge IA", ui->sidebar);
            btnEmployeeLeave->setObjectName("btnDemandeCongeIA");
            btnEmployeeLeave->setCheckable(true);
            btnEmployeeLeave->setCursor(Qt::PointingHandCursor);
            btnEmployeeLeave->setToolTip("Creer une demande de conge avec verification IA du document.");

            if (auto *layout = qobject_cast<QVBoxLayout*>(ui->sidebar->layout())) {
                int insertIndex = layout->count();
                for (int i = 0; i < layout->count(); ++i) {
                    QLayoutItem *item = layout->itemAt(i);
                    if (item && item->spacerItem()) {
                        insertIndex = i;
                        break;
                    }
                }
                const int taskBtnIndex = layout->indexOf(btnEmployeeTasks);
                if (taskBtnIndex >= 0) {
                    insertIndex = taskBtnIndex + 1;
                }
                layout->insertWidget(insertIndex, btnEmployeeLeave);
            }
            if (sidebarGroup) {
                sidebarGroup->addButton(btnEmployeeLeave);
            }
        }

        if (btnEmployeeTasks) {
            btnEmployeeTasks->show();
            btnEmployeeTasks->setToolTip("Ouvrir vos taches prioritaires et les suggestions IA.");
            connect(btnEmployeeTasks, &QPushButton::clicked,
                    this, &MainWindow::openEmployeeTasksDialog,
                    Qt::UniqueConnection);
        }
        if (btnEmployeeLeave) {
            btnEmployeeLeave->show();
            btnEmployeeLeave->setToolTip("Creer une demande de conge avec verification IA du document.");
            connect(btnEmployeeLeave, &QPushButton::clicked,
                    this, &MainWindow::openEmployeeLeaveDialog,
                    Qt::UniqueConnection);
        }
    } else {
        if (btnEmployeeTasks) {
            btnEmployeeTasks->hide();
        }
        if (btnEmployeeLeave) {
            btnEmployeeLeave->hide();
        }
    }

    if (QPushButton *btnMission = findChild<QPushButton*>("btnGoMission")) {
        btnMission->disconnect(this);
        if (!m_isAdminSession) {
            connect(btnMission, &QPushButton::clicked,
                    this, &MainWindow::openEmployeeTasksDialog,
                    Qt::UniqueConnection);
        } else {
            connect(btnMission, &QPushButton::clicked, this, [this]() {
                if (!guardModuleAccess("employes", "Mission IA")) return;
                if (auto *sw = mainStacked()) {
                    if (auto *page = sw->findChild<QWidget*>("mission", Qt::FindDirectChildrenOnly)) {
                        sw->setCurrentWidget(page);
                    }
                }
            });
        }
    }

    if (ui && ui->btnAnnulerPointage) {
        ui->btnAnnulerPointage->disconnect(this);
        if (m_isAdminSession) {
            connect(ui->btnAnnulerPointage, &QPushButton::clicked, this, &MainWindow::showEmployesPage, Qt::UniqueConnection);
        } else {
            connect(ui->btnAnnulerPointage, &QPushButton::clicked, this, &MainWindow::showDashboardHome, Qt::UniqueConnection);
        }
    }

    QString adminNotifJoined;
    if (m_isAdminSession) {
        QString dbError;
        if (!ensureMainWindowDbSessionAlive(dbError)) {
            qWarning() << "Admin notifications skipped (db offline):" << dbError;
        } else {
            QStringList messages;
            QString notifError;
            if (!loadAndMarkAdminNotifications("admin@wasteguard.com", messages, notifError)) {
                qWarning() << "Admin notifications load failed:" << notifError;
            } else if (!messages.isEmpty()) {
                adminNotifJoined = messages.join("\n\n--------------------\n\n");
            }
        }
    }

    QTimer::singleShot(0, this, [this, adminNotifJoined]() {
        installPageAccessGuard();
        applySessionAccessControl();
        forceApplySidebarStyles();
        applyHomogeneousTheme();
        ensureNavigationAndButtonConsistency();
        installWindowGeometryGuard();

        if (!m_isAdminSession) {
            showDashboardHome();
        }
        if (!m_isAdminSession) {
            if (QStackedWidget *sw = mainStacked()) {
                QWidget *current = sw->currentWidget();
                if (current) {
                    const QString moduleKey = moduleKeyForPageObjectName(current->objectName());
                    if (!moduleKey.isEmpty() && !isModuleAccessAllowed(moduleKey)) {
                        showDashboardHome();
                    }
                }
            }
        }

        if (m_isAdminSession && !adminNotifJoined.trimmed().isEmpty()) {
            QMessageBox::information(this, "Alertes absences employees", adminNotifJoined);
        }
    });

    if (!m_employeeTaskPromptShown && !m_isAdminSession) {
        m_employeeTaskPromptShown = true;
    }
}

void MainWindow::openEmployeeTasksDialog()
{
    if (m_isAdminSession) {
        QMessageBox::information(this, "Mes taches", "Cette vue est reservee aux comptes employes.");
        return;
    }

    if (m_sessionEmail.trimmed().isEmpty()) {
        QMessageBox::warning(this, "Mes taches", "Email de session introuvable.");
        return;
    }

    EmployeeTaskBoardDialog dialog(m_sessionEmail, this);
    dialog.exec();
}

void MainWindow::openEmployeeLeaveDialog()
{
    if (m_isAdminSession) {
        QMessageBox::information(this, "Demande de conge IA", "Cette vue est reservee aux comptes employes.");
        return;
    }

    if (m_sessionEmail.trimmed().isEmpty()) {
        QMessageBox::warning(this, "Demande de conge IA", "Email de session introuvable.");
        return;
    }

    EmployeeLeaveRequestDialog dialog(m_sessionEmail, this);
    dialog.exec();
}

void MainWindow::openLabibAssistant()
{
    const auto applyLabibDockGeometry = [this]() {
        if (!m_labibDock) return;

        const int windowW = qMax(900, this->width());
        const int minDockW = 400;
        const int maxDockW = qMax(minDockW, windowW - 180);
        const int preferredDockW = qBound(minDockW, static_cast<int>(windowW * 0.32), maxDockW);

        m_labibDock->setMinimumWidth(minDockW);
        m_labibDock->setMaximumWidth(maxDockW);
        if (m_labibAssistant) {
            m_labibAssistant->setMinimumWidth(380);
            m_labibAssistant->updateGeometry();
        }
        resizeDocks({m_labibDock}, {preferredDockW}, Qt::Horizontal);
    };

    if (!m_labibDock) {
        m_labibDock = new QDockWidget("Labib AI Assistant", this);
        m_labibDock->setObjectName("LabibAssistantDock");
        m_labibDock->setAllowedAreas(Qt::RightDockWidgetArea);
        m_labibDock->setFeatures(QDockWidget::DockWidgetClosable);

        if (!m_labibAssistant) {
            m_labibAssistant = new LabibAssistant(m_labibDock);
        }

        m_labibDock->setWidget(m_labibAssistant);
        addDockWidget(Qt::RightDockWidgetArea, m_labibDock);
        applyLabibDockGeometry();

        connect(m_labibAssistant, &LabibAssistant::requestAddClient, this, [this]() {
            if (ui && ui->btnClient) {
                ui->btnClient->click();
            }
            on_btnNouveau_client_clicked();
        });
        connect(m_labibAssistant, &LabibAssistant::requestViewStock, this, [this]() {
            if (ui && ui->btnStock) {
                ui->btnStock->click();
            }
        });
        connect(m_labibAssistant, &LabibAssistant::requestCheckOrders, this, [this]() {
            if (QPushButton *btnCmd = this->findChild<QPushButton*>("btnCommandes")) {
                btnCmd->click();
            }
        });

        connect(m_labibDock, &QDockWidget::visibilityChanged, this, [this](bool) {
            onFloatingAIButtonPositionUpdate();
        });
    }

    const bool shouldShow = m_labibDock->isHidden();
    m_labibDock->setVisible(shouldShow);
    m_labibDock->setFloating(false);
    if (shouldShow) {
        applyLabibDockGeometry();
        QTimer::singleShot(0, this, [this, applyLabibDockGeometry]() {
            if (m_labibDock && m_labibDock->isVisible()) {
                applyLabibDockGeometry();
            }
        });
        m_labibDock->raise();
        m_labibDock->activateWindow();
    }
}

void MainWindow::createFloatingAIButton()
{
    if (m_floatingAIButton) return; // Already created
    
    // Create floating button
    m_floatingAIButton = new QPushButton(this);
    m_floatingAIButton->setFixedSize(60, 60);
    m_floatingAIButton->setText("");
    m_floatingAIButton->setObjectName("floatingLabibButton");
    m_floatingAIButton->setStyleSheet(
        "QPushButton {"
        "    background: qradialgradient(cx:0.35, cy:0.3, radius:1.1, fx:0.35, fy:0.3, stop:0 #1a8cff, stop:1 #0c3469);"
        "    border: 2px solid #47b4ff;"
        "    border-radius: 30px;"
        "    padding: 0px;"
        "}"
        "QPushButton:hover {"
        "    background: qradialgradient(cx:0.35, cy:0.3, radius:1.1, fx:0.35, fy:0.3, stop:0 #41b0ff, stop:1 #11407a);"
        "    border: 2px solid #8ed5ff;"
        "}"
        "QPushButton:pressed {"
        "    background: #0b2b57;"
        "}"
    );
    m_floatingAIButton->setCursor(Qt::PointingHandCursor);
    m_floatingAIButton->setToolTip("Labib Assistant");

    const QPixmap logoPixmap(":/login_logo.png");
    if (!logoPixmap.isNull()) {
        m_floatingAIButton->setIcon(QIcon(logoPixmap));
        m_floatingAIButton->setIconSize(QSize(42, 42));
    } else {
        m_floatingAIButton->setText("L");
        m_floatingAIButton->setStyleSheet(
            m_floatingAIButton->styleSheet() +
            "QPushButton{color:white;font-weight:900;font-size:22px;}");
    }
    
    // Connect button to open Labib Assistant
    connect(m_floatingAIButton, &QPushButton::clicked, this, &MainWindow::openLabibAssistant);
    
    // Position the button
    onFloatingAIButtonPositionUpdate();
}

void MainWindow::onFloatingAIButtonPositionUpdate()
{
    if (!m_floatingAIButton) return;

    if (m_labibDock && m_labibDock->isVisible()) {
        m_floatingAIButton->hide();
        return;
    }

    const int margin = 18;
    const int x = qMax(margin, width() - m_floatingAIButton->width() - margin);
    const int y = qMax(margin, height() - m_floatingAIButton->height() - margin);

    m_floatingAIButton->move(x, y);
    m_floatingAIButton->show();
    m_floatingAIButton->raise();
}


void MainWindow::refreshEmployes()
{
    if (!ui->tableEmployes) return;
    ui->tableEmployes->setRowCount(0);

    QSqlQueryModel *model = Etmp.afficher();
    if (!model) {
        QMessageBox::critical(this, "Erreur SQL", "Impossible de charger les employes.");
        return;
    }

    if (model->lastError().isValid()) {
        showFriendlySqlError(this, "charger les employes", model->lastError().text());
        delete model;
        return;
    }
    if (model->rowCount() == 0 && !Etmp.lastError().trimmed().isEmpty()) {
        showFriendlySqlError(this, "charger les employes", Etmp.lastError());
        delete model;
        return;
    }

    for (int i = 0; i < model->rowCount(); ++i) {
        int id_emp = model->data(model->index(i, 0)).toInt();
        QString matricule = model->data(model->index(i, 1)).toString();
        QString cin = model->data(model->index(i, 2)).toString().trimmed();
        QString nom = model->data(model->index(i, 3)).toString();
        QString email = model->data(model->index(i, 4)).toString().trimmed();
        QString specialite = model->data(model->index(i, 5)).toString();
        QString dispoDb = model->data(model->index(i, 6)).toString().trimmed();
        QByteArray photoData;
        if (model->columnCount() > 7) {
            const QVariant photoVar = model->data(model->index(i, 7));
            if (photoVar.isValid() && !photoVar.isNull()) {
                photoData = photoVar.toByteArray();
            }
        }

        QString dispoUi = fromDbDisponibiliteLabel(dispoDb);

        int row = ui->tableEmployes->rowCount();
        ui->tableEmployes->insertRow(row);

        auto *matItem = new QTableWidgetItem(matricule);
        matItem->setData(EMP_ROLE_ID, id_emp);
        matItem->setData(EMP_ROLE_EMAIL, email);
        matItem->setData(EMP_ROLE_CIN, cin);
        matItem->setData(EMP_ROLE_SALAIRE, 1200);
        matItem->setData(EMP_ROLE_PERF, 0);
        matItem->setData(EMP_ROLE_PHOTO, photoData);

        ui->tableEmployes->setItem(row, EMP_COL_MATRICULE, matItem);
        auto *nameItem = new QTableWidgetItem(nom);
        const QIcon photoIcon = employeePhotoIcon(photoData, 28);
        if (!photoIcon.isNull()) {
            nameItem->setIcon(photoIcon);
        }
        ui->tableEmployes->setItem(row, EMP_COL_NOM, nameItem);
        ui->tableEmployes->setItem(row, EMP_COL_SPECIALITE, new QTableWidgetItem(specialite));
        ui->tableEmployes->setItem(row, EMP_COL_SALAIRE, new QTableWidgetItem(QString("%1 TND").arg(1200)));
        ui->tableEmployes->setItem(row, EMP_COL_EMAIL, new QTableWidgetItem(email));
        ui->tableEmployes->setItem(row, EMP_COL_CIN, new QTableWidgetItem(cin));
        ui->tableEmployes->setItem(row, EMP_COL_DISPONIBILITE, new QTableWidgetItem(dispoUi));

        installEmployeActionButtonsForRow(row); // garde ton syst?me de boutons
    }

    applyEmployeSortAndFilter();

    delete model;
}

void MainWindow::updateEmployeSidebarStats()
{
    if (!ui->tableEmployes) return;

    int totalRows = ui->tableEmployes->rowCount();
    int visibleRows = 0;
    int availableCount = 0;
    int busyCount = 0;
    int leaveCount = 0;
    int interventionCount = 0;

    for (int row = 0; row < totalRows; ++row) {
        if (ui->tableEmployes->isRowHidden(row)) continue;

        ++visibleRows;

        const QString status = ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE)
            ? ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE)->text()
            : QString();
        const QString normalized = normalizedStatus(status);

        if (normalized.contains("disponible") && !normalized.contains("non")) {
            ++availableCount;
            continue;
        }

        if (normalized.contains("intervention")) {
            ++interventionCount;
        }
        if (normalized.contains("conge")) {
            ++leaveCount;
        }

        ++busyCount;
    }

    const bool filteredView = visibleRows != totalRows;
    const int workloadPercent = visibleRows > 0
        ? qRound((busyCount * 100.0) / visibleRows)
        : 0;

    if (ui->label_Stat1_Title) {
        ui->label_Stat1_Title->setText(filteredView ? "Employes affiches" : "Total Employes");
    }
    if (ui->lblStatNumber) {
        ui->lblStatNumber->setText(filteredView
            ? QString("%1 / %2").arg(visibleRows).arg(totalRows)
            : QString::number(totalRows));
    }

    if (ui->label_Stat2_Title) {
        ui->label_Stat2_Title->setText("Charge de Travail de l'equipe");
    }
    if (ui->lblStatWorkload) {
        QString workloadText = QString("%1%").arg(workloadPercent);
        if (visibleRows > 0) {
            workloadText += QString(" (%1 actifs)").arg(busyCount);
        }
        ui->lblStatWorkload->setText(workloadText);
    }

    if (ui->label_Stat3_Title) {
        ui->label_Stat3_Title->setText("Disponibilite");
    }
    if (ui->lblStatAvailability) {
        QString availabilityText;
        if (visibleRows == 0) {
            availabilityText = "Aucun resultat";
        } else {
            availabilityText = QString("%1 dispo").arg(availableCount);
            if (interventionCount > 0) {
                availabilityText += QString(" | %1 intervention").arg(interventionCount);
            } else if (leaveCount > 0) {
                availabilityText += QString(" | %1 conge").arg(leaveCount);
            }
        }
        ui->lblStatAvailability->setText(availabilityText);
    }
}

void MainWindow::applyEmployeSortAndFilter()
{
    if (!ui->tableEmployes) return;

    struct EmpRowData {
        int idEmp = 0;
        QString matricule;
        QString nom;
        QString specialite;
        QString disponibilite;
        QString email;
        QString cin;
        int salaire = 1200;
        int perf = 0;
        QByteArray photo;
    };

    int selectedId = -1;
    const int selectedRow = ui->tableEmployes->currentRow();
    if (selectedRow >= 0 && selectedRow < ui->tableEmployes->rowCount()) {
        if (auto *selectedItem = ui->tableEmployes->item(selectedRow, EMP_COL_MATRICULE)) {
            selectedId = selectedItem->data(EMP_ROLE_ID).toInt();
        }
    }

    QVector<EmpRowData> rows;
    rows.reserve(ui->tableEmployes->rowCount());
    for (int row = 0; row < ui->tableEmployes->rowCount(); ++row) {
        auto *matItem = ui->tableEmployes->item(row, EMP_COL_MATRICULE);
        if (!matItem) continue;

        EmpRowData rowData;
        rowData.idEmp = matItem->data(EMP_ROLE_ID).toInt();
        rowData.matricule = matItem->text();
        rowData.email = matItem->data(EMP_ROLE_EMAIL).toString();
        rowData.cin = matItem->data(EMP_ROLE_CIN).toString();
        rowData.salaire = matItem->data(EMP_ROLE_SALAIRE).toInt();
        rowData.perf = matItem->data(EMP_ROLE_PERF).toInt();
        rowData.photo = matItem->data(EMP_ROLE_PHOTO).toByteArray();
        rowData.nom = ui->tableEmployes->item(row, EMP_COL_NOM) ? ui->tableEmployes->item(row, EMP_COL_NOM)->text() : QString();
        rowData.specialite = ui->tableEmployes->item(row, EMP_COL_SPECIALITE) ? ui->tableEmployes->item(row, EMP_COL_SPECIALITE)->text() : QString();
        rowData.disponibilite = ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE) ? ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE)->text() : QString();
        rows.append(rowData);
    }

    const int sortIndex = ui->cbSort ? ui->cbSort->currentIndex() : 0;
    std::stable_sort(rows.begin(), rows.end(), [sortIndex](const EmpRowData &a, const EmpRowData &b) {
        switch (sortIndex) {
        case 1:
            if (a.perf != b.perf) return a.perf > b.perf;
            break;
        case 2:
            if (a.salaire != b.salaire) return a.salaire > b.salaire;
            break;
        case 3: {
            const int cmp = QString::compare(a.nom, b.nom, Qt::CaseInsensitive);
            if (cmp != 0) return cmp < 0;
            break;
        }
        case 0:
        default: {
            const int cmp = QString::compare(a.specialite, b.specialite, Qt::CaseInsensitive);
            if (cmp != 0) return cmp < 0;
            break;
        }
        }
        return QString::compare(a.matricule, b.matricule, Qt::CaseInsensitive) < 0;
    });

    ui->tableEmployes->setRowCount(0);
    for (const EmpRowData &rowData : rows) {
        const int row = ui->tableEmployes->rowCount();
        ui->tableEmployes->insertRow(row);

        auto *matItem = new QTableWidgetItem(rowData.matricule);
        matItem->setData(EMP_ROLE_ID, rowData.idEmp);
        matItem->setData(EMP_ROLE_EMAIL, rowData.email);
        matItem->setData(EMP_ROLE_CIN, rowData.cin);
        matItem->setData(EMP_ROLE_SALAIRE, rowData.salaire);
        matItem->setData(EMP_ROLE_PERF, rowData.perf);
        matItem->setData(EMP_ROLE_PHOTO, rowData.photo);

        ui->tableEmployes->setItem(row, EMP_COL_MATRICULE, matItem);
        auto *nameItem = new QTableWidgetItem(rowData.nom);
        const QIcon photoIcon = employeePhotoIcon(rowData.photo, 28);
        if (!photoIcon.isNull()) {
            nameItem->setIcon(photoIcon);
        }
        ui->tableEmployes->setItem(row, EMP_COL_NOM, nameItem);
        ui->tableEmployes->setItem(row, EMP_COL_SPECIALITE, new QTableWidgetItem(rowData.specialite));
        ui->tableEmployes->setItem(row, EMP_COL_SALAIRE, new QTableWidgetItem(QString("%1 TND").arg(rowData.salaire)));
        ui->tableEmployes->setItem(row, EMP_COL_EMAIL, new QTableWidgetItem(rowData.email));
        ui->tableEmployes->setItem(row, EMP_COL_CIN, new QTableWidgetItem(rowData.cin));
        ui->tableEmployes->setItem(row, EMP_COL_DISPONIBILITE, new QTableWidgetItem(rowData.disponibilite));
        installEmployeActionButtonsForRow(row);
    }

    const QString keyword = ui->txtSearch ? ui->txtSearch->text().trimmed() : QString();
    for (int row = 0; row < ui->tableEmployes->rowCount(); ++row) {
        const QString matricule = ui->tableEmployes->item(row, EMP_COL_MATRICULE) ? ui->tableEmployes->item(row, EMP_COL_MATRICULE)->text() : QString();
        const QString nom = ui->tableEmployes->item(row, EMP_COL_NOM) ? ui->tableEmployes->item(row, EMP_COL_NOM)->text() : QString();
        const QString specialite = ui->tableEmployes->item(row, EMP_COL_SPECIALITE) ? ui->tableEmployes->item(row, EMP_COL_SPECIALITE)->text() : QString();
        const QString salaire = ui->tableEmployes->item(row, EMP_COL_SALAIRE) ? ui->tableEmployes->item(row, EMP_COL_SALAIRE)->text() : QString();
        const QString email = ui->tableEmployes->item(row, EMP_COL_EMAIL) ? ui->tableEmployes->item(row, EMP_COL_EMAIL)->text() : QString();
        const QString cin = ui->tableEmployes->item(row, EMP_COL_CIN) ? ui->tableEmployes->item(row, EMP_COL_CIN)->text() : QString();
        const QString disponibilite = ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE) ? ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE)->text() : QString();

        const bool match =
            keyword.isEmpty() ||
            matricule.contains(keyword, Qt::CaseInsensitive) ||
            nom.contains(keyword, Qt::CaseInsensitive) ||
            specialite.contains(keyword, Qt::CaseInsensitive) ||
            salaire.contains(keyword, Qt::CaseInsensitive) ||
            email.contains(keyword, Qt::CaseInsensitive) ||
            cin.contains(keyword, Qt::CaseInsensitive) ||
            disponibilite.contains(keyword, Qt::CaseInsensitive);

        ui->tableEmployes->setRowHidden(row, !match);
    }

    currentEmployeRow = -1;
    if (!m_isEmpCardView) {
        ui->tableEmployes->clearSelection();
    }

    if (selectedId > 0) {
        for (int row = 0; row < ui->tableEmployes->rowCount(); ++row) {
            if (auto *matItem = ui->tableEmployes->item(row, 0)) {
                if (matItem->data(EMP_ROLE_ID).toInt() == selectedId && !ui->tableEmployes->isRowHidden(row)) {
                    if (!m_isEmpCardView) {
                        ui->tableEmployes->selectRow(row);
                    }
                    currentEmployeRow = row;
                    break;
                }
            }
        }
    }

    if (!m_isEmpCardView && currentEmployeRow < 0) {
        for (int row = 0; row < ui->tableEmployes->rowCount(); ++row) {
            if (!ui->tableEmployes->isRowHidden(row)) {
                ui->tableEmployes->selectRow(row);
                currentEmployeRow = row;
                break;
            }
        }
    }

    updateEmployeSidebarStats();

    if (m_isEmpCardView) {
        m_empCurrentPage = 0;
        refreshEmpCardView();
    }
}
