void MainWindow::installEmployeActionButtonsForRow(int row)

{

    if (!ui->tableEmployes) return;

    if (row < 0 || row >= ui->tableEmployes->rowCount()) return;



    if (QWidget *existing = ui->tableEmployes->cellWidget(row, EMP_COL_ACTIONS)) {

        const auto buttons = existing->findChildren<QPushButton*>();

        for (auto *b : buttons)

            b->setProperty("row", row);

        return;

    }



    QWidget *pWidget = new QWidget(ui->tableEmployes);

    QPushButton *btnEdit = new QPushButton("Modifier", pWidget);
    styleTableActionButton(btnEdit);

    btnEdit->setProperty("row", row);



    QPushButton *btnDelete = new QPushButton("Supprimer", pWidget);
    styleTableActionButton(btnDelete);

    btnDelete->setProperty("row", row);



    connect(btnEdit, &QPushButton::clicked, this, &MainWindow::on_btnModifier_clicked);

    connect(btnDelete, &QPushButton::clicked, this, &MainWindow::on_btnSupprimer_clicked);



    QHBoxLayout *pLayout = new QHBoxLayout(pWidget);

    pLayout->addWidget(btnEdit);

    pLayout->addWidget(btnDelete);

    pLayout->setSpacing(8);

    pLayout->setAlignment(Qt::AlignCenter);

    pLayout->setContentsMargins(4, 10, 4, 10);

    pWidget->setLayout(pLayout);

    ui->tableEmployes->setRowHeight(row, qMax(ui->tableEmployes->rowHeight(row), 62));



    ui->tableEmployes->setCellWidget(row, EMP_COL_ACTIONS, pWidget);

}



void MainWindow::refreshEmployeActionButtons()

{

    if (!ui->tableEmployes) return;

    for (int row = 0; row < ui->tableEmployes->rowCount(); ++row)

        installEmployeActionButtonsForRow(row);

}



void MainWindow::on_btnAjouter_clicked()

{

    if (!ui->tableEmployes) {
        QMessageBox::warning(this, "Ajout", "Table des employes introuvable.");
        return;
    }



    const QString nom = ui->txtNom_Ajout ? ui->txtNom_Ajout->text().trimmed() : QString();

    if (nom.isEmpty()) {

        QMessageBox::warning(this, "Ajout", "Le nom est obligatoire.");

        return;

    }

    if (!isValidEmployeeName(nom)) {
        QMessageBox::warning(this, "Ajout", "Le nom doit contenir uniquement des lettres et des espaces.");
        return;
    }



    int maxId = 0;

    for (int r = 0; r < ui->tableEmployes->rowCount(); ++r) {

        if (auto *item = ui->tableEmployes->item(r, 0)) {

            const QString matricule = item->text().trimmed();

            const int dashPos = matricule.lastIndexOf('-');

            const QString numericPart = (dashPos >= 0) ? matricule.mid(dashPos + 1) : matricule;

            bool ok = false;

            const int id = numericPart.toInt(&ok);

            if (ok) maxId = qMax(maxId, id);

        }

    }

    const QString matricule = QString("EMP-%1").arg(maxId + 1, 3, 10, QChar('0'));



    const QString specialite = ui->cbSpecialite_Ajout ? ui->cbSpecialite_Ajout->currentText().trimmed() : QString();

    const QString statut = ui->cbStatut_Ajout ? ui->cbStatut_Ajout->currentText().trimmed() : QString();
    const int salaireAjout = ui->sliderSalaire_Ajout ? ui->sliderSalaire_Ajout->value() : 1200;

    const QString email = ui->txtEmailAjout ? ui->txtEmailAjout->text().trimmed() : QString();

    if (email.isEmpty()) {
        QMessageBox::warning(this, "Ajout", "L'email est obligatoire.");
        return;
    }

    if (!isValidEmail(email)) {
        QMessageBox::warning(this, "Ajout", "Format d'email invalide. Exemple: nom@domaine.com");
        return;
    }

    QString emailApiError;
    if (!verifyEmailWithApiIfConfigured(email, emailApiError)) {
        QMessageBox::warning(this, "Validation email", emailApiError);
        return;
    }

    const QString cin = ui->txtCIN_Ajout ? ui->txtCIN_Ajout->text().trimmed() : QString();
    if (!isValidCinInput(cin)) {
        QMessageBox::warning(this, "Ajout", "Le CIN doit contenir exactement 8 chiffres.");
        return;
    }
    if (specialite.isEmpty() || foldTextKey(specialite).contains("selection")) {
        QMessageBox::warning(this, "Ajout", "Veuillez choisir une specialite.");
        return;
    }
    if (statut.isEmpty() || foldTextKey(statut).contains("selection")) {
        QMessageBox::warning(this, "Ajout", "Veuillez choisir un statut.");
        return;
    }
    if (m_employeePhotoAjout.isEmpty()) {
        QMessageBox::warning(this, "Ajout", "La photo est obligatoire pour creer le compte.");
        return;
    }

    const QString disponibiliteDb = toDbDisponibilite(statut);
    QString dispoSchemaError;
    if (!ensureEmployeDisponibiliteStatusesReady(dispoSchemaError)) {
        showFriendlySqlError(this, "preparer les statuts employe", dispoSchemaError);
        return;
    }

    Etmp.setIdEmp(0);
    Etmp.setMatricule(matricule);
    Etmp.setCin(cin);
    Etmp.setNom(nom);
    Etmp.setEmail(email);
    Etmp.setSpecialite(specialite);
    Etmp.setDisponibilite(disponibiliteDb);
    Etmp.setPhoto(m_employeePhotoAjout);
    if (!Etmp.ajouter()) {
        showFriendlySqlError(this, "ajouter l'employe", Etmp.lastError());
        return;
    }

    if (!m_employeeFaceTemplateAjout.trimmed().isEmpty()) {
        QSqlQuery faceQuery;
        faceQuery.prepare(
            "UPDATE EMPLOYE "
            "SET face_template=:tpl, face_template_updated_at=SYSDATE, face_enabled=1 "
            "WHERE LOWER(TRIM(email)) = LOWER(TRIM(:email))");
        faceQuery.bindValue(":tpl", m_employeeFaceTemplateAjout);
        faceQuery.bindValue(":email", email);
        if (!faceQuery.exec()) {
            qWarning() << "Face template save failed:" << faceQuery.lastError().text();
        }
    }

    refreshEmployes();

    int insertedRow = -1;
    for (int r = 0; r < ui->tableEmployes->rowCount(); ++r) {
        if (auto *item = ui->tableEmployes->item(r, EMP_COL_MATRICULE)) {
            if (item->text().trimmed() == matricule) {
                insertedRow = r;
                break;
            }
        }
    }

    if (insertedRow >= 0) {
        currentEmployeRow = insertedRow;
        ui->tableEmployes->selectRow(insertedRow);
        if (auto *matItem = ui->tableEmployes->item(insertedRow, EMP_COL_MATRICULE)) {
            matItem->setData(EMP_ROLE_SALAIRE, salaireAjout);
            matItem->setData(EMP_ROLE_PHOTO, m_employeePhotoAjout);
        }
        if (auto *nameItem = ui->tableEmployes->item(insertedRow, EMP_COL_NOM)) {
            const QIcon photoIcon = employeePhotoIcon(m_employeePhotoAjout, 28);
            nameItem->setIcon(photoIcon);
        }
        if (auto *salaryItem = ui->tableEmployes->item(insertedRow, EMP_COL_SALAIRE)) {
            salaryItem->setText(QString("%1 TND").arg(salaireAjout));
        }
    }



    if (ui->txtNom_Ajout) ui->txtNom_Ajout->clear();

    if (ui->txtEmailAjout) ui->txtEmailAjout->clear();

    if (ui->txtCIN_Ajout) ui->txtCIN_Ajout->clear();

    if (ui->cbSpecialite_Ajout && ui->cbSpecialite_Ajout->count() > 0) ui->cbSpecialite_Ajout->setCurrentIndex(0);

    if (ui->cbStatut_Ajout && ui->cbStatut_Ajout->count() > 0) ui->cbStatut_Ajout->setCurrentIndex(0);

    if (ui->sliderSalaire_Ajout) {

        const int resetSalaire = qMax(ui->sliderSalaire_Ajout->minimum(), qMin(ui->sliderSalaire_Ajout->maximum(), 1200));

        ui->sliderSalaire_Ajout->setValue(resetSalaire);

    }

    m_employeePhotoAjout.clear();
    m_employeeFaceTemplateAjout.clear();
    setEmployeePhotoPreview(ui->imageLabel_2, m_employeePhotoAjout);

    if (m_isEmpCardView)
        refreshEmpCardView();



    showEmployesPage();
    QMessageBox::information(this, "Succes", "Employe ajoute avec succes.");

}



void MainWindow::on_btnModifier_clicked()

{

    int row = -1;

    if (auto *btn = qobject_cast<QPushButton*>(sender())) {

        const QVariant rowProp = btn->property("row");

        if (rowProp.isValid())

            row = rowProp.toInt();

    }



    if (row < 0 && ui->tableEmployes)

        row = ui->tableEmployes->currentRow();



    if (row < 0 && ui->tableEmployes) {

        if (auto *btn = qobject_cast<QPushButton*>(sender())) {

            for (int r = 0; r < ui->tableEmployes->rowCount(); ++r) {

                QWidget *cell = ui->tableEmployes->cellWidget(r, EMP_COL_ACTIONS);

                if (cell && (cell == btn->parentWidget() || cell->isAncestorOf(btn))) {

                    row = r;

                    break;

                }

            }

        }

    }



    auto cellText = [this, row](int col) -> QString {

        if (!ui->tableEmployes) return QString();

        if (row < 0 || row >= ui->tableEmployes->rowCount()) return QString();

        if (auto *item = ui->tableEmployes->item(row, col))

            return item->text().trimmed();

        return QString();

    };



    auto normalizeText = [](QString value) -> QString {

        value = value.normalized(QString::NormalizationForm_D).toLower().trimmed();

        QString normalized;

        normalized.reserve(value.size());

        for (QChar ch : value) {

            const QChar::Category category = ch.category();

            if (category == QChar::Mark_NonSpacing ||

                category == QChar::Mark_SpacingCombining ||

                category == QChar::Mark_Enclosing) {

                continue;

            }

            if (ch.isLetterOrNumber())

                normalized.append(ch);

        }

        return normalized;

    };



    auto setComboValue = [&](QComboBox *combo, const QString &value) {

        if (!combo || value.trimmed().isEmpty()) return;



        int idx = combo->findText(value, Qt::MatchFixedString);

        if (idx < 0)

            idx = combo->findText(value, Qt::MatchCaseSensitive | Qt::MatchContains);

        if (idx < 0)

            idx = combo->findText(value, Qt::MatchContains);



        if (idx < 0) {

            const QString wanted = normalizeText(value);

            for (int i = 0; i < combo->count(); ++i) {

                if (normalizeText(combo->itemText(i)) == wanted) {

                    idx = i;

                    break;

                }

            }

        }



        if (idx < 0) {

            const QString wanted = normalizeText(value);

            for (int i = 0; i < combo->count(); ++i) {

                const QString current = normalizeText(combo->itemText(i));

                if (current.contains(wanted) || wanted.contains(current)) {

                    idx = i;

                    break;

                }

            }

        }



        if (idx >= 0)

            combo->setCurrentIndex(idx);

    };



    if (row >= 0 && ui->tableEmployes) {

        currentEmployeRow = row;

        ui->tableEmployes->selectRow(row);



        const QString matricule = cellText(EMP_COL_MATRICULE);

        const QString nom = cellText(EMP_COL_NOM);

        const QString specialite = cellText(EMP_COL_SPECIALITE);

        const QString statut = cellText(EMP_COL_DISPONIBILITE);



        if (ui->txtMatricule) ui->txtMatricule->setText(matricule);

        if (ui->txtNom) ui->txtNom->setText(nom);

        setComboValue(ui->cbSpecialite, specialite);

        if (ui->cbStatut) {
            const QString statusNorm = normalizedStatus(fromDbDisponibiliteLabel(statut));
            int idx = -1;
            if (statusNorm.contains("conge") && statusNorm.contains("malad")) {
                idx = ui->cbStatut->findText("En conge maladie", Qt::MatchContains);
            } else if (statusNorm.contains("conge")) {
                idx = ui->cbStatut->findText("En conge normale", Qt::MatchContains);
            } else if (statusNorm.contains("intervention")) {
                idx = ui->cbStatut->findText("En intervention", Qt::MatchContains);
            } else if (statusNorm.contains("indispon")
                       || statusNorm.contains("non disponible")
                       || statusNorm.contains("mission")) {
                idx = ui->cbStatut->findText("Non disponible", Qt::MatchContains);
                if (idx < 0) idx = ui->cbStatut->findText("En intervention", Qt::MatchContains);
            } else {
                idx = ui->cbStatut->findText("Disponible", Qt::MatchContains);
            }
            if (idx < 0 && ui->cbStatut->count() > 0) idx = 0;
            if (idx >= 0) ui->cbStatut->setCurrentIndex(idx);
        }



        m_employeePhotoModif.clear();
        setEmployeePhotoPreview(ui->imageLabel, m_employeePhotoModif);

        if (auto *matItem = ui->tableEmployes->item(row, EMP_COL_MATRICULE)) {

            const QString email = matItem->data(EMP_ROLE_EMAIL).toString().trimmed();

            const QString cin = matItem->data(EMP_ROLE_CIN).toString().trimmed();
            m_employeePhotoModif = matItem->data(EMP_ROLE_PHOTO).toByteArray();
            setEmployeePhotoPreview(ui->imageLabel, m_employeePhotoModif);

            const QVariant salaireData = matItem->data(EMP_ROLE_SALAIRE);



            if (ui->txtEmailModif) ui->txtEmailModif->setText(email);

            if (ui->txtCIN_Modif) ui->txtCIN_Modif->setText(cin);



            if (ui->sliderSalaire_Modif) {

                int salaire = 1200;

                if (salaireData.isValid()) {

                    salaire = salaireData.toInt();

                }

                salaire = qMax(ui->sliderSalaire_Modif->minimum(),

                               qMin(ui->sliderSalaire_Modif->maximum(), salaire));

                ui->sliderSalaire_Modif->setValue(salaire);

            }

        }

    } else {

        currentEmployeRow = -1;
        m_employeePhotoModif.clear();
        setEmployeePhotoPreview(ui->imageLabel, m_employeePhotoModif);

    }



    if (auto *sw = mainStacked()) {

        if (auto *page = sw->findChild<QWidget*>("modification", Qt::FindDirectChildrenOnly)) {

            sw->setCurrentWidget(page);

        } else {

            sw->setCurrentIndex(1);

        }

    }



    // --- STYLE SIDEBAR & CLEAN LABELS (Employee Modification) ---

    QTimer::singleShot(100, this, [this]() {

        if (QWidget *side = this->findChild<QWidget*>("sideMod")) {

            side->setStyleSheet("QWidget#sideMod { background-color: #ffffff; border-radius: 20px; border: 1px solid #e2e8f0; }");

            QList<QLabel*> labels = side->findChildren<QLabel*>();

            auto isInEmployeeGreenBlock = [](QLabel *label) {
                QWidget *w = label;
                while (w) {
                    const QString name = w->objectName();
                    if (name == "empHero" || name == "empQuickActionsLabelWrap") {
                        return true;
                    }
                    w = w->parentWidget();
                }
                return false;
            };

            for (QLabel *lbl : labels) {

                if (!lbl) continue;
                const QString existing = lbl->styleSheet();

                if (isInEmployeeGreenBlock(lbl)) {
                    lbl->setStyleSheet(existing + " background: transparent; color: #ffffff; border: none;");
                    continue;
                }

                if (existing.contains("color:", Qt::CaseInsensitive)) {
                    lbl->setStyleSheet(existing + " background: transparent; border: none;");
                    continue;
                }

                lbl->setStyleSheet(existing + " background: transparent; color: #0f2b4c; border: none;");

            }

        }

        // Remove gray background from all labels in the page

        if (auto *page = mainStacked() ? mainStacked()->currentWidget() : nullptr) {

            QList<QLabel*> allLabels = page->findChildren<QLabel*>();

            for (QLabel *lbl : allLabels) {

                lbl->setStyleSheet(lbl->styleSheet() + " background: transparent; border: none;");

            }

        }

        polishHomogeneousSurfaces();

    });

}



void MainWindow::on_btnSave_clicked()

{

    if (!ui->tableEmployes) {
        QMessageBox::warning(this, "Modification", "Table des employes introuvable.");
        return;
    }

    int row = currentEmployeRow;

    if (row < 0 || row >= ui->tableEmployes->rowCount()) {
        // Fallback: find row by matricule in case the tracked row was reset.
        const QString matriculeFromForm = ui->txtMatricule ? ui->txtMatricule->text().trimmed() : QString();
        if (!matriculeFromForm.isEmpty()) {
            for (int r = 0; r < ui->tableEmployes->rowCount(); ++r) {
                if (auto *item = ui->tableEmployes->item(r, 0)) {
                    if (item->text().trimmed() == matriculeFromForm) {
                        row = r;
                        break;
                    }
                }
            }
        }
    }

    if (row < 0 || row >= ui->tableEmployes->rowCount()) {
        QMessageBox::warning(this, "Modification", "Aucun employe selectionne pour la sauvegarde.");
        return;
    }

    const QString matricule = ui->txtMatricule ? ui->txtMatricule->text().trimmed() : QString();
    const QString nom = ui->txtNom ? ui->txtNom->text().trimmed() : QString();
    const QString specialite = ui->cbSpecialite ? ui->cbSpecialite->currentText().trimmed() : QString();
    const QString statut = ui->cbStatut ? ui->cbStatut->currentText().trimmed() : QString();
    const QString email = ui->txtEmailModif ? ui->txtEmailModif->text().trimmed() : QString();
    const QString cin = ui->txtCIN_Modif ? ui->txtCIN_Modif->text().trimmed() : QString();
    const int salaire = ui->sliderSalaire_Modif ? ui->sliderSalaire_Modif->value() : 1200;

    if (nom.isEmpty()) {
        QMessageBox::warning(this, "Modification", "Le nom est obligatoire.");
        return;
    }

    if (!isValidEmployeeName(nom)) {
        QMessageBox::warning(this, "Modification", "Le nom doit contenir uniquement des lettres et des espaces.");
        return;
    }

    if (email.isEmpty()) {
        QMessageBox::warning(this, "Modification", "L'email est obligatoire.");
        return;
    }

    if (!isValidEmail(email)) {
        QMessageBox::warning(this, "Modification", "Format d'email invalide. Exemple: nom@domaine.com");
        return;
    }

    QString emailApiError;
    if (!verifyEmailWithApiIfConfigured(email, emailApiError)) {
        QMessageBox::warning(this, "Validation email", emailApiError);
        return;
    }
    if (!isValidCinInput(cin)) {
        QMessageBox::warning(this, "Modification", "Le CIN doit contenir exactement 8 chiffres.");
        return;
    }
    if (specialite.isEmpty() || foldTextKey(specialite).contains("selection")) {
        QMessageBox::warning(this, "Modification", "Veuillez choisir une specialite.");
        return;
    }
    if (statut.isEmpty() || foldTextKey(statut).contains("selection")) {
        QMessageBox::warning(this, "Modification", "Veuillez choisir un statut.");
        return;
    }

    int idEmp = -1;
    int perf = 0;
    QByteArray existingPhoto;
    if (auto *matItem = ui->tableEmployes->item(row, EMP_COL_MATRICULE)) {
        idEmp = matItem->data(EMP_ROLE_ID).toInt();
        perf = matItem->data(EMP_ROLE_PERF).toInt();
        existingPhoto = matItem->data(EMP_ROLE_PHOTO).toByteArray();
    }

    if (idEmp <= 0 && !matricule.isEmpty()) {
        int foundId = -1;
        if (Etmp.findIdByMatricule(matricule, foundId)) {
            idEmp = foundId;
        }
    }

    if (idEmp <= 0) {
        QMessageBox::warning(this, "Modification", "ID employe introuvable, modification annulee.");
        return;
    }

    const QString disponibiliteDb = toDbDisponibilite(statut);
    QString dispoSchemaError;
    if (!ensureEmployeDisponibiliteStatusesReady(dispoSchemaError)) {
        showFriendlySqlError(this, "preparer les statuts employe", dispoSchemaError);
        return;
    }
    QByteArray photoToSave = m_employeePhotoModif;
    if (photoToSave.isEmpty() && !existingPhoto.isEmpty()) {
        photoToSave = existingPhoto;
    }

    Etmp.setIdEmp(idEmp);
    Etmp.setMatricule(matricule);
    Etmp.setCin(cin);
    Etmp.setNom(nom);
    Etmp.setEmail(email);
    Etmp.setSpecialite(specialite);
    Etmp.setDisponibilite(disponibiliteDb);
    Etmp.setPhoto(photoToSave);
    if (!Etmp.modifier()) {
        showFriendlySqlError(this, "modifier l'employe", Etmp.lastError());
        return;
    }

    refreshEmployes();

    int updatedRow = -1;
    for (int r = 0; r < ui->tableEmployes->rowCount(); ++r) {
        if (auto *item = ui->tableEmployes->item(r, EMP_COL_MATRICULE)) {
            if (item->data(EMP_ROLE_ID).toInt() == idEmp) {
                updatedRow = r;
                item->setData(EMP_ROLE_SALAIRE, salaire);
                item->setData(EMP_ROLE_PERF, perf);
                item->setData(EMP_ROLE_PHOTO, photoToSave);
                if (auto *nameItem = ui->tableEmployes->item(r, EMP_COL_NOM)) {
                    const QIcon photoIcon = employeePhotoIcon(photoToSave, 28);
                    nameItem->setIcon(photoIcon);
                }
                if (auto *salaryItem = ui->tableEmployes->item(r, EMP_COL_SALAIRE)) {
                    salaryItem->setText(QString("%1 TND").arg(salaire));
                }
                break;
            }
        }
    }

    if (updatedRow >= 0) {
        ui->tableEmployes->selectRow(updatedRow);
        currentEmployeRow = updatedRow;
    } else {
        currentEmployeRow = -1;
    }

    m_employeePhotoModif = photoToSave;
    setEmployeePhotoPreview(ui->imageLabel, m_employeePhotoModif);

    if (m_isEmpCardView)
        refreshEmpCardView();

    showEmployesPage();
    QMessageBox::information(this, "Succes", "Employe modifie avec succes.");

}



// --- SUPPRESSION ---

void MainWindow::on_btnSupprimer_clicked()

{

    if (!ui->tableEmployes) return;



    int row = -1;

    if (auto *btn = qobject_cast<QPushButton*>(sender())) {

        const QVariant rowProp = btn->property("row");

        if (rowProp.isValid())

            row = rowProp.toInt();

    }



    if ((row < 0 || row >= ui->tableEmployes->rowCount()) && currentEmployeRow >= 0)

        row = currentEmployeRow;



    if ((row < 0 || row >= ui->tableEmployes->rowCount()) && ui->tableEmployes->currentRow() >= 0)

        row = ui->tableEmployes->currentRow();



    if (row < 0 || row >= ui->tableEmployes->rowCount()) {

        const QString matriculeForm = ui->txtMatricule ? ui->txtMatricule->text().trimmed() : QString();

        if (!matriculeForm.isEmpty()) {

            for (int r = 0; r < ui->tableEmployes->rowCount(); ++r) {

                if (auto *it = ui->tableEmployes->item(r, 0)) {

                    if (it->text().trimmed() == matriculeForm) {

                        row = r;

                        break;

                    }

                }

            }

        }

    }



    if (row < 0 || row >= ui->tableEmployes->rowCount())

        return;



    if (QMessageBox::question(this, "Supprimer", QString::fromUtf8("Voulez-vous vraiment supprimer cet employ\xC3\xA9 ?"), QMessageBox::Yes | QMessageBox::No) != QMessageBox::Yes)

        return;

    int idEmp = -1;
    if (auto *matItem = ui->tableEmployes->item(row, 0)) {
        idEmp = matItem->data(EMP_ROLE_ID).toInt();
    }

    if (idEmp <= 0) {
        QMessageBox::warning(this, "Suppression", "ID employe introuvable, suppression annulee.");
        return;
    }

    QApplication::setOverrideCursor(Qt::WaitCursor);
    const bool deleted = Etmp.supprimer(idEmp);
    QApplication::restoreOverrideCursor();

    if (!deleted) {
        showFriendlySqlError(this, "supprimer l'employe", Etmp.lastError());
        return;
    }

    refreshEmployes();

    currentEmployeRow = -1;

    if (ui->tableEmployes->rowCount() > 0) {
        const int rowToSelect = qMax(0, qMin(row, ui->tableEmployes->rowCount() - 1));
        ui->tableEmployes->selectRow(rowToSelect);
    }

    bool shouldRunShowPage = true;
    if (auto *sw = mainStacked()) {
        if (auto *page = sw->findChild<QWidget*>("affichage", Qt::FindDirectChildrenOnly)) {
            shouldRunShowPage = (sw->currentWidget() != page);
        }
    }

    if (shouldRunShowPage) {
        showEmployesPage();
    }

}



// --- MISSION IA ---

void MainWindow::on_btnAnalyser_clicked()

{
    if (!ui->tableResultat) return;

    const QString missionText = ui->txtMission ? ui->txtMission->text().trimmed() : QString();
    if (missionText.isEmpty()) {
        ui->tableResultat->clearContents();
        ui->tableResultat->setRowCount(0);
        updateMissionSelectionUi(ui);
        QMessageBox::warning(this, "Affectation IA", "Veuillez decrire la mission.");
        return;
    }

    struct Candidate {
        int idEmp = 0;
        QString matricule;
        QString nom;
        QString specialite;
        QString moduleKey;
        QString disponibilite;
        int experienceYears = 0;
        bool available = false;
        bool specMatch = false;
        bool moduleMatch = false;
        bool responsibleMatch = false;
        bool maintenanceSpeciality = false;
        double score = 0.0;
    };

    QVector<Candidate> candidates;
    int difficulty = missionDifficultyLevel(missionText);
    QStringList requiredHints = missionSpecialityHints(missionText);
    QString targetModule = missionTargetModuleKey(missionText);
    QString inferenceSource = "Heuristique locale";
    QString apiError;
    const bool forceLocalMode = isLocalLeaveAiForced();
    if (forceLocalMode) {
        inferenceSource = "IA locale gratuite (forcee)";
    } else if (inferMissionByApi(missionText, difficulty, requiredHints, inferenceSource, apiError)) {
        // API inference applied.
    } else if (!apiError.trimmed().isEmpty()) {
        inferenceSource = "Heuristique locale (fallback API)";
        qWarning() << "Mission API fallback:" << apiError;
    }

    if (targetModule.isEmpty()) {
        if (requiredHints.contains("commandes")) targetModule = "commandes";
        else if (requiredHints.contains("clients")) targetModule = "clients";
        else if (requiredHints.contains("stock")) targetModule = "stock";
        else if (requiredHints.contains("produits")) targetModule = "produits";
        else if (requiredHints.contains("intervention")) targetModule = "maintenance";
    }
    QString targetResponsibleTitle = responsibleTitleForModule(targetModule);
    const bool missionInDomain = missionLooksInDomain(missionText, requiredHints);

    if (!missionInDomain) {
        ui->tableResultat->clearContents();
        ui->tableResultat->setRowCount(0);
        updateMissionSelectionUi(ui);
        if (ui->lblResultat) {
            ui->lblResultat->setText("Aucune recommandation: mission hors domaine ou trop vague.");
        }
        return;
    }

    const QString missionFold = foldTextKey(missionText);
    const bool forceMaintenanceModule = missionLooksMaintenanceRelated(missionText) || targetModule == "maintenance";
    if (forceMaintenanceModule) {
        targetModule = "maintenance";
        if (!requiredHints.contains("intervention")) {
            requiredHints.prepend("intervention");
        }
        targetResponsibleTitle = responsibleTitleForModule(targetModule);
    }

    const bool missionRequestsTeam = missionFold.contains("equipe")
                                  || missionFold.contains("team")
                                  || missionFold.contains("groupe")
                                  || missionFold.contains("cellule")
                                  || missionFold.contains("plusieurs")
                                  || missionFold.contains("deux")
                                  || missionFold.contains("2 techn")
                                  || missionFold.contains("2 employ");
    int targetTeamSize = 1;
    if (difficulty >= 4) {
        targetTeamSize = missionRequestsTeam ? 3 : 2;
    } else if (difficulty == 3) {
        targetTeamSize = missionRequestsTeam ? 2 : 1;
    } else if (difficulty == 2) {
        targetTeamSize = missionRequestsTeam ? 2 : 1;
    }
    const int requiredYears = (difficulty >= 4) ? 8 : ((difficulty == 3) ? 5 : ((difficulty == 2) ? 3 : 1));

    auto appendCandidate = [&](int idEmp,
                               const QString &matricule,
                               const QString &nom,
                               const QString &specialite,
                               const QString &disponibilite,
                               int experienceYears) {
        Candidate c;
        c.idEmp = idEmp;
        c.matricule = matricule.trimmed();
        c.nom = nom.trimmed();
        c.specialite = specialite.trimmed();
        c.moduleKey = moduleKeyForSpecialite(c.specialite);
        c.disponibilite = disponibilite.trimmed();
        c.experienceYears = (experienceYears > 0) ? experienceYears : fallbackExperienceYears(idEmp, matricule);
        c.available = isEmployeeAvailable(c.disponibilite);
        c.maintenanceSpeciality = isMaintenanceSpecialityLabel(c.specialite);
        c.specMatch = specialityMatches(c.specialite, requiredHints);
        c.moduleMatch = targetModule.isEmpty() || c.moduleKey == targetModule;
        if (forceMaintenanceModule) {
            c.specMatch = c.maintenanceSpeciality;
            // Accept maintenance-like specialities even if legacy label mapping is inconsistent.
            c.moduleMatch = (c.moduleKey == "maintenance") || c.maintenanceSpeciality;
        }

        c.responsibleMatch = c.moduleMatch && specialityMatchesResponsibleModule(c.specialite, targetModule);

        const bool hasSpecificHints = !requiredHints.isEmpty();
        const double availabilityScore = c.available ? 100.0 : 15.0;
        const double specialityScore = hasSpecificHints ? (c.specMatch ? 100.0 : 15.0) : 50.0;
        // Clamp experienceScore so that 0 years still gives a fair base (30 instead of 20)
        // to avoid over-penalising employees whose experience is not recorded in the DB.
        double experienceScore = (100.0 * static_cast<double>(c.experienceYears)) / static_cast<double>(requiredYears);
        experienceScore = qBound(30.0, experienceScore, 95.0);

        // Weights: speciality and availability are the primary signals;
        // experience is secondary so that employees without DB experience data still surface.
        const double availabilityWeight = (difficulty >= 3) ? 0.35 : 0.45;
        const double specialityWeight   = (difficulty >= 3) ? 0.40 : 0.40;
        const double experienceWeight   = (difficulty >= 3) ? 0.25 : 0.15;

        c.score = (availabilityScore * availabilityWeight)
            + (specialityScore * specialityWeight)
            + (experienceScore * experienceWeight);
        if (!hasSpecificHints) c.score -= 15.0;
        if (difficulty >= 3 && !c.available) c.score -= 20.0;
        if (hasSpecificHints && !c.specMatch) c.score -= 25.0;
        if (!targetModule.isEmpty() && !c.moduleMatch) c.score -= 40.0;
        if (forceMaintenanceModule) {
            if (c.maintenanceSpeciality) c.score += 15.0;
            else c.score -= 45.0;
        }
        if (!targetModule.isEmpty() && c.responsibleMatch) c.score += (difficulty >= 3 ? 14.0 : 10.0);
        if (!targetModule.isEmpty() && c.moduleMatch && !c.responsibleMatch) c.score -= (difficulty >= 3 ? 6.0 : 3.0);
        c.score = qBound(0.0, c.score, 98.0);

        candidates.append(c);
    };

    bool loadedFromDb = false;
    {
        QSqlQuery query;
        bool hasExperienceColumn = false;
        if (query.exec("SELECT id_emp, matricule, nom, specialite, disponibilite, experience FROM EMPLOYE")) {
            hasExperienceColumn = true;
            loadedFromDb = true;
        } else if (query.exec("SELECT id_emp, matricule, nom, specialite, disponibilite FROM EMPLOYE")) {
            hasExperienceColumn = false;
            loadedFromDb = true;
        }

        if (loadedFromDb) {
            while (query.next()) {
                const int idEmp = query.value(0).toInt();
                const QString matricule = query.value(1).toString();
                const QString nom = query.value(2).toString();
                const QString specialite = query.value(3).toString();
                const QString disponibilite = query.value(4).toString();
                const int experienceYears = hasExperienceColumn ? query.value(5).toInt() : 0;
                appendCandidate(idEmp, matricule, nom, specialite, disponibilite, experienceYears);
            }
        }
    }

    if (!loadedFromDb && ui->tableEmployes) {
        QSqlQueryModel *model = Etmp.afficher();
        if (model && !model->lastError().isValid() && model->rowCount() > 0) {
            loadedFromDb = true;
            for (int i = 0; i < model->rowCount(); ++i) {
                const int idEmp = model->data(model->index(i, 0)).toInt();
                const QString matricule = model->data(model->index(i, 1)).toString();
                const QString nom = model->data(model->index(i, 3)).toString();
                const QString specialite = model->data(model->index(i, 5)).toString();
                const QString disponibilite = model->data(model->index(i, 6)).toString();
                appendCandidate(idEmp, matricule, nom, specialite, disponibilite, 0);
            }
        }
        delete model;
    }

    if (!loadedFromDb && ui->tableEmployes) {
        for (int row = 0; row < ui->tableEmployes->rowCount(); ++row) {
            QTableWidgetItem *matItem = ui->tableEmployes->item(row, EMP_COL_MATRICULE);
            if (!matItem) continue;
            const int idEmp = matItem->data(EMP_ROLE_ID).toInt();
            const QString matricule = matItem->text();
            const QString nom = ui->tableEmployes->item(row, EMP_COL_NOM) ? ui->tableEmployes->item(row, EMP_COL_NOM)->text() : QString();
            const QString specialite = ui->tableEmployes->item(row, EMP_COL_SPECIALITE) ? ui->tableEmployes->item(row, EMP_COL_SPECIALITE)->text() : QString();
            const QString disponibilite = ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE) ? ui->tableEmployes->item(row, EMP_COL_DISPONIBILITE)->text() : QString();
            appendCandidate(idEmp, matricule, nom, specialite, disponibilite, 0);
        }
    }

    if (candidates.isEmpty()) {
        ui->tableResultat->clearContents();
        ui->tableResultat->setRowCount(0);
        updateMissionSelectionUi(ui);
        QMessageBox::warning(this, "Affectation IA", "Aucun employe disponible pour l'analyse.");
        return;
    }

    int targetModuleCandidateCount = 0;
    int targetModuleAvailableCount = 0;
    int targetResponsibleCandidateCount = 0;
    int targetResponsibleAvailableCount = 0;
    if (!targetModule.isEmpty()) {
        for (const Candidate &c : candidates) {
            if (c.moduleMatch) {
                ++targetModuleCandidateCount;
                if (c.available) ++targetModuleAvailableCount;
            }
            if (specialityMatchesResponsibleModule(c.specialite, targetModule)) {
                ++targetResponsibleCandidateCount;
                if (c.available) ++targetResponsibleAvailableCount;
            }
        }
    }

    std::stable_sort(candidates.begin(), candidates.end(), [&](const Candidate &a, const Candidate &b) {
        if (a.score != b.score) return a.score > b.score;
        if (targetModule != "maintenance" && a.responsibleMatch != b.responsibleMatch) return a.responsibleMatch && !b.responsibleMatch;
        if (a.moduleMatch != b.moduleMatch) return a.moduleMatch && !b.moduleMatch;
        if (a.maintenanceSpeciality != b.maintenanceSpeciality) return a.maintenanceSpeciality && !b.maintenanceSpeciality;
        if (a.available != b.available) return a.available && !b.available;
        if (a.specMatch != b.specMatch) return a.specMatch && !b.specMatch;
        return a.experienceYears > b.experienceYears;
    });

    QVector<int> preferredOrder;
    preferredOrder.reserve(candidates.size());
    auto pushGroup = [&](bool available, bool specMatch) {
        for (int i = 0; i < candidates.size(); ++i) {
            const Candidate &c = candidates.at(i);
            if (c.available == available && c.specMatch == specMatch) {
                preferredOrder.append(i);
            }
        }
    };

    if (!requiredHints.isEmpty()) {
        pushGroup(true, true);
        pushGroup(false, true);
        pushGroup(true, false);
        pushGroup(false, false);
    } else {
        for (int i = 0; i < candidates.size(); ++i) preferredOrder.append(i);
    }

    QVector<int> eligibleOrder;
    eligibleOrder.reserve(preferredOrder.size());
    const double minScore = (difficulty >= 4) ? 75.0 : ((difficulty == 3) ? 63.0 : ((difficulty == 2) ? 55.0 : (requiredHints.isEmpty() ? 55.0 : 50.0)));
    const bool needsSpecMatch = !requiredHints.isEmpty();
    const bool requireResponsibleRole = !targetModule.isEmpty() && targetModule != "maintenance";
    const bool requireMaintenanceSpeciality = forceMaintenanceModule;
    const bool lockToTargetModule = !targetModule.isEmpty();

    for (int idx : preferredOrder) {
        const Candidate &c = candidates.at(idx);
        if (!c.available) continue;
        if (c.score < minScore) continue;
        if (!targetModule.isEmpty() && !c.moduleMatch) continue;
        if (requireResponsibleRole && !c.responsibleMatch) continue;
        if (requireMaintenanceSpeciality && !c.maintenanceSpeciality) continue;
        if (needsSpecMatch && !c.specMatch) continue;
        eligibleOrder.append(idx);
    }

    const int strictEligibleCount = eligibleOrder.size();
    if (eligibleOrder.size() < targetTeamSize) {
        const double fallbackMinScore = !targetModule.isEmpty()
            ? qMax(difficulty >= 3 ? 56.0 : 45.0, minScore - (difficulty >= 4 ? 15.0 : 12.0))
            : qMax(40.0, minScore - 14.0);
        for (int idx : preferredOrder) {
            if (eligibleOrder.contains(idx)) continue;
            const Candidate &c = candidates.at(idx);
            if (!c.available) continue;
            if (!targetModule.isEmpty() && !c.moduleMatch) continue;
            if (requireMaintenanceSpeciality && !c.maintenanceSpeciality) continue;
            if (c.score < fallbackMinScore) continue;
            eligibleOrder.append(idx);
            if (eligibleOrder.size() >= targetTeamSize) break;
        }
    }

    // Respect combo-box role types: if no available strict match, prefer same responsible type
    // even when currently not available, before switching to another module/profile.
    if (eligibleOrder.size() < targetTeamSize && !targetModule.isEmpty() && !requireMaintenanceSpeciality) {
        for (int idx : preferredOrder) {
            if (eligibleOrder.contains(idx)) continue;
            const Candidate &c = candidates.at(idx);
            if (!c.moduleMatch) continue;
            if (!c.responsibleMatch) continue;
            eligibleOrder.append(idx);
            if (eligibleOrder.size() >= targetTeamSize) break;
        }
    }

    // If still missing candidates, prefer same module profiles (available first, then unavailable)
    // instead of jumping to another module.
    if (eligibleOrder.size() < targetTeamSize && lockToTargetModule) {
        for (int idx : preferredOrder) {
            if (eligibleOrder.contains(idx)) continue;
            const Candidate &c = candidates.at(idx);
            if (!c.moduleMatch) continue;
            if (requireMaintenanceSpeciality && !c.maintenanceSpeciality) continue;
            if (needsSpecMatch && !c.specMatch && c.available) continue;
            eligibleOrder.append(idx);
            if (eligibleOrder.size() >= targetTeamSize) break;
        }
    }

    // If module-strict filtering still yields nothing, allow cross-module experts as soft fallback
    // (except maintenance missions, which remain strictly maintenance-speciality).
    if (eligibleOrder.size() < targetTeamSize && !requireMaintenanceSpeciality && !lockToTargetModule) {
        const double crossModuleMinScore = qMax(38.0, minScore - 22.0);
        for (int idx : preferredOrder) {
            if (eligibleOrder.contains(idx)) continue;
            const Candidate &c = candidates.at(idx);
            if (!c.available) continue;
            if (needsSpecMatch && !c.specMatch) continue;
            if (c.score < crossModuleMinScore) continue;
            eligibleOrder.append(idx);
            if (eligibleOrder.size() >= targetTeamSize) break;
        }
    }

    // Last resort: keep UI usable by proposing top available profiles.
    if (eligibleOrder.size() < targetTeamSize) {
        for (int idx : preferredOrder) {
            if (eligibleOrder.contains(idx)) continue;
            const Candidate &c = candidates.at(idx);
            if (!lockToTargetModule && !c.available) continue;
            if (lockToTargetModule && !c.moduleMatch) continue;
            if (requireMaintenanceSpeciality && !c.maintenanceSpeciality) continue;
            eligibleOrder.append(idx);
            if (eligibleOrder.size() >= targetTeamSize) break;
        }
    }

    // Ultimate fallback: if still empty (e.g. no maintenance-speciality employees in DB),
    // propose the best-scored available employees regardless of module/speciality constraints.
    if (eligibleOrder.isEmpty()) {
        for (int idx : preferredOrder) {
            const Candidate &c = candidates.at(idx);
            if (!c.available) continue;
            eligibleOrder.append(idx);
            if (eligibleOrder.size() >= targetTeamSize) break;
        }
        // If even no available employees, just take the highest-scored ones
        if (eligibleOrder.isEmpty()) {
            for (int idx = 0; idx < candidates.size() && eligibleOrder.size() < targetTeamSize; ++idx) {
                eligibleOrder.append(idx);
            }
        }
    }

    if (difficulty == 3 && targetTeamSize == 1) {
        std::stable_sort(eligibleOrder.begin(), eligibleOrder.end(), [&](int left, int right) {
            const Candidate &a = candidates.at(left);
            const Candidate &b = candidates.at(right);
            if (targetModule != "maintenance" && a.responsibleMatch != b.responsibleMatch) return a.responsibleMatch && !b.responsibleMatch;
            if (a.maintenanceSpeciality != b.maintenanceSpeciality) return a.maintenanceSpeciality && !b.maintenanceSpeciality;
            if (a.experienceYears != b.experienceYears) return a.experienceYears > b.experienceYears;
            if (a.score != b.score) return a.score > b.score;
            return a.available && !b.available;
        });
    }

    const int selectedCount = qMin(targetTeamSize, eligibleOrder.size());

    QSignalBlocker missionBlocker(ui->tableResultat);
    ui->tableResultat->clearContents();
    ui->tableResultat->setRowCount(0);
    ui->tableResultat->setColumnCount(5);
    ui->tableResultat->setHorizontalHeaderLabels({"Choix", "Matricule", "Nom", "Competence", "Score Match"});
    if (auto *header = ui->tableResultat->horizontalHeader()) {
        header->setStretchLastSection(false);
        header->setMinimumSectionSize(80);
        header->setSectionResizeMode(0, QHeaderView::Fixed);
        header->setSectionResizeMode(1, QHeaderView::ResizeToContents);
        header->setSectionResizeMode(2, QHeaderView::Stretch);
        header->setSectionResizeMode(3, QHeaderView::Stretch);
        header->setSectionResizeMode(4, QHeaderView::ResizeToContents);
    }
    ui->tableResultat->setColumnWidth(0, 70);
    ui->tableResultat->verticalHeader()->setVisible(false);
    ui->tableResultat->verticalHeader()->setDefaultSectionSize(60);
    ui->tableResultat->setAlternatingRowColors(true);
    ui->tableResultat->setShowGrid(false);

    if (selectedCount == 0) {
        missionBlocker.unblock();
        updateMissionSelectionUi(ui);
        if (ui->lblResultat) {
            ui->lblResultat->setText("Aucune recommandation fiable pour cette mission.");
        }
        return;
    }

    double totalScore = 0.0;
    int availableCount = 0;

    for (int i = 0; i < selectedCount; ++i) {
        const Candidate &c = candidates.at(eligibleOrder.at(i));
        const int row = ui->tableResultat->rowCount();
        ui->tableResultat->insertRow(row);

        QTableWidgetItem *selectItem = new QTableWidgetItem();
        selectItem->setFlags((selectItem->flags() | Qt::ItemIsEnabled | Qt::ItemIsSelectable | Qt::ItemIsUserCheckable) & ~Qt::ItemIsEditable);
        selectItem->setCheckState(Qt::Checked);
        selectItem->setTextAlignment(Qt::AlignCenter);
        selectItem->setData(MISSION_ROLE_ID, c.idEmp);
        selectItem->setData(MISSION_ROLE_SCORE, c.score);
        ui->tableResultat->setItem(row, 0, selectItem);

        ui->tableResultat->setItem(row, 1, new QTableWidgetItem(c.matricule));
        ui->tableResultat->setItem(row, 2, new QTableWidgetItem(c.nom));

        const QString skillText = QString("%1 | %2 ans | %3")
                                      .arg(c.specialite.isEmpty() ? "-" : c.specialite)
                                      .arg(c.experienceYears)
                                      .arg(c.available ? "Disponible" : "Indisponible");
        ui->tableResultat->setItem(row, 3, new QTableWidgetItem(skillText));

        const double displayScore = qRound(c.score * 10.0) / 10.0;
        QTableWidgetItem *scoreItem = new QTableWidgetItem(QString::number(displayScore, 'f', 1) + "%");
        scoreItem->setTextAlignment(Qt::AlignCenter);
        if (displayScore >= 80.0) {
            scoreItem->setForeground(QBrush(QColor("#16a34a")));
        } else if (displayScore >= 60.0) {
            scoreItem->setForeground(QBrush(QColor("#d97706")));
        } else {
            scoreItem->setForeground(QBrush(QColor("#dc2626")));
        }
        ui->tableResultat->setItem(row, 4, scoreItem);

        totalScore += c.score;
        if (c.available) ++availableCount;
    }

    missionBlocker.unblock();
    updateMissionSelectionUi(ui);

    if (ui->lblResultat) {
        const double avgScore = (selectedCount > 0) ? (totalScore / static_cast<double>(selectedCount)) : 0.0;
        const QString mode = (selectedCount <= 1) ? "Employe recommande" : "Equipe recommandee";
        QString text = QString::fromUtf8("\xE2\x9C\x85 %1 (%2) - Difficulte: %3 - Score moyen: %4 - Source: %5")
                           .arg(mode)
                           .arg(selectedCount)
                           .arg(difficultyLabel(difficulty))
                           .arg(QString::number(avgScore, 'f', 1) + "%")
                           .arg(inferenceSource);
        if (!targetModule.isEmpty()) {
            const QString fallbackTitle = QString("Responsable %1").arg(moduleDisplayName(targetModule));
            text += QString(" - Cible: %1").arg(targetResponsibleTitle.isEmpty() ? fallbackTitle : targetResponsibleTitle);
        }
        if (!targetModule.isEmpty() && strictEligibleCount == 0) {
            const QString expectedTitle = targetResponsibleTitle.isEmpty()
                ? QString("responsable %1").arg(moduleDisplayName(targetModule).toLower())
                : targetResponsibleTitle.toLower();
            if (targetResponsibleCandidateCount <= 0) {
                text += QString(" - Aucun %1 trouve en base").arg(expectedTitle);
            } else if (targetResponsibleAvailableCount <= 0) {
                text += QString(" - Aucun %1 disponible, fallback meme module").arg(expectedTitle);
            } else if (targetModuleCandidateCount > 0 && targetModuleAvailableCount <= 0) {
                text += " - Aucun profil du module cible disponible";
            } else {
                text += " - Fallback controle sur module cible";
            }
        }
        if (availableCount < selectedCount) {
            text += " - Attention: disponibilite limitee";
        }
        if (strictEligibleCount < selectedCount) {
            text += " - Attention: couverture partielle (fallback)";
        }
        if (!apiError.trimmed().isEmpty()) {
            text += " - API indisponible";
        }
        ui->lblResultat->setText(text);
    }

}



