void MainWindow::on_btn_ajouter_client_clicked() {

    updateClientFormValidationState();

    if (!validateClientForm(false)) {
        QMessageBox::warning(this, "Saisie invalide", "Corrigez les champs en rouge avant d'enregistrer.");
        return;
    }

    const QString dateCreation = QDate::currentDate().toString("yyyy-MM-dd");

    // Create Client object with form data
    Client newClient(0,
                     ui->input_nom_ajouter->text(),
                     ui->input_matricule_ajouter->text(),
                     ui->input_email_ajouter->text(),
                     ui->input_contrat_ajouter->currentText(),
                     ui->input_paiement_ajouter->currentText().trimmed(),
                     dateCreation,
                     ui->input_date_expiration_ajouter->date().toString("yyyy-MM-dd"),
                     80); // Default tauxTri for new clients

    // Save to database FIRST
    if (!newClient.ajouter()) {
        QMessageBox::critical(this, "Erreur", "Impossible d'ajouter le client: " + newClient.lastError());
        return;
    }

    // Commit the transaction
    QSqlDatabase db = QSqlDatabase::database();
    if (!db.commit()) {
        qDebug() << "Erreur commit apres ajouter client:" << db.lastError().text();
    }

    // Update UI table only if database save succeeded
    onClientAdded(ui->input_matricule_ajouter->text(), 

                  ui->input_nom_ajouter->text(), 

                  ui->input_email_ajouter->text(), 

                  ui->input_contrat_ajouter->currentText(),

                  dateCreation,

                  ui->input_date_expiration_ajouter->date().toString("yyyy-MM-dd"),

                  ui->input_paiement_ajouter->currentText().trimmed());

    // Real-time warning email: send immediately if contract expires within 1 month.
    const QDate expirationDate = ui->input_date_expiration_ajouter->date();
    const int daysLeft = QDate::currentDate().daysTo(expirationDate);
    if (daysLeft >= 0 && daysLeft <= 30) {
        const bool sent = sendContractExpirationEmail(
            ui->input_email_ajouter->text().trimmed(),
            ui->input_nom_ajouter->text().trimmed(),
            expirationDate.toString("yyyy-MM-dd"),
            ui->input_contrat_ajouter->currentText().trimmed());

        if (!sent) {
            QMessageBox::warning(
                this,
                "Notification email",
                "Client ajoute, mais l'email d'alerte contrat (moins de 30 jours) n'a pas pu etre envoye.\n"
                "Verifiez la configuration SMTP (WASTEGUARD_SMTP_EMAIL / WASTEGUARD_SMTP_APP_PASSWORD)."
            );
        } else {
            QSettings settings("WasteGuard", "WasteGuard");
            const QString notifKey = QString("contractExpiryNotice/sent/%1/%2")
                                         .arg(ui->input_email_ajouter->text().trimmed().toLower(),
                                              expirationDate.toString("yyyy-MM-dd"));
            settings.setValue(notifKey, true);
        }
    }

    QMessageBox::information(this, "Succes", "Client ajoute avec succes.");

    if (ui->stackedWidget_Client) ui->stackedWidget_Client->setCurrentIndex(0);

}



void MainWindow::on_btn_modifier_client_clicked() {

    if (!validateClientForm(true)) {
        QMessageBox::warning(this, "Saisie invalide", "Verifiez Matricule, Nom, Email et Numero Telephone.");
        return;
    }

    // Use ID stored in the current row's UserRole for modification
    int clientId = -1;
    if (currentClientRow >= 0 && ui->tableWidget_Client->item(currentClientRow, 1)) {
        clientId = ui->tableWidget_Client->item(currentClientRow, 1)->data(Qt::UserRole).toInt();
    }

    if (clientId <= 0) {
        // Fallback search if ID could not be retrieved from the table row
        Client tempClient;
        if (!tempClient.findIdByMatricule(ui->input_matricule_modifier->text(), clientId)) {
            QMessageBox::warning(this, "Erreur", "Impossible de retrouver l'ID du client pour la modification.");
            return;
        }
    }

    // Preserve existing EcoScore instead of showing a pop-up
    int currentEcoScore = 85; // Fallback
    QSqlQuery qScore;
    qScore.prepare("SELECT TAUX_TRI FROM CLIENT WHERE ID_CLIENT = :id");
    qScore.bindValue(":id", clientId);
    if (qScore.exec() && qScore.next()) {
        currentEcoScore = qScore.value(0).toInt();
    }

    QString dateCreation = QDate::currentDate().toString("yyyy-MM-dd");
    if (currentClientRow >= 0 && ui->tableWidget_Client->item(currentClientRow, 5)) {
        const QString existingCreation = ui->tableWidget_Client->item(currentClientRow, 5)->text().trimmed();
        if (!existingCreation.isEmpty()) {
            dateCreation = existingCreation;
        }
    }

    // Create Client object with form data
    Client updatedClient(clientId,
                         ui->input_nom_modifier->text(),
                         ui->input_matricule_modifier->text(),
                         ui->input_email_modifier->text(),
                         ui->input_contrat_modifier->currentText(),
                         ui->input_paiement_modifier->currentText().trimmed(),
                         dateCreation,
                         ui->input_date_expiration_modifier->date().toString("yyyy-MM-dd"),
                         currentEcoScore);

    // Save to database FIRST
    if (!updatedClient.modifier()) {
        QMessageBox::critical(this, "Erreur", "Impossible de modifier le client: " + updatedClient.lastError());
        return;
    }

    // Commit the transaction
    QSqlDatabase db = QSqlDatabase::database();
    if (!db.commit()) {
        qDebug() << "Erreur commit apres modifier client:" << db.lastError().text();
    }

    // Update UI table only if database save succeeded
    onClientModified(currentClientRow,

                     ui->input_matricule_modifier->text(), 

                     ui->input_nom_modifier->text(), 

                     ui->input_email_modifier->text(), 

                     ui->input_contrat_modifier->currentText(),

                     dateCreation,

                     ui->input_date_expiration_modifier->date().toString("yyyy-MM-dd"),

                     ui->input_paiement_modifier->currentText().trimmed());

    // Refresh the client list from database to ensure consistency
    refreshClients();

    QMessageBox::information(this, "Succes", "Informations du client modifiees avec succes.");

    if (ui->stackedWidget_Client) ui->stackedWidget_Client->setCurrentIndex(0);

}



void MainWindow::onClientAdded(QString /*matricule*/, QString /*nom*/, QString /*email*/, QString /*type_contrat*/, QString /*date_creation*/, QString /*date_expiration*/, QString /*telephone*/) {

    // Refresh the entire client table from database to ensure consistency
    refreshClients();
}



void MainWindow::onClientModified(int row, QString matricule, QString nom, QString email, QString type_contrat, QString date_creation, QString date_expiration, QString telephone) {

    if(row >= 0 && row < ui->tableWidget_Client->rowCount()) {
        // Warning: Column 0 is the Checkbox widget. Regular items start at column 1.
        if (ui->tableWidget_Client->item(row, 1)) ui->tableWidget_Client->item(row, 1)->setText(matricule);
        if (ui->tableWidget_Client->item(row, 2)) ui->tableWidget_Client->item(row, 2)->setText(nom);
        if (ui->tableWidget_Client->item(row, 3)) ui->tableWidget_Client->item(row, 3)->setText(email);
        if (ui->tableWidget_Client->item(row, 4)) ui->tableWidget_Client->item(row, 4)->setText(type_contrat);
        if (ui->tableWidget_Client->item(row, 5)) ui->tableWidget_Client->item(row, 5)->setText(date_creation);
        if (ui->tableWidget_Client->item(row, 6)) ui->tableWidget_Client->item(row, 6)->setText(date_expiration);
        if (ui->tableWidget_Client->item(row, 7)) ui->tableWidget_Client->item(row, 7)->setText(telephone);
    }

}

bool MainWindow::validateClientForm(bool isModificationForm) const
{
    const QLineEdit *matField = isModificationForm ? ui->input_matricule_modifier : ui->input_matricule_ajouter;
    const QLineEdit *nomField = isModificationForm ? ui->input_nom_modifier : ui->input_nom_ajouter;
    const QLineEdit *emailField = isModificationForm ? ui->input_email_modifier : ui->input_email_ajouter;
    const QComboBox *phoneCombo = isModificationForm ? ui->input_paiement_modifier : ui->input_paiement_ajouter;

    if (!matField || !nomField || !emailField || !phoneCombo) {
        return false;
    }

    const QString matricule = matField->text().trimmed();
    const QString nom = nomField->text().trimmed();
    const QString email = emailField->text().trimmed();
    const QString telephone = phoneCombo->currentText().trimmed();

    const QRegularExpression matriculeRx("^[A-Za-z0-9_-]{3,20}$");
    const QRegularExpression nomRx("^[\\p{L}' -]{2,60}$");
    const QRegularExpression emailRx("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$");
    const QRegularExpression phoneRx("^\\+?[0-9]{8,15}$");

    return matriculeRx.match(matricule).hasMatch()
        && nomRx.match(nom).hasMatch()
        && emailRx.match(email).hasMatch()
        && phoneRx.match(telephone).hasMatch();
}

void MainWindow::updateClientFormValidationState()
{
    auto applyInputStyle = [](QLineEdit *field, const QRegularExpression &rx) {
        if (!field) return;
        const QString value = field->text().trimmed();
        const bool invalid = !value.isEmpty() && !rx.match(value).hasMatch();
        if (invalid) {
            field->setStyleSheet(
                "QLineEdit { border: 2px solid #dc2626; border-left: 4px solid #dc2626; "
                "background: #fff5f5; border-radius: 6px; }"
            );
            field->setToolTip("Saisie invalide");
        } else {
            field->setStyleSheet("");
            field->setToolTip("");
        }
    };

    auto applyComboLineStyle = [](QComboBox *combo, const QRegularExpression &rx) {
        if (!combo || !combo->lineEdit()) return;
        QLineEdit *field = combo->lineEdit();
        const QString value = field->text().trimmed();
        const bool invalid = !value.isEmpty() && !rx.match(value).hasMatch();
        if (invalid) {
            combo->setStyleSheet(
                "QComboBox { border: 2px solid #dc2626; border-left: 4px solid #dc2626; border-radius: 6px; background: #fff5f5; }"
                "QComboBox::drop-down { border: none; }"
            );
            field->setToolTip("Numero invalide (8 a 15 chiffres, + autorise)");
        } else {
            combo->setStyleSheet("");
            field->setToolTip("");
        }
    };

    const QRegularExpression matriculeRx("^[A-Za-z0-9_-]{3,20}$");
    const QRegularExpression nomRx("^[\\p{L}' -]{2,60}$");
    const QRegularExpression emailRx("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$");
    const QRegularExpression phoneRx("^\\+?[0-9]{8,15}$");

    applyInputStyle(ui->input_matricule_ajouter, matriculeRx);
    applyInputStyle(ui->input_nom_ajouter, nomRx);
    applyInputStyle(ui->input_email_ajouter, emailRx);
    applyComboLineStyle(ui->input_paiement_ajouter, phoneRx);

    applyInputStyle(ui->input_matricule_modifier, matriculeRx);
    applyInputStyle(ui->input_nom_modifier, nomRx);
    applyInputStyle(ui->input_email_modifier, emailRx);
    applyComboLineStyle(ui->input_paiement_modifier, phoneRx);

    const bool addValid = validateClientForm(false);
    const bool modValid = validateClientForm(true);

    if (ui->btn_save_ajouter) ui->btn_save_ajouter->setEnabled(addValid);
    if (ui->btn_save_modifier) ui->btn_save_modifier->setEnabled(modValid);
}



void MainWindow::addClientActionButtons(int row) {

    QWidget* actionWidget = new QWidget();

    QHBoxLayout* layout = new QHBoxLayout(actionWidget);

    layout->setContentsMargins(4, 10, 4, 10);

    layout->setSpacing(6);

    layout->setAlignment(Qt::AlignCenter);



    QPushButton* btnEdit = new QPushButton("Modifier");
    styleTableActionButton(btnEdit);

    

    QPushButton* btnDelete = new QPushButton("Supprimer");
    styleTableActionButton(btnDelete);

    

    layout->addWidget(btnEdit);

    layout->addWidget(btnDelete);

    if (ui->tableWidget_Client)
        ui->tableWidget_Client->setRowHeight(row, qMax(ui->tableWidget_Client->rowHeight(row), 62));

    

    ui->tableWidget_Client->setCellWidget(row, 8, actionWidget);

    connect(btnEdit, &QPushButton::clicked, this, [this, actionWidget](){

        int r = getRowForClientWidget(actionWidget);

        if (r < 0) return;

        currentClientRow = r;

        ui->input_matricule_modifier->setText(ui->tableWidget_Client->item(r, 1)->text());
        ui->input_nom_modifier->setText(ui->tableWidget_Client->item(r, 2)->text());
        ui->input_email_modifier->setText(ui->tableWidget_Client->item(r, 3)->text());
        ui->input_contrat_modifier->setCurrentText(ui->tableWidget_Client->item(r, 4)->text());
        ui->input_paiement_modifier->setCurrentText(ui->tableWidget_Client->item(r, 7)->text());

        QString dateStr = ui->tableWidget_Client->item(r, 6)->text();
        QDate expirationDate = QDate::fromString(dateStr, "yyyy-MM-dd");
        if (!expirationDate.isValid()) {
            expirationDate = QDate::currentDate();
        }
        ui->input_date_expiration_modifier->setDate(expirationDate);

        updateClientFormValidationState();

        if (ui->stackedWidget_Client) ui->stackedWidget_Client->setCurrentIndex(2);

    });

    connect(btnDelete, &QPushButton::clicked, this, [this, actionWidget](){

        int r = getRowForClientWidget(actionWidget);

        if (r < 0) return;

        if (QMessageBox::question(this, "Supprimer", "Voulez-vous supprimer ce client ?") == QMessageBox::Yes) {

            // Get ID from UserRole of the Matricule column (column 1)
            QTableWidgetItem* matriculeItem = ui->tableWidget_Client->item(r, 1);
            if (!matriculeItem) return;

            int clientId = matriculeItem->data(Qt::UserRole).toInt();
            if (clientId <= 0) {
                QMessageBox::warning(this, "Erreur", "ID client invalide.");
                return;
            }

            Client tempClient;
            // Delete from database
            if (!tempClient.supprimer(clientId)) {
                QMessageBox::critical(this, "Erreur", "Impossible de supprimer le client: " + tempClient.lastError());
                return;
            }

            // Commit the transaction
            QSqlDatabase db = QSqlDatabase::database();
            db.commit();

            // Refresh table
            refreshClients();
            QMessageBox::information(this, "Succes", "Client supprime avec succes");

        }

    });

}



int MainWindow::getRowForClientWidget(QWidget *widget) {

    for (int i = 0; i < ui->tableWidget_Client->rowCount(); i++) {

        // Action widget is in column 8
        if (ui->tableWidget_Client->cellWidget(i, 8) == widget) return i;

    }

    return -1;

}



void MainWindow::forceApplySidebarStyles()

{
    if (!ui) return;

    // Read colors from ThemeManager so this function works in all theme modes.
    const ThemePalette tp = ThemeManager::instance()->palette();

    // Right-panel sidebar buttons — use sidebar palette colors
    const QString btnStyle = QString(
        "QPushButton {"
        "  background: qlineargradient(spread:pad, x1:0, y1:0, x2:1, y2:1,"
        "    stop:0 %1, stop:1 %2);"
        "  color: %3;"
        "  border-radius: 12px;"
        "  padding: 12px;"
        "  font-weight: bold;"
        "  font-size: 13px;"
        "  border: 1px solid %2;"
        "  min-height: 40px;"
        "}"
        "QPushButton:hover {"
        "  background: qlineargradient(spread:pad, x1:0, y1:0, x2:1, y2:1,"
        "    stop:0 %2, stop:1 %4);"
        "}"
        "QPushButton:pressed {"
        "  background: %1;"
        "}"
    ).arg(tp.sidebarBg, tp.sidebarBg2, tp.textWhite, tp.primary);

    // Right panel frame/card style — use bgCard + border
    const QString sideStyle = QString(
        "QFrame {"
        "  background-color: %1;"
        "  border-radius: 20px;"
        "  border: 1px solid %2;"
        "}"
    ).arg(tp.bgCard, tp.border);

    const QString labelStyle =
        "QLabel {"
        "  background: transparent;"
        "  border: none;"
        "}";

    const QString cardStyle = QString(
        "QFrame {"
        "  background-color: %1;"
        "  border: 1px solid %2;"
        "  border-radius: 12px;"
        "}"
    ).arg(tp.bgCard, tp.border);

    const QStringList sidebarNames = {
        "rightSidebar", "rightSidebar_Commande", "stockRightSidebar",
        "prod_rightSidebar", "sidePanel_Employe", "sidePanel_Client",
        "sideDashboard", "sideAjout", "sideMod", "sidepanel"
    };

    for (const QString &name : sidebarNames) {

        const QList<QWidget*> panels = this->findChildren<QWidget*>(name);

        for (QWidget *panel : panels) {

            // 1. Style the panel itself
            panel->setStyleSheet(sideStyle);
            panel->setAttribute(Qt::WA_StyledBackground, true);

            // 2. Style all buttons inside
            const QList<QPushButton*> buttons = panel->findChildren<QPushButton*>();
            for (QPushButton *btn : buttons) {
                btn->setStyleSheet(btnStyle);
                btn->setCursor(Qt::PointingHandCursor);
            }

            // 3. Style labels — only set bg/border, preserve existing text color
            const QList<QLabel*> labels = panel->findChildren<QLabel*>();
            for (QLabel *lbl : labels) {
                if (!lbl) continue;
                const QString existing = lbl->styleSheet();
                if (!existing.contains("color:", Qt::CaseInsensitive)) {
                    lbl->setStyleSheet(existing + QString(
                        " background: transparent; border: none; color: %1;"
                    ).arg(tp.textBody));
                } else {
                    lbl->setStyleSheet(existing + " background: transparent; border: none;");
                }
            }

            // 4. Style stat/card child frames
            const QList<QFrame*> cards = panel->findChildren<QFrame*>();
            for (QFrame *card : cards) {
                if (card->objectName().startsWith("stat") ||
                    card->objectName().startsWith("st_")) {
                    card->setStyleSheet(cardStyle);
                }
            }
        }
    }

    // --- CATCH-ALL FOR GLOBAL BUTTONS BY NAME ---
    const QStringList globalBtnNames = {
        "btnPdf", "btnPdf_Cmd", "btnExport", "btnOrder", "btnFichePaie",
        "btnGoStats_Stock", "btnGoStats_Maint", "btnGoStats_Client", "btnGoStats_Cmd"
    };

    for (const QString &btnName : globalBtnNames) {
        if (QPushButton *btn = this->findChild<QPushButton*>(btnName)) {
            btn->setStyleSheet(btnStyle);
            btn->setCursor(Qt::PointingHandCursor);
        }
    }

    // Force update sidebar state to fix any overrides
    if (ui->sidebar) {
        updateSidebarState();
    }

    polishHomogeneousSurfaces();
}


void MainWindow::on_btnToggleSidebar_clicked()
{
    m_sidebarExpanded = !m_sidebarExpanded;
    updateSidebarState();
}

void MainWindow::updateSidebarState()
{
    if (!ui || !ui->sidebar) return;

    int targetWidth = m_sidebarExpanded ? 250 : 70;
    
    // Animate minimum width for smooth transition
    QPropertyAnimation *animation = new QPropertyAnimation(ui->sidebar, "minimumWidth");
    animation->setDuration(300);
    animation->setStartValue(ui->sidebar->width());
    animation->setEndValue(targetWidth);
    animation->setEasingCurve(QEasingCurve::InOutQuad);
    animation->start(QAbstractAnimation::DeleteWhenStopped);

    ui->sidebar->setMaximumWidth(targetWidth);

    // Toggle Logo Visibility
    if (ui->label_logo) {
         ui->label_logo->setVisible(m_sidebarExpanded);
    }

    // Toggle Button Text
    struct ButtonInfo {
        QPushButton* btn;
        QString fullText;
        QString emoji;
    };

    QList<ButtonInfo> buttons;
    // Append \uFE0E (Effectively \xe2\x96\x8e in utf8 literal? No, use u string or just the char)
    // Actually, in C++ source with UTF-8, we can just embed it if we are careful, or use QString properties.
    // \uFE0E is the "Text Presentation Selector".
    const QString vs = QChar(0xFE0E);

    const QString emoHome = QString::fromUcs4(U"\U0001F3E0") + vs;
    const QString emoStock = QString::fromUcs4(U"\U0001F4E6") + vs;
    const QString emoProd = QString::fromUcs4(U"\U0001F6CD") + vs;
    const QString emoClient = QString::fromUcs4(U"\U0001F465") + vs;
    const QString emoEmp = QString::fromUcs4(U"\U0001F477") + vs;
    const QString emoTasks = QString::fromUcs4(U"\U0001F4CB") + vs;
    const QString emoLeave = QString::fromUcs4(U"\U0001F3E5") + vs;
    const QString emoStats = QString::fromUcs4(U"\U0001F4CA") + vs;
    const QString emoMaint = QString::fromUcs4(U"\U0001F527") + vs;
    const QString emoCmd = QString::fromUcs4(U"\U0001F4DD") + vs;
    const QString emoLogout = QString::fromUcs4(U"\U0001F6AA") + vs;

    if (ui->btnAccueil && ui->btnAccueil->isVisible()) buttons.append({ui->btnAccueil, emoHome + " Accueil", emoHome});
    if (ui->btnStock && ui->btnStock->isVisible()) buttons.append({ui->btnStock, emoStock + " Stock", emoStock});
    if (ui->btnProduits && ui->btnProduits->isVisible()) buttons.append({ui->btnProduits, emoProd + " Produits", emoProd});
    if (ui->btnClient && ui->btnClient->isVisible()) buttons.append({ui->btnClient, emoClient + " Clients", emoClient});
    if (ui->btnEmployes && ui->btnEmployes->isVisible()) buttons.append({ui->btnEmployes, emoEmp + " Employes", emoEmp});
    if (QPushButton *btnTasks = this->findChild<QPushButton*>("btnMesTachesIA")) {
        if (btnTasks->isVisible()) {
            buttons.append({btnTasks, emoTasks + " Mes taches IA", emoTasks});
        }
    }
    if (QPushButton *btnLeave = this->findChild<QPushButton*>("btnDemandeCongeIA")) {
        if (btnLeave->isVisible()) {
            buttons.append({btnLeave, emoLeave + " Demande de conge IA", emoLeave});
        }
    }

    if (ui->btnMaintenance && ui->btnMaintenance->isVisible()) buttons.append({ui->btnMaintenance, emoMaint + " Maintenances", emoMaint});
    
    if (QPushButton* btnCmd = this->findChild<QPushButton*>("btnCommandes")) {
        if (btnCmd->isVisible()) {
            buttons.append({btnCmd, emoCmd + " Commandes", emoCmd});
        }
    }
    if (QPushButton *btnLogout = this->findChild<QPushButton*>("btnLogout")) {
        if (btnLogout->isVisible()) {
            buttons.append({btnLogout, emoLogout + " Deconnexion", emoLogout});
        }
    }

    QString commonStyle = 
        "QPushButton {"
        "   color: white !important;"
        "   background-color: transparent;"
        "   border: none;"
        "   font-size: 14px;"
        "   font-family: 'Segoe UI Symbol', 'Segoe UI', sans-serif;"
        "}"
        "QPushButton:hover {"
        "   background-color: rgba(39,174,96,0.16);"
        "   border-left: 3px solid #27ae60;"
        "}"
        "QPushButton:checked {"
        "   background-color: #27ae60;"
        "   border-left: 3px solid #1f8b4d;"
        "}";

    for (const auto& info : buttons) {
        if (!info.btn) continue;
        info.btn->setText(m_sidebarExpanded ? info.fullText : info.emoji);
        info.btn->setIcon(QIcon()); // Force remove any existing icon to rely on emoji text
        
        if (m_sidebarExpanded) {
            // Expanded: Left aligned, padding to look nice
            info.btn->setStyleSheet(commonStyle + 
                "QPushButton { text-align: left; padding-left: 20px; }");
        } else {
            // Collapsed: Center aligned, no padding (to center emoji)
            info.btn->setStyleSheet(commonStyle + 
                "QPushButton { text-align: center; padding-left: 0px; padding-right: 0px; font-size: 18px; }");
        }
    }
    
    // Toggle button icon
    if (QPushButton* btnToggle = ui->sidebar->findChild<QPushButton*>("btnToggleSidebar")) {
        btnToggle->setText(QString::fromUtf8(m_sidebarExpanded ? "\xE2\x97\x80" : "\xE2\x96\xB6"));
    }

    QTimer::singleShot(0, this, &MainWindow::onFloatingAIButtonPositionUpdate);
    QTimer::singleShot(320, this, &MainWindow::onFloatingAIButtonPositionUpdate);
}

// ---------- Card View Implementation ----------
void MainWindow::setupCardViewContainer()
{
    if (ui && ui->prod_cardLayout) {
        m_cardLayout = ui->prod_cardLayout;
    } else {
        // Fallback search if UI pointer is limited or renamed in merge
        m_cardLayout = findChild<QGridLayout*>("prod_cardLayout");
    }
}

void MainWindow::slot_toggleView()
{
    if (!ui || !ui->prod_viewStackedWidget) return;
    
    m_isCardView = !m_isCardView;
    ui->prod_viewStackedWidget->setCurrentIndex(m_isCardView ? 1 : 0);
    
    if (m_isCardView) {
        refreshCardView();
    } else if (QTableWidget *t = produitTable()) {
        for (int r = 0; r < t->rowCount(); ++r) {
            t->setRowHidden(r, false);
        }
    }
    
    if (ui->prod_btnToggleView) {
        // Keep the same font-safe glyphs used in the Stock module.
        ui->prod_btnToggleView->setText(QString::fromUtf8(m_isCardView ? "\xE2\x8A\x9F" : "\xE2\x8A\x9E"));
    }

    ensureRetractableRightPanels();
}

void MainWindow::refreshCardView()
{
    if (!m_isCardView) return;
    if (!m_cardLayout) setupCardViewContainer();
    if (!m_cardLayout) return;

    // Clear existing layout items
    QLayoutItem *child;
    while ((child = m_cardLayout->takeAt(0)) != nullptr) {
        if (child->widget()) delete child->widget();
        delete child;
    }

    QTableWidget *t = produitTable();
    if (!t) return;

    int totalItems = t->rowCount();
    int startIdx = m_currentPage * m_itemsPerPage;
    int endIdx = qMin(startIdx + m_itemsPerPage, totalItems);

    for (int i = startIdx; i < endIdx; ++i) {
        QWidget *card = createProductCard(i);
        if (card) {
            int row = (i - startIdx) / 3;
            int col = (i - startIdx) % 3;
            m_cardLayout->addWidget(card, row, col);
        }
    }

    // Update Table visibility (Synchronized Pagination)
    for (int i = 0; i < totalItems; ++i) {
        t->setRowHidden(i, (i < startIdx || i >= endIdx));
    }

    // Update Pagination UI
    QWidget *root = produitRoot();
    if (root) {
        QLabel *lblPage = root->findChild<QLabel*>("pagination_lblPage");
        QPushButton *btnPrev = root->findChild<QPushButton*>("pagination_btnPrev");
        QPushButton *btnNext = root->findChild<QPushButton*>("pagination_btnNext");

        int maxPages = qMax(1, (totalItems + m_itemsPerPage - 1) / m_itemsPerPage);
        if (lblPage) lblPage->setText(QString("Page %1 sur %2").arg(m_currentPage + 1).arg(maxPages));
        if (btnPrev) btnPrev->setEnabled(m_currentPage > 0);
        if (btnNext) btnNext->setEnabled(m_currentPage < maxPages - 1);
    }
}

QWidget* MainWindow::createProductCard(int row)
{
    QTableWidget *t = produitTable();
    if (!t || row >= t->rowCount()) return nullptr;

    const QString barcodeValue = t->item(row, 0) ? t->item(row, 0)->text().trimmed() : QString();
    QString model = t->item(row, 1) ? t->item(row, 1)->text() : "";
    QString cap   = t->item(row, 2) ? t->item(row, 2)->text() : "";
    QString price = t->item(row, 3) ? t->item(row, 3)->text() : "";

    QTableWidgetItem *refItem = t->item(row, 0);
    int cur = refItem ? refItem->data(PROD_ROLE_CUR).toInt() : 0;
    int max = refItem ? refItem->data(PROD_ROLE_MAX).toInt() : 0;
    QString aisle = refItem ? refItem->data(PROD_ROLE_AISLE).toString() : QString();
    QString features = refItem ? refItem->data(PROD_ROLE_FEATURES).toString() : QString();
    if (cur <= 0 && refItem) cur = refItem->data(Qt::UserRole).toInt();
    if (max <= 0 && refItem) max = refItem->data(Qt::UserRole + 1).toInt();
    if (aisle.isEmpty() && refItem) aisle = refItem->data(Qt::UserRole + 2).toString();

    int stockVal = qMax(0, cur);
    if (max <= 0) max = qMax(cur, 100);
    if (aisle.isEmpty()) aisle = "---";

    QString priceDisplay = price.trimmed();
    if (priceDisplay.isEmpty()) priceDisplay = "0";
    if (priceDisplay.contains("TND", Qt::CaseInsensitive)) {
        priceDisplay.remove(QRegularExpression("\\s*TND\\s*", QRegularExpression::CaseInsensitiveOption));
        priceDisplay = priceDisplay.trimmed();
    }

    // Derive type from characteristics/model for image choice
    QString typeProbe = features;
    if (typeProbe.isEmpty()) typeProbe = model + " " + cap;
    const QString typeLower = typeProbe.toLower();
    QString type;
    if (typeLower.contains("capteur")) type = "Capteur";
    else if (typeLower.contains("industriel") || typeLower.contains("3 flux")) type = "Industriel";
    else if (typeLower.contains("urbain") || typeLower.contains("compacteur")) type = "Urbain";
    else type = "Standard";

    // ?? Outer card frame ??????????????????????????????????????????????????????
    QFrame *card = new QFrame();
    card->setObjectName("productCard");
    card->setSizePolicy(QSizePolicy::Preferred, QSizePolicy::Fixed);
    card->setMinimumWidth(280);
    card->setMaximumWidth(420);
    card->setStyleSheet(
        "QFrame#productCard {"
        "  background-color: white;"
        "  border-radius: 18px;"
        "  border: 1px solid #e8edf2;"
        "}"
    );
    auto *shadow = new QGraphicsDropShadowEffect(card);
    shadow->setBlurRadius(20);
    shadow->setColor(QColor(0, 0, 0, 20));
    shadow->setOffset(0, 6);
    card->setGraphicsEffect(shadow);

    QVBoxLayout *outerLayout = new QVBoxLayout(card);
    outerLayout->setContentsMargins(0, 0, 0, 0);
    outerLayout->setSpacing(0);

    // ?? GLOSS IMAGE AREA ??????????????????????????????????????????????????????
    QWidget *imgArea = new QWidget();
    imgArea->setFixedHeight(190);
    imgArea->setStyleSheet(
        "background: qlineargradient(x1:0,y1:0,x2:0,y2:1,"
        "  stop:0 #eef4fb, stop:0.6 #ddeaf7, stop:1 #ccddf0);"
        "border-top-left-radius: 18px;"
        "border-top-right-radius: 18px;"
    );

    QHBoxLayout *imgAreaLayout = new QHBoxLayout(imgArea);
    imgAreaLayout->setContentsMargins(14, 10, 14, 10);
    imgAreaLayout->setSpacing(10);

    QLabel *imgLabel = new QLabel();
    imgLabel->setAlignment(Qt::AlignCenter);
    imgLabel->setStyleSheet("background: transparent;");
    imgLabel->setFixedSize(150, 150);
    imgLabel->setSizePolicy(QSizePolicy::Fixed, QSizePolicy::Fixed);

    const QString imagePath = refItem ? refItem->data(PROD_ROLE_IMAGE).toString() : QString();
    QString resPath = ":/assets/bin.png";
    if (type.contains("Capteur"))    resPath = ":/assets/sensor.png";
    else if (type.contains("Industriel")) resPath = ":/assets/landscape_bin.png";
    else if (type.contains("Urbain"))     resPath = ":/assets/compactor.png";

    if (!imagePath.isEmpty() && QFile::exists(imagePath)) {
        QPixmap pix(imagePath);
        if (!pix.isNull()) {
            imgLabel->setPixmap(renderProduitImage(pix, imgLabel->size()));
        }
    }
    if (imgLabel->pixmap(Qt::ReturnByValue).isNull()) {
        QPixmap pix(resPath);
        if (!pix.isNull()) {
            imgLabel->setPixmap(renderProduitImage(pix, imgLabel->size()));
        }
    }

    // Info column inside image area (right side)
    QWidget *infoColWrap = new QWidget();
    infoColWrap->setMinimumWidth(150);
    infoColWrap->setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Preferred);
    QVBoxLayout *infoCol = new QVBoxLayout(infoColWrap);
    infoCol->setSpacing(6);
    infoCol->setContentsMargins(0, 0, 0, 0);
    infoCol->setContentsMargins(8, 0, 0, 0);

    QLabel *lblTitle = new QLabel(model.toUpper());
    lblTitle->setWordWrap(true);
    lblTitle->setStyleSheet("font-size: 15px; font-weight: 800; color: #1e293b; background: transparent;");

    QLabel *lblSub = new QLabel("Smart Waste");
    lblSub->setStyleSheet("font-size: 12px; color: #64748b; background: transparent;");

    // Stock bar row (separate from capacity)
    QWidget *progRow = new QWidget();
    progRow->setStyleSheet("background: transparent;");
    QHBoxLayout *progLayout = new QHBoxLayout(progRow);
    progLayout->setContentsMargins(0, 0, 0, 0);
    progLayout->setSpacing(6);

    QProgressBar *bar = new QProgressBar();
    bar->setRange(0, 100);
    bar->setValue(qMin(stockVal, 100));
    bar->setTextVisible(false);
    bar->setFixedHeight(7);
    bar->setStyleSheet(
        "QProgressBar { background: #d1dce8; border-radius: 3px; border: none; }"
        "QProgressBar::chunk { background: #4ade80; border-radius: 3px; }"
    );
    QLabel *lblStock = new QLabel(QString("Stock: %1").arg(stockVal));
    lblStock->setStyleSheet("font-size: 11px; color: #475569; font-weight: 700; background: transparent;");
    progLayout->addWidget(bar, 1);
    progLayout->addWidget(lblStock);

    QString capDisplay = cap.trimmed();
    if (capDisplay.isEmpty()) capDisplay = QString::number(max);
    if (!capDisplay.contains("L", Qt::CaseInsensitive)) capDisplay += " L";
    QLabel *lblCap = new QLabel(QString("Capacite: %1").arg(capDisplay));
    lblCap->setStyleSheet("font-size: 11px; color: #475569; font-weight: 600; background: transparent;");

    // Status pill
    QWidget *pill = new QWidget();
    QHBoxLayout *pillL = new QHBoxLayout(pill);
    pillL->setContentsMargins(8, 3, 8, 3);
    pillL->setSpacing(4);
    QLabel *pIco = new QLabel();
    QLabel *pTxt = new QLabel();
    pTxt->setMinimumWidth(80);
    pTxt->setSizePolicy(QSizePolicy::Preferred, QSizePolicy::Fixed);
    pIco->setStyleSheet("background: transparent;");
    if (stockVal == 0) {
        pIco->setText(QString::fromUcs4(U"\u274C")); pTxt->setText("Rupture");
        pill->setStyleSheet("background: #fee2e2; border-radius: 10px;");
        pTxt->setStyleSheet("color: #b91c1c; font-size: 11px; font-weight: 700; background: transparent;");
    } else if (stockVal < 20) {
        pIco->setText(QString::fromUcs4(U"\u26A0")); pTxt->setText("Stock Faible");
        pill->setStyleSheet("background: #fef3c7; border-radius: 10px;");
        pTxt->setStyleSheet("color: #92400e; font-size: 11px; font-weight: 700; background: transparent;");
    } else {
        pIco->setText(QString::fromUcs4(U"\u2705")); pTxt->setText("En Stock");
        pill->setStyleSheet("background: #dcfce7; border-radius: 10px;");
        pTxt->setStyleSheet("color: #15803d; font-size: 11px; font-weight: 700; background: transparent;");
    }
    pillL->addWidget(pIco);
    pillL->addWidget(pTxt);

    // Aisle badge (replaces stock circle)
    QLabel *lblAisle = new QLabel(QString("%1 Allee %2").arg(QString::fromUcs4(U"\U0001F4CD")).arg(aisle));
    lblAisle->setStyleSheet("font-size: 11px; color: #475569; font-weight: 600; background: transparent;");

    QHBoxLayout *statusRow = new QHBoxLayout();
    statusRow->setContentsMargins(0,0,0,0);
    statusRow->addWidget(pill);
    statusRow->addStretch();
    statusRow->addWidget(lblAisle);

    infoCol->addWidget(lblTitle);
    infoCol->addWidget(lblSub);
    infoCol->addStretch();
    infoCol->addWidget(progRow);
    infoCol->addWidget(lblCap);
    infoCol->addLayout(statusRow);

    imgAreaLayout->addWidget(imgLabel, 0, Qt::AlignCenter);
    imgAreaLayout->addWidget(infoColWrap, 1);

    // ?? BOTTOM: Price + Buttons on ONE ROW ???????????????????????????????????
    QWidget *bottomArea = new QWidget();
    bottomArea->setStyleSheet("background: transparent;");
    QVBoxLayout *bottomLayout = new QVBoxLayout(bottomArea);
    bottomLayout->setContentsMargins(14, 10, 14, 12);
    bottomLayout->setSpacing(8);

    // Separator
    QFrame *sep = new QFrame();
    sep->setFrameShape(QFrame::HLine);
    sep->setStyleSheet("color: #f1f5f9; background: #f1f5f9; border: none; max-height: 1px;");

    QLabel *barcodeLabel = new QLabel();
    barcodeLabel->setAlignment(Qt::AlignCenter);
    barcodeLabel->setPixmap(renderEan13BarcodePixmap(barcodeValue, QSize(250, 82)));
    barcodeLabel->setToolTip(QString("Code-barres EAN-13 : %1").arg(barcodeValue));
    barcodeLabel->setStyleSheet(
        "background: #ffffff;"
        "border: 1px solid #e2e8f0;"
        "border-radius: 10px;"
        "padding: 4px;"
    );

    // Single row: Price badge + Modifier + Supprimer
    QHBoxLayout *actionRow = new QHBoxLayout();
    actionRow->setContentsMargins(0, 10, 0, 0);
    actionRow->setSpacing(8);

    // Price badge
    QWidget *priceBadge = new QWidget();
    priceBadge->setStyleSheet("background: #f0f9ff; border-radius: 10px; border: 1.5px solid #bae6fd;");
    QHBoxLayout *priceInner = new QHBoxLayout(priceBadge);
    priceInner->setContentsMargins(8, 5, 8, 5);
    priceInner->setSpacing(4);
    QLabel *priceIcon = new QLabel(QString::fromUcs4(U"\U0001F4B0"));
    priceIcon->setStyleSheet("background: transparent; font-size: 14px;");
    QLabel *priceVal = new QLabel(priceDisplay);
    priceVal->setStyleSheet(
        "font-size: 15px; font-weight: 900; color: #0f172a;"
        "background: transparent;"
    );
    priceBadge->setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Fixed);
    priceBadge->setMinimumWidth(90);
    priceVal->setSizePolicy(QSizePolicy::MinimumExpanding, QSizePolicy::Fixed);
    priceVal->setMinimumWidth(50);
    priceInner->addWidget(priceIcon);
    priceInner->addWidget(priceVal);

    // Modifier button
    QPushButton *btnEdit = new QPushButton(QString::fromUcs4(U"\u270F") + " Modifier");
    btnEdit->setFixedHeight(36);
    btnEdit->setSizePolicy(QSizePolicy::Minimum, QSizePolicy::Fixed);
    btnEdit->setProperty("row", row);
    btnEdit->setCursor(Qt::PointingHandCursor);
    btnEdit->setStyleSheet(
        "QPushButton { background: #2563eb; color: white; border-radius: 9px;"
        "  font-weight: 700; font-size: 12px; border: none; padding: 0 10px; }"
        "QPushButton:hover { background: #1d4ed8; }"
    );
    connect(btnEdit, &QPushButton::clicked, this, &MainWindow::handleEditClicked);

    // Supprimer button
    QPushButton *btnDelete = new QPushButton("Supprimer");
    btnDelete->setFixedHeight(36);
    btnDelete->setSizePolicy(QSizePolicy::Minimum, QSizePolicy::Fixed);
    btnDelete->setProperty("row", row);
    btnDelete->setCursor(Qt::PointingHandCursor);
    btnDelete->setStyleSheet(
        "QPushButton { background: #ef4444; color: white; border-radius: 9px;"
        "  font-weight: 700; font-size: 12px; border: none; padding: 0 10px; }"
        "QPushButton:hover { background: #dc2626; }"
    );
    connect(btnDelete, &QPushButton::clicked, this, &MainWindow::handleDeleteClicked);

    actionRow->addWidget(priceBadge, 1);
    actionRow->addStretch(1);
    actionRow->addWidget(btnEdit);
    actionRow->addWidget(btnDelete);

    bottomLayout->addWidget(sep);
    bottomLayout->addWidget(barcodeLabel);
    bottomLayout->addLayout(actionRow);

    outerLayout->addWidget(imgArea);
    outerLayout->addWidget(bottomArea);

    return card;
}

// --- PAGINATION LOGIC ---

void MainWindow::on_pagination_cbSize_currentIndexChanged(int /*index*/)
{
    QComboBox *cb = qobject_cast<QComboBox*>(sender());
    if (!cb) return;

    m_itemsPerPage = cb->currentText().toInt();
    m_currentPage = 0; // Reset to first page
    refreshCardView();
}

void MainWindow::on_pagination_btnPrev_clicked()
{
    if (m_currentPage > 0) {
        m_currentPage--;
        refreshCardView();
    }
}

void MainWindow::on_pagination_btnNext_clicked()
{
    QTableWidget *t = produitTable();
    if (!t) return;

    int totalItems = t->rowCount();
    int maxPages = (totalItems + m_itemsPerPage - 1) / m_itemsPerPage;

    if (m_currentPage < maxPages - 1) {
        m_currentPage++;
        refreshCardView();
    }
}

