void MainWindow::releaseBacsForCommande(int idCmd)
{
    if (idCmd <= 0) return;
    QString errorText;
    if (!restoreCommandeBacSelectionsToStock(idCmd, &errorText)) {
        QSqlQuery q;
        q.prepare("UPDATE BAC_INTEL SET ID_COMMANDE = NULL WHERE ID_COMMANDE = :id_cmd");
        q.bindValue(":id_cmd", idCmd);
        q.exec();
    }
    return;

    QSqlQuery q;
    q.prepare("UPDATE BAC_INTEL SET ID_COMMANDE = NULL WHERE ID_COMMANDE = :id_cmd");
    q.bindValue(":id_cmd", idCmd);
    q.exec();
}

void MainWindow::buildMaintenanceStats()
{
    if (!ui) return;

    if (ui->chartViewAbsence) ui->chartViewAbsence->show();
    if (ui->chartViewWorkload) ui->chartViewWorkload->show();
    if (ui->chartViewTasks) ui->chartViewTasks->show();
    if (ui->cbProjetStats) ui->cbProjetStats->show();

    // --- Pie chart: Cout pieces vs main d'oeuvre ---
    double totalCout = 0.0;
    double totalMO = 0.0;
    QSqlQuery qTotals;
    if (qTotals.exec("SELECT NVL(SUM(COUT), 0), NVL(SUM(MAIN_OEUVRE), 0) FROM INTERVENTION") && qTotals.next()) {
        totalCout = qTotals.value(0).toDouble();
        totalMO = qTotals.value(1).toDouble();
    }

    QPieSeries *costSeries = new QPieSeries();
    if (totalCout <= 0.0 && totalMO <= 0.0) {
        costSeries->append("Aucune donnee", 1);
        costSeries->slices().at(0)->setLabelVisible(true);
        costSeries->slices().at(0)->setBrush(QColor("#bdc3c7"));
    } else {
        auto *slicePieces = costSeries->append("Cout", totalCout);
        auto *sliceMO = costSeries->append("Main d'oeuvre", totalMO);
        
        slicePieces->setLabel(QString("Cout\n%1%").arg(slicePieces->percentage() * 100.0, 0, 'f', 1));
        sliceMO->setLabel(QString("Main d'oeuvre\n%1%").arg(sliceMO->percentage() * 100.0, 0, 'f', 1));
        
        slicePieces->setLabelVisible(true);
        sliceMO->setLabelVisible(true);
        slicePieces->setBrush(QColor("#3b82f6"));
        sliceMO->setBrush(QColor("#f59e0b"));
    }

    QChart *costChart = new QChart();
    costChart->addSeries(costSeries);
    costChart->setTitle("Repartition du cout (Pieces vs MO)");
    costChart->setTitleFont(QFont("Segoe UI", 12, QFont::Bold));
    costChart->legend()->setAlignment(Qt::AlignBottom);
    costChart->setAnimationOptions(QChart::SeriesAnimations);

    if (ui->chartViewAbsence) {
        ui->chartViewAbsence->setChart(costChart);
        ui->chartViewAbsence->setRenderHint(QPainter::Antialiasing);
    }

    // Populate year combo for monthly stats
    if (ui->cbProjetStats) {
        ui->cbProjetStats->setProperty("statsMode", "maintenance");
        QSignalBlocker blocker(ui->cbProjetStats);
        ui->cbProjetStats->setPlaceholderText("Choisir une annee...");
        ui->cbProjetStats->clear();
        QSqlQuery qYears;
        qYears.prepare(
            "SELECT DISTINCT EXTRACT(YEAR FROM DATE_INTER) AS annee "
            "FROM INTERVENTION "
            "WHERE DATE_INTER IS NOT NULL "
            "ORDER BY annee"
        );
        if (qYears.exec()) {
            while (qYears.next()) {
                const int year = qYears.value(0).toInt();
                ui->cbProjetStats->addItem(QString::number(year));
            }
        }
        if (ui->cbProjetStats->count() == 0) {
            ui->cbProjetStats->addItem(QString::number(QDate::currentDate().year()));
        }
        ui->cbProjetStats->setCurrentIndex(ui->cbProjetStats->count() - 1);
        ui->cbProjetStats->setToolTip("Selectionnez l'annee pour le detail mensuel");
    }

    int selectedYear = QDate::currentDate().year();
    if (ui->cbProjetStats && ui->cbProjetStats->count() > 0) {
        bool ok = false;
        const int y = ui->cbProjetStats->currentText().trimmed().toInt(&ok);
        if (ok) selectedYear = y;
    }
    updateMaintenanceMonthlyChart(selectedYear);
    updateMaintenanceTypeCostChart(selectedYear);
}

void MainWindow::updateMaintenanceMonthlyChart(int year)
{
    if (!ui || !ui->chartViewWorkload) return;

    QVector<double> monthTotals(12, 0.0);
    QSqlQuery qMonths;
    qMonths.prepare(
        "SELECT EXTRACT(MONTH FROM i.DATE_INTER) AS mois, "
        "       SUM(NVL(i.COUT,0)) AS cout, "
        "       SUM(NVL(i.MAIN_OEUVRE,0)) AS mo "
        "FROM INTERVENTION i "
        "WHERE i.DATE_INTER IS NOT NULL "
        "  AND EXTRACT(YEAR FROM i.DATE_INTER) = :annee "
        "GROUP BY EXTRACT(MONTH FROM i.DATE_INTER) "
        "ORDER BY mois"
    );
    qMonths.bindValue(":annee", year);
    if (qMonths.exec()) {
        while (qMonths.next()) {
            const int month = qMonths.value(0).toInt();
            const double cout = qMonths.value(1).toDouble();
            const double mo = qMonths.value(2).toDouble();
            if (month >= 1 && month <= 12) {
                monthTotals[month - 1] = cout + mo;
            }
        }
    }

    auto *set = new QBarSet("Cout total (DT)");
    set->setColor(QColor("#3b82f6"));
    double maxVal = 0.0;
    for (double v : monthTotals) {
        *set << v;
        if (v > maxVal) maxVal = v;
    }

    auto *series = new QBarSeries();
    series->append(set);
    series->setBarWidth(0.6);

    auto *chart = new QChart();
    chart->addSeries(series);
    chart->setTitle(QString("Cout mensuel (Pieces + MO) - %1").arg(year));
    chart->setTitleFont(QFont("Segoe UI", 12, QFont::Bold));
    chart->setAnimationOptions(QChart::SeriesAnimations);
    chart->legend()->setVisible(false);
    chart->setBackgroundBrush(QColor("#ffffff"));
    chart->setPlotAreaBackgroundVisible(true);
    chart->setPlotAreaBackgroundBrush(QColor("#f8fafc"));

    QStringList months = {"Jan", "Fev", "Mar", "Avr", "Mai", "Juin", "Juil", "Aou", "Sep", "Oct", "Nov", "Dec"};
    auto *axisX = new QBarCategoryAxis();
    axisX->append(months);
    axisX->setLabelsColor(QColor("#334155"));
    chart->addAxis(axisX, Qt::AlignBottom);
    series->attachAxis(axisX);

    auto *axisY = new QValueAxis();
    axisY->setRange(0, qMax(1.0, maxVal * 1.15));
    axisY->setLabelsColor(QColor("#334155"));
    axisY->setTitleText("Cout total (TND)");
    axisY->setTitleBrush(QBrush(QColor("#334155")));
    chart->addAxis(axisY, Qt::AlignLeft);
    series->attachAxis(axisY);

    ui->chartViewWorkload->setChart(chart);
    ui->chartViewWorkload->setRenderHint(QPainter::Antialiasing);
}

void MainWindow::updateMaintenanceTypeCostChart(int year)
{
    if (!ui || !ui->chartViewTasks) return;

    QStringList types;
    QList<double> totals;
    QSqlQuery qTypes;
    qTypes.prepare(
        "SELECT t.type, SUM(t.total_cost) AS total "
        "FROM ( "
        "    SELECT i.ID_INTER, NVL(i.TYPE, 'Non specifie') AS type, "
        "           NVL(i.COUT,0) + NVL(i.MAIN_OEUVRE,0) AS total_cost, "
        "           i.DATE_INTER "
        "    FROM INTERVENTION i "
        ") t "
        "WHERE t.DATE_INTER IS NOT NULL "
        "  AND EXTRACT(YEAR FROM t.DATE_INTER) = :annee "
        "GROUP BY t.type "
        "ORDER BY total DESC"
    );
    qTypes.bindValue(":annee", year);
    if (qTypes.exec()) {
        while (qTypes.next() && types.size() < 6) {
            types << qTypes.value(0).toString();
            totals << qTypes.value(1).toDouble();
        }
    }
    if (types.isEmpty()) {
        types << "Aucune";
        totals << 0.0;
    }

    auto *set = new QBarSet("Cout par type (DT)");
    set->setColor(QColor("#10b981"));
    double maxVal = 0.0;
    for (double v : totals) {
        *set << v;
        if (v > maxVal) maxVal = v;
    }

    auto *series = new QBarSeries();
    series->append(set);
    series->setBarWidth(0.6);

    auto *chart = new QChart();
    chart->addSeries(series);
    chart->setTitle(QString("Cout par type d'intervention - %1").arg(year));
    chart->setTitleFont(QFont("Segoe UI", 12, QFont::Bold));
    chart->setAnimationOptions(QChart::SeriesAnimations);
    chart->legend()->setVisible(false);
    chart->setBackgroundBrush(QColor("#ffffff"));
    chart->setPlotAreaBackgroundVisible(true);
    chart->setPlotAreaBackgroundBrush(QColor("#f8fafc"));

    auto *axisX = new QBarCategoryAxis();
    axisX->append(types);
    axisX->setLabelsColor(QColor("#334155"));
    chart->addAxis(axisX, Qt::AlignBottom);
    series->attachAxis(axisX);

    auto *axisY = new QValueAxis();
    axisY->setRange(0, qMax(1.0, maxVal * 1.15));
    axisY->setLabelsColor(QColor("#334155"));
    axisY->setTitleText("Cout total (TND)");
    axisY->setTitleBrush(QBrush(QColor("#334155")));
    chart->addAxis(axisY, Qt::AlignLeft);
    series->attachAxis(axisY);

    ui->chartViewTasks->setChart(chart);
    ui->chartViewTasks->setRenderHint(QPainter::Antialiasing);
}

void MainWindow::buildCommandeStats()
{
    if (!ui) return;

    // Ensure Commande stats are visible and employee task chart is hidden
    if (ui->chartViewAbsence) ui->chartViewAbsence->show();
    if (ui->chartViewWorkload) ui->chartViewWorkload->show();
    if (ui->chartViewTasks) ui->chartViewTasks->show();
    if (ui->cbProjetStats) ui->cbProjetStats->show();

    // --- Pie chart: Total money generated by each bin model ---
    if (ui->chartViewTasks) {
        QPieSeries *binSeries = new QPieSeries();
        QSqlQuery qBins("SELECT NVL(b.MODELE, 'Inconnu'), SUM(cb.QTE * cb.PRIX_UNITAIRE) "
                        "FROM COMMANDE_BAC cb "
                        "LEFT JOIN BAC_INTEL b ON cb.ID_BAC = b.ID_BAC "
                        "GROUP BY b.MODELE "
                        "HAVING SUM(cb.QTE * cb.PRIX_UNITAIRE) > 0");

        while (qBins.next()) {
            QString modele = qBins.value(0).toString();
            double total = qBins.value(1).toDouble();
            binSeries->append(modele, total);
        }

        if (binSeries->count() == 0) {
            binSeries->append("Aucune donnee", 1);
            binSeries->slices().at(0)->setBrush(QColor("#bdc3c7"));
            binSeries->slices().at(0)->setLabelVisible(true);
        } else {
            // Assign dynamic colors using HSV to handle new bins automatically
            for (int i = 0; i < binSeries->count(); ++i) {
                QPieSlice *slice = binSeries->slices().at(i);
                double pct = slice->percentage() * 100.0;
                slice->setLabel(QString("%1\n%2%").arg(slice->label()).arg(pct, 0, 'f', 1));
                slice->setLabelVisible(true);
                slice->setBrush(QColor::fromHsv((i * 137) % 360, 180, 230));
            }
        }

        QChart *binChart = new QChart();
        binChart->addSeries(binSeries);
        binChart->setTitle("Revenus par modÃ¨le de bac");
        binChart->setTitleFont(QFont("Segoe UI", 12, QFont::Bold));
        binChart->setAnimationOptions(QChart::SeriesAnimations);
        binChart->legend()->setVisible(true);
        binChart->legend()->setAlignment(Qt::AlignRight);
        binChart->setBackgroundBrush(QColor("#ffffff"));

        ui->chartViewTasks->setChart(binChart);
        ui->chartViewTasks->setRenderHint(QPainter::Antialiasing);
    }

    // Annual revenue chart (yearly CA)
    QStringList yearLabels;
    QList<double> yearTotals;

    QSqlQuery qYears;
    qYears.prepare(
        "SELECT EXTRACT(YEAR FROM DATE_COMMANDE) AS annee, SUM(NVL(PRIX_TOTAL,0)) AS total "
        "FROM COMMANDE "
        "WHERE DATE_COMMANDE IS NOT NULL "
        "GROUP BY EXTRACT(YEAR FROM DATE_COMMANDE) "
        "ORDER BY annee"
    );
    if (qYears.exec()) {
        while (qYears.next()) {
            const int year = qYears.value(0).toInt();
            const double total = qYears.value(1).toDouble();
            yearLabels << QString::number(year);
            yearTotals << total;
        }
    }

    if (yearLabels.isEmpty()) {
        yearLabels << "Aucune";
        yearTotals << 0.0;
    }

    auto *yearSet = new QBarSet("Chiffre d'affaires");
    yearSet->setColor(QColor("#3b82f6"));
    yearSet->setBorderColor(QColor("#1d4ed8"));
    double maxYearVal = 0.0;
    for (double v : yearTotals) {
        *yearSet << v;
        if (v > maxYearVal) maxYearVal = v;
    }

    auto *yearSeries = new QBarSeries();
    yearSeries->append(yearSet);
    yearSeries->setBarWidth(0.6);

    auto *yearChart = new QChart();
    yearChart->addSeries(yearSeries);
    yearChart->setTitle("Chiffre annuel par annee");
    yearChart->setTitleFont(QFont("Segoe UI", 12, QFont::Bold));
    yearChart->setAnimationOptions(QChart::SeriesAnimations);
    yearChart->legend()->setVisible(false);
    yearChart->setBackgroundBrush(QColor("#ffffff"));
    yearChart->setPlotAreaBackgroundVisible(true);
    yearChart->setPlotAreaBackgroundBrush(QColor("#f8fafc"));

    auto *yearAxisX = new QBarCategoryAxis();
    yearAxisX->append(yearLabels);
    yearAxisX->setLabelsColor(QColor("#334155"));
    yearChart->addAxis(yearAxisX, Qt::AlignBottom);
    yearSeries->attachAxis(yearAxisX);

    auto *yearAxisY = new QValueAxis();
    yearAxisY->setRange(0, qMax(1.0, maxYearVal * 1.15));
    yearAxisY->setLabelsColor(QColor("#334155"));
    yearAxisY->setTitleText("Chiffre d'affaire (TND)");
    yearAxisY->setTitleBrush(QBrush(QColor("#334155")));
    yearChart->addAxis(yearAxisY, Qt::AlignLeft);
    yearSeries->attachAxis(yearAxisY);

    if (ui->chartViewAbsence) {
        ui->chartViewAbsence->setChart(yearChart);
        ui->chartViewAbsence->setRenderHint(QPainter::Antialiasing);
    }

    // Populate year combo for monthly stats
    if (ui->cbProjetStats) {
        ui->cbProjetStats->setProperty("statsMode", "commandes");
        QSignalBlocker blocker(ui->cbProjetStats);
        ui->cbProjetStats->setPlaceholderText("Choisir une annee...");
        ui->cbProjetStats->clear();
        for (const QString &y : yearLabels) {
            if (y == "Aucune") continue;
            ui->cbProjetStats->addItem(y);
        }
        if (ui->cbProjetStats->count() == 0) {
            const int currentYear = QDate::currentDate().year();
            ui->cbProjetStats->addItem(QString::number(currentYear));
        }
        ui->cbProjetStats->setCurrentIndex(ui->cbProjetStats->count() - 1);
        ui->cbProjetStats->setToolTip("Selectionnez l'annee pour le detail mensuel");

        if (!ui->cbProjetStats->property("cmdStatsConnected").toBool()) {
            connect(ui->cbProjetStats, &QComboBox::currentTextChanged, this, [this](const QString &text) {
                bool ok = false;
                const int year = text.trimmed().toInt(&ok);
                if (ok) updateCommandeMonthlyChart(year);
            });
            ui->cbProjetStats->setProperty("cmdStatsConnected", true);
        }
    }

    // Build monthly chart for selected year
    int selectedYear = QDate::currentDate().year();
    if (ui->cbProjetStats && ui->cbProjetStats->count() > 0) {
        bool ok = false;
        const int y = ui->cbProjetStats->currentText().trimmed().toInt(&ok);
        if (ok) selectedYear = y;
    }
    updateCommandeMonthlyChart(selectedYear);
}

void MainWindow::updateCommandeMonthlyChart(int year)
{
    if (!ui || !ui->chartViewWorkload) return;

    QVector<double> monthTotals(12, 0.0);
    QSqlQuery qMonths;
    qMonths.prepare(
        "SELECT EXTRACT(MONTH FROM DATE_COMMANDE) AS mois, SUM(NVL(PRIX_TOTAL,0)) AS total "
        "FROM COMMANDE "
        "WHERE DATE_COMMANDE IS NOT NULL "
        "  AND EXTRACT(YEAR FROM DATE_COMMANDE) = :annee "
        "GROUP BY EXTRACT(MONTH FROM DATE_COMMANDE) "
        "ORDER BY mois"
    );
    qMonths.bindValue(":annee", year);
    if (qMonths.exec()) {
        while (qMonths.next()) {
            const int month = qMonths.value(0).toInt();
            const double total = qMonths.value(1).toDouble();
            if (month >= 1 && month <= 12) {
                monthTotals[month - 1] = total;
            }
        }
    }

    auto *set = new QBarSet(QString("CA %1").arg(year));
    set->setColor(QColor("#3b82f6"));
    set->setBorderColor(QColor("#1d4ed8"));

    double maxVal = 0.0;
    for (double v : monthTotals) {
        *set << v;
        if (v > maxVal) maxVal = v;
    }

    auto *series = new QBarSeries();
    series->append(set);
    series->setBarWidth(0.6);

    auto *chart = new QChart();
    chart->addSeries(series);
    chart->setTitle(QString("Chiffre d'affaire mensuel - %1").arg(year));
    chart->setTitleFont(QFont("Segoe UI", 12, QFont::Bold));
    chart->setAnimationOptions(QChart::SeriesAnimations);
    chart->legend()->setVisible(false);
    chart->setBackgroundBrush(QColor("#ffffff"));
    chart->setPlotAreaBackgroundVisible(true);
    chart->setPlotAreaBackgroundBrush(QColor("#f8fafc"));

    QStringList months = {"Jan", "Fev", "Mar", "Avr", "Mai", "Jun", "Jul", "Aou", "Sep", "Oct", "Nov", "Dec"};
    auto *axisX = new QBarCategoryAxis();
    axisX->append(months);
    axisX->setLabelsColor(QColor("#334155"));
    chart->addAxis(axisX, Qt::AlignBottom);
    series->attachAxis(axisX);

    auto *axisY = new QValueAxis();
    axisY->setRange(0, qMax(1.0, maxVal * 1.15));
    axisY->setLabelsColor(QColor("#334155"));
    axisY->setTitleText("Chiffre d'affaire (TND)");
    axisY->setTitleBrush(QBrush(QColor("#334155")));
    chart->addAxis(axisY, Qt::AlignLeft);
    series->attachAxis(axisY);

    ui->chartViewWorkload->setChart(chart);
    ui->chartViewWorkload->setRenderHint(QPainter::Antialiasing);
}

void MainWindow::on_btnPdf_Cmd_clicked()
{
    QString defaultName = "Facture_Commandes_" + QDate::currentDate().toString("yyyyMMdd") + ".pdf";
    QString fileName = QFileDialog::getSaveFileName(this, "Exporter Facture Commandes", defaultName, "PDF Files (*.pdf)");
    if (fileName.isEmpty()) return;
    if (!fileName.endsWith(".pdf", Qt::CaseInsensitive)) {
        fileName += ".pdf";
    }

    QPdfWriter writer(fileName);
    writer.setPageSize(QPageSize::A4);
    writer.setPageMargins(QMarginsF(22, 20, 22, 20));
    writer.setResolution(300);

    QPainter painter(&writer);
    painter.setRenderHint(QPainter::Antialiasing);
    if (!painter.isActive()) {
        QMessageBox::critical(this, "Export PDF", "Impossible de creer le PDF.");
        return;
    }

    const int pageW = writer.width();
    const int pageH = writer.height();
    const int margin = 120;
    const int headerH = 620;
    const int compactHeaderH = 300;
    const int footerH = 110;

    QTableWidget *t = ui->tableProduits_2;
    const int totalCmds = t ? t->rowCount() : 0;
    int totalBacs = 0;
    double totalCA = 0.0;
    QSet<QString> addresses;
    QDate minDate;
    QDate maxDate;
    bool hasDate = false;

    auto parseAmount = [](const QString &text) -> double {
        QString cleaned = text;
        cleaned.replace("TND", "", Qt::CaseInsensitive);
        cleaned.replace("DT", "", Qt::CaseInsensitive);
        cleaned.replace(" ", "");
        cleaned.replace(",", ".");
        bool ok = false;
        double val = cleaned.toDouble(&ok);
        return ok ? val : 0.0;
    };

    if (t) {
        for (int i = 0; i < t->rowCount(); ++i) {
            if (auto *itQty = t->item(i, 1)) totalBacs += itQty->text().toInt();
            if (auto *itPrice = t->item(i, 7)) totalCA += parseAmount(itPrice->text());
            if (auto *itAddr = t->item(i, 4)) {
                const QString addr = itAddr->text().trimmed();
                if (!addr.isEmpty() && addr != "---") addresses.insert(addr);
            }
            if (auto *itDate = t->item(i, 5)) {
                const QDate d = QDate::fromString(itDate->text(), "yyyy-MM-dd");
                if (d.isValid()) {
                    if (!hasDate) {
                        minDate = maxDate = d;
                        hasDate = true;
                    } else {
                        if (d < minDate) minDate = d;
                        if (d > maxDate) maxDate = d;
                    }
                }
            }
        }
    }

    const QString invoiceNo = QString("FC-%1").arg(QDateTime::currentDateTime().toString("yyyyMMdd-HHmm"));
    const QString invoiceDate = QDate::currentDate().toString("dd/MM/yyyy");
    const QString period = hasDate
        ? (minDate.toString("dd/MM/yyyy") + " - " + maxDate.toString("dd/MM/yyyy"))
        : "---";
    const QString billTo = addresses.size() == 1 ? *addresses.begin()
                                                 : (addresses.isEmpty() ? "---" : "Clients multiples");

    QPixmap logo(":/wasteguard_logo.png");
    if (logo.isNull()) logo.load("wasteguard_logo.png");

    int pageNumber = 1;
    QLocale fr(QLocale::French);

    auto drawHeader = [&](bool compact) {
        const int h = compact ? compactHeaderH : headerH;
        painter.fillRect(0, 0, pageW, h, QColor("#f8fafc"));

        const int logoH = compact ? 60 : 80;
        int titleX = margin;
        if (!logo.isNull()) {
            painter.drawPixmap(margin, 40, logo.scaledToHeight(logoH, Qt::SmoothTransformation));
            titleX = margin + (logoH + 40);
        }

        painter.setPen(QColor("#0f172a"));
        painter.setFont(QFont("Segoe UI", compact ? 18 : 26, QFont::Bold));
        painter.drawText(titleX, 60, pageW - margin - titleX, 70,
                         Qt::AlignLeft | Qt::AlignVCenter, "FACTURE");
        painter.setFont(QFont("Segoe UI", compact ? 9 : 11, QFont::Normal));
        painter.drawText(titleX, compact ? 112 : 144, pageW - margin - titleX, 40,
                         Qt::AlignLeft | Qt::AlignVCenter, "Commandes");

        const int infoW = 420;
        const int infoX = pageW - margin - infoW;
        int infoY = 70;
        QFont infoBoldFont("Segoe UI", compact ? 9 : 10, QFont::Bold);
        QFont infoNormFont("Segoe UI", compact ? 9 : 10, QFont::Normal);
        QFontMetricsF infoBoldFm(infoBoldFont, painter.device());
        QFontMetricsF infoNormFm(infoNormFont, painter.device());
        const int infoLineH = static_cast<int>(qMax(infoBoldFm.height(), infoNormFm.height())) + 10;
        painter.setFont(infoBoldFont);
        painter.drawText(infoX, infoY, infoW, infoLineH,
                         Qt::AlignRight | Qt::AlignVCenter, "Ndeg " + invoiceNo);
        infoY += infoLineH;
        painter.setFont(infoNormFont);
        painter.drawText(infoX, infoY, infoW, infoLineH,
                         Qt::AlignRight | Qt::AlignVCenter, "Date: " + invoiceDate);
        infoY += infoLineH;
        painter.drawText(infoX, infoY, infoW, infoLineH,
                         Qt::AlignRight | Qt::AlignVCenter, "Periode: " + period);

        if (!compact) {
            const int gap = 30;
            const int blockW = (pageW - 2 * margin - gap) / 2;
            const int blockH = 220;
            const int blockY = 210;
            const int pad = 16;

            painter.setPen(QColor("#e2e8f0"));
            painter.setBrush(Qt::white);
            painter.drawRoundedRect(margin, blockY, blockW, blockH, 10, 10);
            painter.drawRoundedRect(margin + blockW + gap, blockY, blockW, blockH, 10, 10);

            QFont labelFont("Segoe UI", 9, QFont::Bold);
            QFont textFont("Segoe UI", 9);
            QFont smallFont("Segoe UI", 8);
            QFontMetricsF fm(textFont, painter.device());
            const int lineH = static_cast<int>(fm.height()) + 12;

            int yLeft = blockY + pad + 2;
            painter.setPen(QColor("#0f172a"));
            painter.setFont(labelFont);
            painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                             Qt::AlignLeft | Qt::AlignVCenter, "Emis par");
            yLeft += lineH + 4;
            painter.setFont(textFont);
            painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                             Qt::AlignLeft | Qt::AlignVCenter, "WasteGuard");
            yLeft += lineH;
            painter.setFont(smallFont);
            painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                             Qt::AlignLeft | Qt::AlignVCenter, "support@wasteguard.com");

            int xRight = margin + blockW + gap;
            int yRight = blockY + pad + 2;
            painter.setPen(QColor("#0f172a"));
            painter.setFont(labelFont);
            painter.drawText(xRight + pad, yRight, blockW - 2 * pad, lineH,
                             Qt::AlignLeft | Qt::AlignVCenter, "Facture a");
            yRight += lineH + 4;
            painter.setFont(textFont);
            painter.drawText(QRect(xRight + pad, yRight, blockW - 2 * pad, lineH * 2),
                             Qt::AlignLeft | Qt::AlignTop | Qt::TextWordWrap,
                             billTo);
            yRight += lineH * 2;
            painter.setFont(smallFont);
            painter.drawText(xRight + pad, yRight, blockW - 2 * pad, lineH,
                             Qt::AlignLeft | Qt::AlignVCenter, "Adresse de livraison");

            painter.setPen(QColor("#e2e8f0"));
            const int dividerY = blockY + blockH + 30;
            painter.drawLine(margin, dividerY, pageW - margin, dividerY);

            QFont summaryFont("Segoe UI", 8, QFont::Bold);
            QFontMetricsF summaryFm(summaryFont, painter.device());
            const int summaryH = static_cast<int>(summaryFm.height()) + 12;
            const int summaryY = dividerY + 20;
            painter.setPen(QColor("#334155"));
            painter.setFont(summaryFont);
            painter.drawText(margin, summaryY, pageW - 2 * margin, summaryH,
                             Qt::AlignLeft | Qt::AlignVCenter,
                             QString("Total commandes: %1   |   Bacs: %2   |   Total: %3")
                                 .arg(totalCmds)
                                 .arg(totalBacs)
                                 .arg(fr.toString(totalCA, 'f', 2) + " TND"));
        }

        painter.setPen(QColor("#e2e8f0"));
        painter.drawLine(margin, h - 20, pageW - margin, h - 20);
    };

    auto drawFooter = [&]() {
        painter.setPen(QColor("#cbd5e1"));
        painter.drawLine(margin, pageH - footerH, pageW - margin, pageH - footerH);
        painter.setFont(QFont("Segoe UI", 7));
        painter.setPen(QColor("#64748b"));
        painter.drawText(margin, pageH - footerH + 30, pageW - 2 * margin, 40,
                         Qt::AlignLeft | Qt::AlignVCenter,
                         "WasteGuard | Facture Commandes");
        painter.drawText(pageW - margin - 200, pageH - footerH + 30, 200, 40,
                         Qt::AlignRight | Qt::AlignVCenter,
                         QString("Page %1").arg(pageNumber));
    };

    drawHeader(false);

    int y = headerH + 120;
    const int tableW = pageW - 2 * margin;
    const int rowH = 60;
    const int totalsBoxH = 320;
    const int reservedBottom = totalsBoxH + 30;

    QStringList headers = {"Reference", "Date Cmd", "Date Liv", "Qte", "Priorite", "Statut", "Montant"};
    QList<int> colMap = {0, 5, 6, 1, 2, 3, 7};
    QVector<double> colFractions = {0.20, 0.14, 0.14, 0.08, 0.14, 0.14, 0.16};
    QVector<int> colWidths;
    for (double f : colFractions) colWidths << qRound(tableW * f);

    auto drawTableHeader = [&]() {
        painter.setPen(Qt::NoPen);
        painter.setBrush(QColor("#0f172a"));
        painter.drawRoundedRect(margin, y, tableW, 60, 10, 10);
        painter.setPen(Qt::white);
        painter.setFont(QFont("Segoe UI", 8, QFont::Bold));
        int x = margin;
        for (int i = 0; i < headers.size(); ++i) {
            painter.drawText(x + 10, y, colWidths[i] - 10, 60, Qt::AlignLeft | Qt::AlignVCenter, headers[i]);
            x += colWidths[i];
        }
        y += 70;
    };

    drawTableHeader();
    painter.setFont(QFont("Segoe UI", 8));

    if (t && t->rowCount() > 0) {
        for (int i = 0; i < t->rowCount(); ++i) {
            if (y + rowH > pageH - footerH - reservedBottom) {
                drawFooter();
                writer.newPage();
                painter.setRenderHint(QPainter::Antialiasing);
                pageNumber++;
                drawHeader(true);
                y = compactHeaderH + 20;
                drawTableHeader();
            }

            QColor rowBg = (i % 2 == 0) ? QColor("#f8fafc") : QColor("#ffffff");
            painter.setPen(Qt::NoPen);
            painter.setBrush(rowBg);
            painter.drawRoundedRect(margin, y, tableW, rowH, 8, 8);

            painter.setPen(QColor("#0f172a"));
            int x = margin;
            for (int c = 0; c < colMap.size(); ++c) {
                QString txt;
                if (auto *it = t->item(i, colMap[c])) txt = it->text();
                painter.drawText(x + 10, y, colWidths[c] - 10, rowH,
                                 Qt::AlignLeft | Qt::AlignVCenter, txt);
                x += colWidths[c];
            }
            y += rowH + 8;
        }
    } else {
        painter.setPen(QColor("#334155"));
        QFont italicFont("Segoe UI", 9);
        italicFont.setItalic(true);
        painter.setFont(italicFont);
        painter.drawText(margin, y + 20, tableW, 40, Qt::AlignLeft | Qt::AlignVCenter,
                         "Aucune commande a exporter.");
        y += 80;
    }

    if (y + totalsBoxH > pageH - footerH - 10) {
        drawFooter();
        writer.newPage();
        painter.setRenderHint(QPainter::Antialiasing);
        pageNumber++;
        drawHeader(true);
        y = compactHeaderH + 20;
    }

    const double subtotal = totalCA;
    const double taxRate = 0.0;
    const double taxValue = subtotal * taxRate;
    const double totalTtc = subtotal + taxValue;

    const int totalsW = 480;
    const int totalsX = pageW - margin - totalsW;
    const int totalsY = y + 10;
    painter.setPen(QColor("#e2e8f0"));
    painter.setBrush(QColor("#ffffff"));
    painter.drawRoundedRect(totalsX, totalsY, totalsW, totalsBoxH, 10, 10);

    painter.setPen(QColor("#0f172a"));
    painter.setFont(QFont("Segoe UI", 9, QFont::Bold));
    painter.drawText(totalsX + 16, totalsY + 40, totalsW - 32, 28, Qt::AlignLeft | Qt::AlignVCenter, "Totaux");

    const int totalsPad = 18;
    const int totalsGap = 16;
    const int valueW = 220;
    const int lineH = 28;
    auto drawTotalLine = [&](int offsetY, const QString &label, const QString &value, bool bold) {
        painter.setFont(QFont("Segoe UI", 8, bold ? QFont::Bold : QFont::Normal));
        painter.setPen(QColor("#334155"));
        const int labelW = totalsW - (totalsPad * 2) - totalsGap - valueW;
        QRect labelRect(totalsX + totalsPad, totalsY + offsetY, labelW, lineH);
        QRect valueRect(totalsX + totalsPad + labelW + totalsGap, totalsY + offsetY, valueW, lineH);
        painter.drawText(labelRect, Qt::AlignLeft | Qt::AlignVCenter, label);
        painter.drawText(valueRect, Qt::AlignRight | Qt::AlignVCenter, value);
    };

    drawTotalLine(110, "Sous-total", fr.toString(subtotal, 'f', 2) + " TND", false);
    drawTotalLine(180, "TVA (0%)", fr.toString(taxValue, 'f', 2) + " TND", false);
    drawTotalLine(250, "Total", fr.toString(totalTtc, 'f', 2) + " TND", true);

    painter.setPen(QColor("#64748b"));
    painter.setFont(QFont("Segoe UI", 8));
    painter.drawText(margin, totalsY + totalsBoxH + 20, pageW - 2 * margin, 30,
                     Qt::AlignLeft | Qt::AlignVCenter, "Merci pour votre confiance.");

    drawFooter();
    painter.end();
    QMessageBox::information(this, "Export PDF", "La facture PDF a ete generee avec succes.");
}

void MainWindow::generateCommandePdfForOrder(int commandeId, int row)
{
    QString defaultName = "Facture_Commande_" + QString::number(commandeId) + "_" + QDate::currentDate().toString("yyyyMMdd") + ".pdf";
    QString fileName = QFileDialog::getSaveFileName(this, "Exporter Facture Commande", defaultName, "PDF Files (*.pdf)");
    if (fileName.isEmpty()) return;
    if (!fileName.endsWith(".pdf", Qt::CaseInsensitive)) {
        fileName += ".pdf";
    }

    QPdfWriter writer(fileName);
    writer.setPageSize(QPageSize::A4);
    writer.setPageMargins(QMarginsF(22, 20, 22, 20));
    writer.setResolution(300);

    QPainter painter(&writer);
    painter.setRenderHint(QPainter::Antialiasing);
    if (!painter.isActive()) {
        QMessageBox::critical(this, "Export PDF", "Impossible de creer le PDF.");
        return;
    }

    const int pageW = writer.width();
    const int pageH = writer.height();
    const int margin = 200;
    const int headerH = pageH - 100;
    const int footerH = 120;
    
    QLocale fr(QLocale::French);
    
    // Get order information from the table
    if (!ui->tableProduits_2 || row < 0 || row >= ui->tableProduits_2->rowCount()) {
        QMessageBox::warning(this, "Erreur", "Commande non trouvee dans la table.");
        return;
    }
    
    QString reference = ui->tableProduits_2->item(row, 0) ? ui->tableProduits_2->item(row, 0)->text() : "---";
    QString quantity = ui->tableProduits_2->item(row, 1) ? ui->tableProduits_2->item(row, 1)->text() : "0";
    QString priority = ui->tableProduits_2->item(row, 2) ? ui->tableProduits_2->item(row, 2)->text() : "---";
    QString status = ui->tableProduits_2->item(row, 3) ? ui->tableProduits_2->item(row, 3)->text() : "---";
    QString address = ui->tableProduits_2->item(row, 4) ? ui->tableProduits_2->item(row, 4)->text() : "---";
    QString dateCmd = ui->tableProduits_2->item(row, 5) ? ui->tableProduits_2->item(row, 5)->text() : QDate::currentDate().toString("yyyy-MM-dd");
    QString dateLivr = ui->tableProduits_2->item(row, 6) ? ui->tableProduits_2->item(row, 6)->text() : "---";
    QString price = ui->tableProduits_2->item(row, 7) ? ui->tableProduits_2->item(row, 7)->text() : "0 TND";
    
    // Get client info
    int idClient = ui->tableProduits_2->item(row, 0) ? ui->tableProduits_2->item(row, 0)->data(Qt::UserRole).toInt() : 0;
    QString clientNom = "---";
    QString clientEmail = "---";
    QString clientTel = "---";
    
    if (idClient > 0) {
        QSqlQuery qClient;
        qClient.prepare("SELECT NOM, EMAIL, TELEPHONE FROM CLIENT WHERE ID_CLIENT = :id");
        qClient.addBindValue(idClient);
        if (qClient.exec() && qClient.next()) {
            clientNom = qClient.value(0).toString();
            clientEmail = qClient.value(1).toString();
            clientTel = qClient.value(2).toString();
        }
    }
    
    // Get bins associated with this order
    struct BinDetail { QString modele; int qty; double prix; };
    QList<BinDetail> binDetails;
    
    QSqlQuery qBacs;
    qBacs.prepare(
        "SELECT bi.MODELE, cb.QTE, cb.PRIX_UNITAIRE "
        "FROM COMMANDE_BAC cb "
        "JOIN BAC_INTEL bi ON cb.ID_BAC = bi.ID_BAC "
        "WHERE cb.ID_COMMANDE = :idCmd "
        "ORDER BY bi.MODELE"
    );
    qBacs.addBindValue(commandeId);
    if (qBacs.exec()) {
        while (qBacs.next()) {
            BinDetail bd;
            bd.modele = qBacs.value(0).toString();
            bd.qty = qBacs.value(1).toInt();
            bd.prix = qBacs.value(2).toDouble();
            binDetails.append(bd);
        }
    }
    
    // ===== DRAW HEADER =====
    painter.fillRect(0, 0, pageW, headerH, QColor("#f8fafc"));
    
    QPixmap logo(":/wasteguard_logo.png");
    if (logo.isNull()) logo.load("wasteguard_logo.png");
    
    int logoH = 80;
    int titleX = margin;
    if (!logo.isNull()) {
        painter.drawPixmap(margin, 40, logo.scaledToHeight(logoH, Qt::SmoothTransformation));
        titleX = margin + (logoH + 40);
    }
    
    painter.setPen(QColor("#0f172a"));
    painter.setFont(QFont("Segoe UI", 26, QFont::Bold));
    painter.drawText(titleX, 60, pageW - margin - titleX, 70,
                     Qt::AlignLeft | Qt::AlignVCenter, "FACTURE");
    painter.setFont(QFont("Segoe UI", 11, QFont::Normal));
    painter.drawText(titleX, 144, pageW - margin - titleX, 40,
                     Qt::AlignLeft | Qt::AlignVCenter, "Commande Specifique");
    
    // Invoice info (right side)
    const int infoW = 420;
    const int infoX = pageW - margin - infoW;
    int infoY = 70;
    QFont infoBoldFont("Segoe UI", 10, QFont::Bold);
    QFont infoNormFont("Segoe UI", 10, QFont::Normal);
    QFontMetricsF infoBoldFm(infoBoldFont, painter.device());
    QFontMetricsF infoNormFm(infoNormFont, painter.device());
    const int infoLineH = static_cast<int>(qMax(infoBoldFm.height(), infoNormFm.height())) + 10;
    
    painter.setFont(infoBoldFont);
    painter.setPen(QColor("#0f172a"));
    painter.drawText(infoX, infoY, infoW, infoLineH,
                     Qt::AlignRight | Qt::AlignVCenter, "Ref: " + reference);
    infoY += infoLineH;
    painter.setFont(infoNormFont);
    painter.drawText(infoX, infoY, infoW, infoLineH,
                     Qt::AlignRight | Qt::AlignVCenter, "Date: " + dateCmd);
    infoY += infoLineH;
    painter.drawText(infoX, infoY, infoW, infoLineH,
                     Qt::AlignRight | Qt::AlignVCenter, "Livraison: " + dateLivr);
    
    // Client info boxes
    const int gap = 40;
    const int blockW = (pageW - 2 * margin - gap) / 2;
    const int blockH = 350;
    const int blockY = 300;
    const int pad = 24;
    
    painter.setPen(QColor("#e2e8f0"));
    painter.setBrush(Qt::white);
    painter.drawRoundedRect(margin, blockY, blockW, blockH, 10, 10);
    painter.drawRoundedRect(margin + blockW + gap, blockY, blockW, blockH, 10, 10);
    
    QFont labelFont("Segoe UI", 9, QFont::Bold);
    QFont textFont("Segoe UI", 9);
    QFont smallFont("Segoe UI", 8);
    QFontMetricsF fm(textFont, painter.device());
    const int lineH = static_cast<int>(fm.height()) + 12;
    
    // Left block: WasteGuard
    int yLeft = blockY + pad + 2;
    painter.setPen(QColor("#0f172a"));
    painter.setFont(labelFont);
    painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, "Emis par");
    yLeft += lineH + 4;
    painter.setFont(textFont);
    painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, "WasteGuard");
    yLeft += lineH;
    painter.setFont(smallFont);
    painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, "support@wasteguard.com");
    yLeft += lineH + 8;
    painter.setFont(smallFont);
    painter.drawText(margin + pad, yLeft, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, "Tunis, Tunisia");
    
    // Right block: Client
    int xRight = margin + blockW + gap;
    int yRight = blockY + pad + 2;
    painter.setPen(QColor("#0f172a"));
    painter.setFont(labelFont);
    painter.drawText(xRight + pad, yRight, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, "Facture a");
    yRight += lineH + 4;
    painter.setFont(textFont);
    painter.drawText(QRect(xRight + pad, yRight, blockW - 2 * pad, lineH * 2),
                     Qt::AlignLeft | Qt::AlignTop | Qt::TextWordWrap,
                     clientNom);
    yRight += lineH * 2;
    painter.setFont(smallFont);
    painter.drawText(xRight + pad, yRight, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, clientEmail);
    yRight += lineH;
    painter.drawText(xRight + pad, yRight, blockW - 2 * pad, lineH,
                     Qt::AlignLeft | Qt::AlignVCenter, clientTel);
    
    int y = blockY + blockH + 100;
    
    // ===== TABLE: BIN DETAILS =====
    painter.setPen(Qt::NoPen);
    painter.setBrush(QColor("#1a365d"));
    painter.drawRoundedRect(margin, y, pageW - 2 * margin, 70, 10, 10);
    
    painter.setPen(Qt::white);
    painter.setFont(QFont("Segoe UI", 11, QFont::Bold));
    int colW1 = (pageW - 2 * margin) * 0.45;
    int colW2 = (pageW - 2 * margin) * 0.20;
    int colW3 = (pageW - 2 * margin) * 0.35;
    
    painter.drawText(margin + 25, y + 12, colW1 - 40, 46, Qt::AlignLeft | Qt::AlignVCenter, "Modele Bac");
    painter.drawText(margin + colW1 + 15, y + 12, colW2 - 30, 46, Qt::AlignCenter | Qt::AlignVCenter, "Quantite");
    painter.drawText(margin + colW1 + colW2 + 15, y + 12, colW3 - 40, 46, Qt::AlignRight | Qt::AlignVCenter, "Prix Unitaire");
    
    y += 85;
    
    painter.setFont(QFont("Segoe UI", 10, QFont::Normal));
    const int rowHeight = 80;
    
    double totalAmount = 0.0;
    for (const auto &bin : binDetails) {
        painter.fillRect(margin, y, pageW - 2 * margin, rowHeight, QColor("#ffffff"));
        painter.setPen(QColor("#cbd5e1"));
        painter.drawRect(margin, y, pageW - 2 * margin, rowHeight);
        
        painter.setPen(Qt::white);
        painter.setFont(QFont("Segoe UI", 10, QFont::Bold));
        painter.fillRect(margin, y, pageW - 2 * margin, rowHeight, QColor("#2c5282"));
        painter.drawText(margin + 25, y + 8, colW1 - 40, rowHeight - 16, Qt::AlignLeft | Qt::AlignVCenter | Qt::TextWordWrap, bin.modele);
        painter.drawText(margin + colW1 + 15, y + 8, colW2 - 30, rowHeight - 16, Qt::AlignCenter | Qt::AlignVCenter, QString::number(bin.qty));
        
        // Use actual unit price from database
        totalAmount += bin.prix * bin.qty;
        painter.drawText(margin + colW1 + colW2 + 15, y + 8, colW3 - 40, rowHeight - 16, Qt::AlignRight | Qt::AlignVCenter, 
                        QString::number(bin.prix, 'f', 2) + " TND");
        
        y += rowHeight + 3;
    }
    
    if (binDetails.isEmpty()) {
        painter.fillRect(margin, y, pageW - 2 * margin, rowHeight, QColor("#2c5282"));
        painter.setPen(QColor("#cbd5e1"));
        painter.drawRect(margin, y, pageW - 2 * margin, rowHeight);
        painter.setPen(Qt::white);
        painter.setFont(QFont("Segoe UI", 10, QFont::Normal));
        painter.drawText(margin + 25, y + 8, pageW - 2 * margin - 50, rowHeight - 16, Qt::AlignCenter | Qt::AlignVCenter, "Aucun bac dans cette commande");
        y += rowHeight + 5;
    }
    
    y += 60;
    
    // ===== TOTALS BOX =====
    const int totalsBoxH = 560;
    const int totalsW = 1050;
    const int totalsX = pageW - margin - totalsW;
    const int totalsY = y;
    painter.setPen(QColor("#cbd5e1"));
    painter.setBrush(QColor("#ffffff"));
    painter.drawRoundedRect(totalsX, totalsY, totalsW, totalsBoxH, 10, 10);
    
    painter.setPen(QColor("#1a365d"));
    painter.setFont(QFont("Segoe UI", 15, QFont::Bold));
    painter.drawText(totalsX + 40, totalsY + 35, totalsW - 80, 50, Qt::AlignLeft | Qt::AlignVCenter, "Recapitulatif");
    
    const int totalsPad = 50;
    const int totalsGap = 50;
    const int valueW = 400;
    const int lineH2 = 55;
    auto drawTotalLine = [&](int offsetY, const QString &label, const QString &value, bool bold) {
        painter.setFont(QFont("Segoe UI", bold ? 13 : 11, bold ? QFont::Bold : QFont::Normal));
        painter.setPen(QColor("#334155"));
        const int labelW = totalsW - (totalsPad * 2) - totalsGap - valueW;
        QRect labelRect(totalsX + totalsPad, totalsY + offsetY, labelW, lineH2);
        QRect valueRect(totalsX + totalsPad + labelW + totalsGap, totalsY + offsetY, valueW - 10, lineH2);
        painter.drawText(labelRect, Qt::AlignLeft | Qt::AlignVCenter, label);
        painter.setPen(bold ? QColor("#1a365d") : QColor("#475569"));
        painter.setFont(QFont("Segoe UI", bold ? 14 : 12, bold ? QFont::Bold : QFont::Normal));
        painter.drawText(valueRect, Qt::AlignRight | Qt::AlignVCenter, value);
    };
    
    double taxValue = totalAmount * 0.0; // Tax rate 0%
    double totalTtc = totalAmount + taxValue;
    
    drawTotalLine(110, "Sous-total", fr.toString(totalAmount, 'f', 2) + " TND", false);
    drawTotalLine(195, "TVA (0%)", fr.toString(taxValue, 'f', 2) + " TND", false);
    
    painter.setPen(QColor("#1a365d"));
    painter.setBrush(QColor("#f0f4f8"));
painter.drawRoundedRect(totalsX + 25, totalsY + 320, totalsW - 50, 130, 8, 8);
    drawTotalLine(335, "Total", fr.toString(totalTtc, 'f', 2) + " TND", true);
    
    // Additional info
    painter.setPen(QColor("#64748b"));
    painter.setFont(QFont("Segoe UI", 9));
    int infoLineY = totalsY + totalsBoxH + 40;
    painter.drawText(margin, infoLineY, pageW - 2 * margin, 60,
                     Qt::AlignLeft | Qt::TextWordWrap,
                     QString("Statut: %1 | Priorite: %2 | Livraison: %3").arg(status, priority, address));
    
    // ===== SIGNATURE/FOOTER =====
    int footerY = pageH - footerH;
    painter.setPen(QColor("#cbd5e1"));
    painter.drawLine(margin, footerY, pageW - margin, footerY);
    painter.setFont(QFont("Segoe UI", 8));
    painter.setPen(QColor("#94a3b8"));
    painter.drawText(margin, footerY + 15, pageW - 2 * margin, 30, Qt::AlignCenter,
                     "Merci pour votre confiance. | WasteGuard - Systeme Intelligent de Gestion des Dechets");
    painter.drawText(margin, footerY + 55, pageW - 2 * margin, 30, Qt::AlignCenter,
                     "Page 1 | Genere le " + QDateTime::currentDateTime().toString("dd/MM/yyyy HH:mm"));
    
    painter.end();
    QMessageBox::information(this, "Export PDF", "La facture PDF pour la commande " + reference + " a ete generee avec succes.");
}

// ===== PRODUIT FUNCTIONS MERGED =====

void MainWindow::applyProduitFilterAndSort()
{
    m_currentPage = 0; // Reset pagination
    refreshProduitTable();
    refreshCardView();
}

void MainWindow::exportClientPdf() {
    if (!ui->tableWidget_Client) return;

    // Determine which contrat type to export
    QString selectedContrat = ui->cbTrier ? ui->cbTrier->currentText() : "Tous";

    // Collect visible rows matching the filter
    QList<int> rowsToExport;
    for (int i = 0; i < ui->tableWidget_Client->rowCount(); ++i) {
        if (!ui->tableWidget_Client->isRowHidden(i)) {
            rowsToExport.append(i);
        }
    }

    if (rowsToExport.isEmpty()) {
        QMessageBox::warning(this, "Export PDF", "Aucun client a exporter pour le filtre selectionne.");
        return;
    }

    QString defaultName = (selectedContrat == "Tous")
        ? "Rapport_Clients.pdf"
        : "Rapport_Clients_" + selectedContrat + ".pdf";
    QString fileName = QFileDialog::getSaveFileName(this, "Exporter PDF Clients", defaultName, "PDF Files (*.pdf)");
    if (fileName.isEmpty()) return;

    QPdfWriter writer(fileName);
    writer.setPageSize(QPageSize::A4);
    writer.setPageMargins(QMarginsF(25, 25, 25, 25));
    writer.setResolution(300);

    QPainter painter(&writer);
    int pageW = writer.width();

    // -- Colors --
    QColor headerBg(15, 43, 76);
    QColor lightGray(245, 247, 250);
    QColor borderGray(220, 225, 230);
    QColor textDark(30, 30, 30);
    QColor white(255, 255, 255);
    QColor green(39, 174, 96);
    QColor red(231, 76, 60);

    int y = 0;

    // -- Header banner --
    painter.fillRect(0, 0, pageW, 520, headerBg);
    painter.setPen(white);
    painter.setFont(QFont("Segoe UI", 24, QFont::Bold));
    painter.drawText(QRect(200, 60, pageW - 400, 180), Qt::AlignLeft | Qt::AlignVCenter, "WasteGuard");
    painter.setFont(QFont("Segoe UI", 12));
    QString subtitle = (selectedContrat == "Tous")
        ? "Rapport des Clients - Tous les contrats"
        : "Rapport des Clients - Contrat " + selectedContrat;
    painter.drawText(QRect(200, 240, pageW - 400, 120), Qt::AlignLeft | Qt::AlignVCenter, subtitle);
    painter.setFont(QFont("Segoe UI", 9));
    painter.drawText(QRect(200, 380, pageW - 400, 100), Qt::AlignLeft | Qt::AlignVCenter,
        "Date : " + QDate::currentDate().toString("dd MMMM yyyy") + "   |   Clients : " + QString::number(rowsToExport.size()));
    y = 660;

    // -- Summary cards --
    int annualCount = 0, monthlyCount = 0;
    for (int row : rowsToExport) {
        QTableWidgetItem *item = ui->tableWidget_Client->item(row, 4);
        if (item && item->text().contains("Annuel", Qt::CaseInsensitive)) annualCount++;
        else monthlyCount++;
    }
    int totalFiltered = rowsToExport.size();

    int cardW = (pageW - 300) / 3;
    int cardH = 300;
    int cardY = y;

    auto drawCard = [&](int idx, int value, const QString &label, QColor valueColor) {
        int cx = 100 + idx * (cardW + 50);
        painter.fillRect(cx, cardY, cardW, cardH, white);
        painter.setPen(QPen(borderGray, 3));
        painter.drawRoundedRect(cx, cardY, cardW, cardH, 20, 20);
        painter.setPen(valueColor);
        painter.setFont(QFont("Segoe UI", 20, QFont::Bold));
        painter.drawText(QRect(cx, cardY + 30, cardW, 140), Qt::AlignCenter, QString::number(value));
        painter.setFont(QFont("Segoe UI", 9));
        painter.setPen(textDark);
        painter.drawText(QRect(cx, cardY + 170, cardW, 100), Qt::AlignCenter, label);
    };
    drawCard(0, totalFiltered, "Total Clients", headerBg);
    drawCard(1, annualCount, "Contrat Annuel", green);
    drawCard(2, monthlyCount, "Autres Contrats", red);

    y = cardY + cardH + 160;

    // -- Table header --
    QStringList headers = {"Matricule", "Nom", "Email", "Type Contrat", "Date Creation", "Date Expiration", "Telephone"};
    int colCount = headers.size();
    int colW = (pageW - 200) / colCount;
    int rowH = 240;
    int xStart = 100;

    auto drawTableHeader = [&]() {
        painter.fillRect(xStart, y, pageW - 200, rowH, headerBg);
        painter.setPen(white);
        painter.setFont(QFont("Segoe UI", 9, QFont::Bold));
        for (int c = 0; c < colCount; ++c)
            painter.drawText(QRect(xStart + c * colW + 40, y, colW - 80, rowH), Qt::AlignVCenter | Qt::AlignLeft, headers[c]);
        y += rowH;
    };
    drawTableHeader();

    // -- Table rows --
    int visibleIdx = 0;
    for (int row : rowsToExport) {
        if (y + rowH > writer.height() - 400) {
            painter.setPen(borderGray);
            painter.drawLine(100, writer.height() - 300, pageW - 100, writer.height() - 300);
            painter.setPen(QColor(150, 150, 150));
            painter.setFont(QFont("Segoe UI", 7));
            painter.drawText(QRect(100, writer.height() - 280, pageW - 200, 200), Qt::AlignCenter,
                "WasteGuard - Page " + QString::number(writer.logicalDpiX())); // placeholder
            writer.newPage();
            y = 200;
            drawTableHeader();
        }

        QColor rowBg = (visibleIdx % 2 == 0) ? white : lightGray;
        painter.fillRect(xStart, y, pageW - 200, rowH, rowBg);
        painter.setPen(QPen(borderGray, 1));
        painter.drawRect(xStart, y, pageW - 200, rowH);
        painter.setPen(textDark);
        painter.setFont(QFont("Segoe UI", 8));

        const QList<int> colMap = {1, 2, 3, 4, 5, 6, 7};
        for (int c = 0; c < colMap.size(); ++c) {
            QString txt;
            QTableWidgetItem *item = ui->tableWidget_Client->item(row, colMap[c]);
            if (item) txt = item->text();
            painter.drawText(QRect(xStart + c * colW + 40, y, colW - 80, rowH), Qt::AlignVCenter | Qt::AlignLeft, txt);
        }
        y += rowH;
        visibleIdx++;
    }

    // -- Footer --
    painter.setPen(borderGray);
    painter.drawLine(100, writer.height() - 300, pageW - 100, writer.height() - 300);
    painter.setPen(QColor(150, 150, 150));
    painter.setFont(QFont("Segoe UI", 7));
    QString footerText = "WasteGuard - Genere le " + QDate::currentDate().toString("dd/MM/yyyy");
    if (selectedContrat != "Tous") footerText += " - Filtre : " + selectedContrat;
    painter.drawText(QRect(100, writer.height() - 280, pageW - 200, 200), Qt::AlignCenter, footerText);

    painter.end();
    QMessageBox::information(this, "Export PDF",
        "Le rapport PDF (" + QString::number(rowsToExport.size()) + " clients) a ete genere avec succes.");
}

void MainWindow::filterClients() {
    if (!ui->tableWidget_Client) return;
    
    QLineEdit *searchEdit = findChild<QLineEdit*>("recherche");
    QComboBox *triCombo = findChild<QComboBox*>("cbTrier");
    
    QString searchText = searchEdit ? searchEdit->text().trimmed().toLower() : QString();
    QString selectedContrat = triCombo ? triCombo->currentText() : "Tous";

    for (int i = 0; i < ui->tableWidget_Client->rowCount(); ++i) {
        bool matchSearch = true;
        bool matchContrat = true;

        // Search by matricule, nom or telephone
        if (!searchText.isEmpty()) {
            QTableWidgetItem *matItem = ui->tableWidget_Client->item(i, 1); 
            QTableWidgetItem *nomItem = ui->tableWidget_Client->item(i, 2);
            QTableWidgetItem *telItem = ui->tableWidget_Client->item(i, 7);
            
            matchSearch = false;
            if (matItem && matItem->text().toLower().contains(searchText)) matchSearch = true;
            else if (nomItem && nomItem->text().toLower().contains(searchText)) matchSearch = true;
            else if (telItem && telItem->text().toLower().contains(searchText)) matchSearch = true;
        }

        // Filter by Type de Contrat (Column 4)
        if (selectedContrat != "Tous" && selectedContrat != "Filtrer par contrat") {
            QTableWidgetItem *contratItem = ui->tableWidget_Client->item(i, 4);
            if (contratItem) {
                matchContrat = contratItem->text().contains(selectedContrat, Qt::CaseInsensitive);
            } else {
                matchContrat = false;
            }
        }

        ui->tableWidget_Client->setRowHidden(i, !(matchSearch && matchContrat));
    }
}

void MainWindow::generateMaintenancePdf()
{
    auto* table = maintenanceTable();
    if (!table) return;

    // Collect checked rows
    QList<int> checkedRows;
    for (int i = 0; i < table->rowCount(); ++i) {
        QTableWidgetItem *chk = table->item(i, 0);
        if (chk && chk->checkState() == Qt::Checked)
            checkedRows.append(i);
    }
    if (checkedRows.isEmpty()) {
        QMessageBox::warning(this, "Rapport PDF", "Veuillez cocher au moins une intervention.");
        return;
    }

    // Generate one PDF per checked intervention
    int generated = 0;
    for (int row : checkedRows) {
        QString ref      = table->item(row, 1) ? table->item(row, 1)->text() : "UNKNOWN";
        QString date     = table->item(row, 2) ? table->item(row, 2)->text() : "";
        QString statut   = table->item(row, 3) ? table->item(row, 3)->text() : "";
        QString cout     = table->item(row, 4) ? table->item(row, 4)->text() : "";
        QString duree    = table->item(row, 5) ? table->item(row, 5)->text() : "";
        QString priorite = table->item(row, 6) ? table->item(row, 6)->text() : "";
        QString idStr    = table->item(row, 8) ? table->item(row, 8)->text() : "";
        QString type     = table->item(row, 9) ? table->item(row, 9)->text() : "";

        // Query additional info from DB
        QString description, adresse;
        int idBac = 0;
        {
            QSqlQuery q;
            q.prepare("SELECT ID_BAC FROM INTERVENTION WHERE ID_INTER = :id");
            q.bindValue(":id", idStr.toInt());
            if (q.exec() && q.next()) idBac = q.value(0).toInt();
        }
        if (idBac > 0) {
            QSqlQuery q;
            q.prepare("SELECT LOCALISATION_STOCK FROM BAC_INTEL WHERE ID_BAC = :id");
            q.bindValue(":id", idBac);
            if (q.exec() && q.next()) adresse = q.value(0).toString();
        }

        // File path
        QString safeRef = ref;
        safeRef.replace(QRegularExpression("[^a-zA-Z0-9_-]"), "_");
        QString dir = QStandardPaths::writableLocation(QStandardPaths::DesktopLocation);
        QString filePath = dir + "/Maintenance_Request_" + safeRef + ".pdf";

        QPdfWriter writer(filePath);
        writer.setPageSize(QPageSize(QPageSize::A4));
        writer.setPageMargins(QMarginsF(25, 20, 25, 20), QPageLayout::Millimeter);
        writer.setResolution(300);

        QPainter p(&writer);
        int W = writer.width();
        int pageH = writer.height();

        // Colors
        QColor headerBg(31, 60, 90);       // #1f3c5a
        QColor sectionBg(241, 245, 249);    // #f1f5f9
        QColor textDark(30, 41, 59);        // #1e293b
        QColor textGray(100, 116, 139);     // #64748b
        QColor accent(59, 130, 246);        // #3b82f6
        QColor white(255, 255, 255);
        QColor borderColor(226, 232, 240);  // #e2e8f0
        QColor greenBg(220, 252, 231);      // #dcfce7
        QColor greenText(22, 163, 74);      // #16a34a
        QColor yellowBg(254, 243, 199);     // #fef3c7
        QColor yellowText(217, 119, 6);     // #d97706
        QColor redBg(254, 226, 226);        // #fee2e2
        QColor redText(220, 38, 38);        // #dc2626

        int y = 0;

        // ----------- HEADER BAR -----------
        int headerH = 420;
        p.fillRect(0, 0, W, headerH, headerBg);

        QFont titleFont("Segoe UI", 16, QFont::Bold);
        p.setFont(titleFont);
        p.setPen(white);
        p.drawText(120, 100, W - 240, 140, Qt::AlignLeft | Qt::AlignVCenter, "DEMANDE DE MAINTENANCE");

        QFont subtitleFont("Segoe UI", 8, QFont::Normal);
        p.setFont(subtitleFont);
        p.setPen(QColor(180, 200, 220));
        p.drawText(120, 240, W - 240, 80, Qt::AlignLeft | Qt::AlignVCenter,
                   "Document genere automatiquement | WasteGuard System");

        // Reference badge on right side
        QFont refFont("Segoe UI", 9, QFont::Bold);
        p.setFont(refFont);
        QFontMetrics fm(refFont, &writer);
        int refW = fm.horizontalAdvance(ref) + 120;
        int refH = 100;
        int refX = W - refW - 120;
        int refY = 160;
        p.setBrush(accent);
        p.setPen(Qt::NoPen);
        p.drawRoundedRect(refX, refY, refW, refH, 30, 30);
        p.setPen(white);
        p.drawText(refX, refY, refW, refH, Qt::AlignCenter, ref);

        y = headerH + 80;

        // ----------- DETAILS DE L'INTERVENTION -----------
        auto drawSectionTitle = [&](const QString &title) {
            QFont secFont("Segoe UI", 11, QFont::Bold);
            p.setFont(secFont);
            p.setPen(headerBg);
            p.drawText(120, y, W - 240, 100, Qt::AlignLeft | Qt::AlignVCenter, title);
            y += 120;
            // Accent line
            p.fillRect(120, y - 20, 200, 8, accent);
            y += 20;
        };

        auto drawInfoRow = [&](const QString &label, const QString &value, bool shaded = false) {
            int rowH = 120;
            if (shaded)
                p.fillRect(80, y, W - 160, rowH, sectionBg);
            else
                p.fillRect(80, y, W - 160, rowH, white);

            // Bottom border
            p.fillRect(80, y + rowH - 2, W - 160, 2, borderColor);

            QFont lblFont("Segoe UI", 8, QFont::Bold);
            p.setFont(lblFont);
            p.setPen(textGray);
            p.drawText(140, y, 600, rowH, Qt::AlignLeft | Qt::AlignVCenter, label);

            QFont valFont("Segoe UI", 8, QFont::Normal);
            p.setFont(valFont);
            p.setPen(textDark);
            p.drawText(750, y, W - 900, rowH, Qt::AlignLeft | Qt::AlignVCenter, value);

            y += rowH;
        };

        // Priority badge helper
        auto drawPrioBadge = [&](const QString &prio) {
            int rowH = 120;
            p.fillRect(80, y, W - 160, rowH, white);
            p.fillRect(80, y + rowH - 2, W - 160, 2, borderColor);

            QFont lblFont("Segoe UI", 8, QFont::Bold);
            p.setFont(lblFont);
            p.setPen(textGray);
            p.drawText(140, y, 600, rowH, Qt::AlignLeft | Qt::AlignVCenter, "Priorite");

            // Badge
            QColor bg = greenBg, fg = greenText;
            if (prio.contains("lev", Qt::CaseInsensitive) || prio == "Urgente")
            { bg = yellowBg; fg = yellowText; }
            else if (prio == "Critique") { bg = redBg; fg = redText; }

            QFont badgeFont("Segoe UI", 7, QFont::Bold);
            p.setFont(badgeFont);
            QFontMetrics bfm(badgeFont, &writer);
            int bw = bfm.horizontalAdvance(prio) + 80;
            int bh = 80;
            int bx = 750;
            int by = y + (rowH - bh) / 2;
            p.setBrush(bg);
            p.setPen(Qt::NoPen);
            p.drawRoundedRect(bx, by, bw, bh, 25, 25);
            p.setPen(fg);
            p.drawText(bx, by, bw, bh, Qt::AlignCenter, prio);

            y += rowH;
        };

        drawSectionTitle("DETAILS DE L'INTERVENTION");

        // Info card with rounded rect background
        int cardStart = y; (void)cardStart;
        drawInfoRow("Reference", ref, true);
        drawInfoRow("Date", date, false);
        drawInfoRow("Duree", duree, true);
        drawInfoRow("Cout", cout, false);
        drawInfoRow("Statut", statut, true);
        drawInfoRow("Technicien / Type", type.isEmpty() ? "Non specifie" : type, false);
        drawPrioBadge(priorite);

        y += 60;

        // ----------- INFORMATIONS COMPLEMENTAIRES -----------
        drawSectionTitle("INFORMATIONS COMPLEMENTAIRES");

        drawInfoRow("ID Intervention", idStr, true);
        drawInfoRow("Adresse / Localisation", adresse.isEmpty() ? "Non renseignee" : adresse, false);
        drawInfoRow("ID Bac", idBac > 0 ? QString::number(idBac) : "N/A", true);

        y += 60;

        // ----------- OBSERVATIONS -----------
        drawSectionTitle("OBSERVATIONS");

        int obsH = 300;
        p.setBrush(sectionBg);
        p.setPen(QPen(borderColor, 3));
        p.drawRoundedRect(80, y, W - 160, obsH, 20, 20);

        QFont obsFont("Segoe UI", 7, QFont::Normal);
        p.setFont(obsFont);
        p.setPen(textGray);
        p.drawText(140, y + 30, W - 300, obsH - 60, Qt::AlignLeft | Qt::TextWordWrap,
                   "Intervention " + ref + " planifiee le " + date + ".\n"
                   "Type: " + (type.isEmpty() ? "Maintenance" : type) + " | Priorite: " + priorite + "\n"
                   "Cout estime: " + cout + " | Duree estimee: " + duree);
        y += obsH + 40;

        // ----------- SIGNATURES -----------
        int sigY = pageH - 500;
        if (y > sigY - 100) sigY = y + 80;

        p.fillRect(0, sigY - 40, W, 3, borderColor);

        QFont sigLbl("Segoe UI", 7, QFont::Bold);
        p.setFont(sigLbl);
        p.setPen(textGray);

        int sigW = (W - 240) / 2;
        p.drawText(120, sigY, sigW, 80, Qt::AlignLeft | Qt::AlignVCenter, "Responsable Technique");
        p.drawText(120 + sigW + 40, sigY, sigW, 80, Qt::AlignLeft | Qt::AlignVCenter, "Directeur de Maintenance");

        // Signature lines
        p.setPen(QPen(textGray, 3));
        int lineY = sigY + 200;
        p.drawLine(120, lineY, 120 + sigW - 100, lineY);
        p.drawLine(120 + sigW + 40, lineY, W - 120, lineY);

        // ----------- FOOTER -----------
        int footerY = pageH - 150;
        p.fillRect(0, footerY, W, 150, headerBg);

        QFont footFont("Segoe UI", 6, QFont::Normal);
        p.setFont(footFont);
        p.setPen(QColor(180, 200, 220));
        p.drawText(120, footerY, W - 240, 150, Qt::AlignLeft | Qt::AlignVCenter,
                   "WasteGuard - Smart Waste Collection System | Document confidentiel | " +
                   QDate::currentDate().toString("dd/MM/yyyy"));

        // QR Code placeholder (simple styled square)
        int qrSize = 200;
        int qrX = W - qrSize - 120;
        int qrY = footerY - qrSize - 60;
        p.setBrush(white);
        p.setPen(QPen(borderColor, 4));
        p.drawRoundedRect(qrX, qrY, qrSize, qrSize, 12, 12);

        // Draw a mini QR-like pattern
        p.setBrush(headerBg);
        p.setPen(Qt::NoPen);
        int cellSz = qrSize / 8;
        int pattern[] = {0,0, 0,1, 0,2, 0,6, 0,7,
                         1,0, 1,2, 1,4, 1,7,
                         2,0, 2,1, 2,2, 2,5, 2,6, 2,7,
                         3,4, 3,5,
                         4,3, 4,5,
                         5,0, 5,1, 5,2, 5,4, 5,6,
                         6,0, 6,2, 6,3, 6,5, 6,7,
                         7,0, 7,1, 7,2, 7,4, 7,6, 7,7};
        int patLen = sizeof(pattern) / sizeof(pattern[0]);
        for (int pi = 0; pi < patLen; pi += 2) {
            p.drawRect(qrX + 8 + pattern[pi+1] * cellSz, qrY + 8 + pattern[pi] * cellSz, cellSz - 4, cellSz - 4);
        }

        p.end();
        generated++;

        // Open the generated PDF
        QDesktopServices::openUrl(QUrl::fromLocalFile(filePath));
    }

    // Uncheck all after generation
    for (int i = 0; i < table->rowCount(); ++i) {
        QTableWidgetItem *chk = table->item(i, 0);
        if (chk) chk->setCheckState(Qt::Unchecked);
    }

    QMessageBox::information(this, "Rapport PDF",
        QString::number(generated) + " rapport(s) PDF genere(s) sur le Bureau.");
}



void MainWindow::loadCmdToModificationForm(int row)
{
    if (!ui->tableProduits_2) return;
    currentCmdRow = row;
    ui->tableProduits_2->selectRow(row);

    // Retrieve data from table
    int idClient = ui->tableProduits_2->item(row, 0)->data(Qt::UserRole).toInt();
    int idCmd    = ui->tableProduits_2->item(row, 0)->data(Qt::UserRole + 1).toInt();
    (void)idCmd; // Read from table but used by other operations
    int qte      = ui->tableProduits_2->item(row, 1)->text().toInt();
    QString prio = ui->tableProduits_2->item(row, 2)->text();
    QString statut = ui->tableProduits_2->item(row, 3)->text();
    QString adresse = ui->tableProduits_2->item(row, 4)->text();
    // Price string "3200 TND" -> 3200
    double prix = ui->tableProduits_2->item(row, 8)->text().split(" ").first().toDouble();

    // Populate UI
    QComboBox *cbClientMod = findChild<QComboBox*>("cb_client_mod");
    if (!cbClientMod) cbClientMod = findChild<QComboBox*>("cb_client_add");
    if (cbClientMod) {
        int idx = cbClientMod->findData(idClient);
        if (idx >= 0) cbClientMod->setCurrentIndex(idx);
    }
    if (ui->sb_qty_add_2) ui->sb_qty_add_2->setValue(qte);
    if (ui->cb_model_add_2) ui->cb_model_add_2->setCurrentText(prio);
    if (ui->cb_status_add_2) ui->cb_status_add_2->setCurrentText(statut);
    if (ui->dsb_price_add_2) ui->dsb_price_add_2->setValue(prix);
    if (ui->textEdit_2) ui->textEdit_2->setPlainText(adresse == "---" ? "" : adresse);

    if (m_mapModOrder && m_mapModOrder->rootObject()) {
        QString startAddr = ui->tableProduits_2->item(row, 0)->data(Qt::UserRole + 2).toString();
        double sLat = 0.0;
        double sLon = 0.0;
        if (!startAddr.isEmpty() && startAddr != "---") {
            QStringList parts = startAddr.split(",");
            if (parts.size() == 2) {
                sLat = parts[0].trimmed().toDouble();
                sLon = parts[1].trimmed().toDouble();
            }
        }
        
        m_mapModOrder->rootObject()->setProperty("isInitialSet", true);
        QMetaObject::invokeMethod(m_mapModOrder->rootObject(), "setInitialLocation",
            Q_ARG(QVariant, sLat), Q_ARG(QVariant, sLon), Q_ARG(QVariant, adresse == "---" ? "" : adresse));
        QMetaObject::invokeMethod(m_mapModOrder->rootObject(), "setPathHistory",
            Q_ARG(QVariant, ui->tableProduits_2->item(row, 0)->data(Qt::UserRole + 3).toString()));
    }

    populateCommandeBacListMod(idCmd);

    QDate dCmd = QDate::fromString(ui->tableProduits_2->item(row, 5)->text(), "yyyy-MM-dd");
    if (dCmd.isValid()) {
        ui->comboBox_7->setCurrentText(QString("%1").arg(dCmd.day(), 2, 10, QChar('0')));
        ui->comboBox_8->setCurrentText(QString("%1").arg(dCmd.month(), 2, 10, QChar('0')));
        ui->comboBox_9->setCurrentText(QString::number(dCmd.year()));
    }
    
    QDate dLiv = QDate::fromString(ui->tableProduits_2->item(row, 7)->text(), "yyyy-MM-dd");
    if (dLiv.isValid()) {
        ui->comboBox_13->setCurrentText(QString("%1").arg(dLiv.day(), 2, 10, QChar('0')));
        ui->comboBox_14->setCurrentText(QString("%1").arg(dLiv.month(), 2, 10, QChar('0')));
        ui->comboBox_15->setCurrentText(QString::number(dLiv.year()));
    }
}

void MainWindow::loadProduitToModificationForm(int row)
{
    QTableWidget *t = produitTable();
    if (!t || row < 0 || row >= t->rowCount()) return;

    currentProduitRow = row;
    t->selectRow(row);

    const QString reference = t->item(row, 0) ? t->item(row, 0)->text().trimmed() : QString();
    const QString modele = t->item(row, 1) ? t->item(row, 1)->text().trimmed() : QString();
    const QString status = t->item(row, 5) ? t->item(row, 5)->text().trimmed() : QString("En Stock");
    const int quantite = t->item(row, 0) ? t->item(row, 0)->data(PROD_ROLE_CUR).toInt() : 0;
    const double prix = t->item(row, 3) ? t->item(row, 3)->text().trimmed().toDouble() : 0.0;
    const int capacite = t->item(row, 0) ? t->item(row, 0)->data(PROD_ROLE_MAX).toInt() : 100;
    const int battery = t->item(row, 0) ? t->item(row, 0)->data(PROD_ROLE_BATTERY).toInt() : 12000;

    if (ui->prod_ln_ref_mod) ui->prod_ln_ref_mod->setText(reference);
    if (ui->prod_dsb_price_mod) ui->prod_dsb_price_mod->setValue(prix);
    if (ui->prod_sb_qty_mod) ui->prod_sb_qty_mod->setValue(quantite);
    if (ui->prod_slider_cap_mod) ui->prod_slider_cap_mod->setValue(qMax(ui->prod_slider_cap_mod->minimum(), qMin(ui->prod_slider_cap_mod->maximum(), capacite)));
    if (ui->prod_slider_bat_mod) ui->prod_slider_bat_mod->setValue(qMax(ui->prod_slider_bat_mod->minimum(), qMin(ui->prod_slider_bat_mod->maximum(), battery)));

    QLineEdit *modelLineMod = findChild<QLineEdit*>("prod_ln_model_mod");
    if (modelLineMod) {
        modelLineMod->setText(modele);
    } else if (QComboBox *modelComboMod = findChild<QComboBox*>("prod_cb_model_mod")) {
        setComboTextSafe(modelComboMod, modele);
    }
    setComboTextSafe(ui->prod_cb_status_mod, status);
    const QString caracteristiques = t->item(row, 0) ? t->item(row, 0)->data(PROD_ROLE_FEATURES).toString() : QString();
    QStringList featuresList = caracteristiques.split(",", Qt::SkipEmptyParts);
    for (QString &f : featuresList) f = f.trimmed();
    int idBac = -1;
    if (auto *it = t->item(row, 0)) idBac = it->data(PROD_ROLE_ID).toInt();
    if (ui->prod_lstCharacteristics_mod) {
        ui->prod_lstCharacteristics_mod->setProperty("prodCurrentFeatures", featuresList);
        ui->prod_lstCharacteristics_mod->setProperty("prodCurrentQty", quantite);
    }
    refreshProduitFeatureLists(featuresList, -1, quantite, idBac);
    m_lastProdQty = quantite;

    // Force update labels in case setValue didn't change (no signal)
    if (ui->prod_slider_bat_mod) {
        QLabel *lblTitle = ui->pageProduit->findChild<QLabel*>("prod_l_bat_m");
        updateProduitSliderTitleLabel(ui->prod_slider_bat_mod, lblTitle, "mAh");
    }
    if (ui->prod_slider_cap_mod) {
        QLabel *lblTitle = ui->pageProduit->findChild<QLabel*>("prod_l_cap_m");
        updateProduitSliderTitleLabel(ui->prod_slider_cap_mod, lblTitle, "L");
    }

    // Load Image
    const QString imagePath = t->item(row, 0) ? t->item(row, 0)->data(PROD_ROLE_IMAGE).toString() : QString();
    m_prodImagePathMod = imagePath;

    const QString loc = t->item(row, 0) ? t->item(row, 0)->data(PROD_ROLE_LOC).toString() : QString();
    m_selectedEmplacement = loc;
    if (auto *lbl = ui->pageProduit->findChild<QLabel*>("prod_l5_m")) {
        if (!loc.isEmpty()) {
            const QString pin = QString::fromUcs4(U"\U0001F4CD");
            lbl->setText(QString("%1 Emplacement selectionne : %2").arg(pin, loc));
            lbl->setStyleSheet("color: #fbbf24; font-size: 13px; font-weight: 700; padding: 10px 16px; "
                               "background: rgba(251, 191, 36, 0.05); border: 1px solid rgba(251, 191, 36, 0.2); "
                               "border-radius: 10px; font-family: 'Segoe UI Emoji','Segoe UI Symbol','Segoe UI';");
        } else {
            lbl->setText("Plan du depot : cliquer ici pour choisir");
            lbl->setStyleSheet("font-family: 'Segoe UI Emoji','Segoe UI Symbol','Segoe UI';");
        }
    }
    if (ui->prod_imgBin) {
        ui->prod_imgBin->setProperty("prodImageHeight", 170);
        ui->prod_imgBin->setProperty("prodImageWidth", 260);
        applyProduitImageLabel(ui->prod_imgBin, imagePath, "[ Image Actuelle ]");
    }
    refreshProduitRealtimeValidation(this, true);
}

