void MainWindow::on_btnSave_CmdMod_clicked()
{
    QComboBox *cbClientMod = findChild<QComboBox*>("cb_client_mod");
    if (!cbClientMod) cbClientMod = findChild<QComboBox*>("cb_client_add");
    if (!cbClientMod || currentCmdRow < 0) return;

    {
    QString schemaError;
    if (!ensureCommandeBacTableExists(&schemaError)) {
        QMessageBox::critical(this, "Modification Commande", "La table COMMANDE_BAC est introuvable.\n" + schemaError);
        return;
    }

    const int cmdId = m_lastCmdId;
    const QString cmdRefer = m_lastCmdRefer;
    const int clientId = cbClientMod->currentData().toInt();
    if (cmdId <= 0 || clientId <= 0) {
        QMessageBox::warning(this, "Modification Commande", "Veuillez selectionner un client valide.");
        return;
    }

    QList<CommandeBacSelection> selections;
    int totalQte = 0;
    double totalPrix = 0.0;
    collectCommandeBacSelections(ui->lstBacsCmdMod, selections, totalQte, totalPrix);
    if (selections.isEmpty()) {
        QMessageBox::warning(this, "Modification Commande", "Veuillez saisir une quantite pour au moins un bac.");
        return;
    }

    const QString prio = ui->cb_model_add_2 ? ui->cb_model_add_2->currentText() : QString();
    const QString statut = ui->cb_status_add_2 ? ui->cb_status_add_2->currentText() : QString();
    const QDate dCmd(ui->comboBox_9 ? ui->comboBox_9->currentText().toInt() : 0,
                     ui->comboBox_8 ? ui->comboBox_8->currentText().toInt() : 0,
                     ui->comboBox_7 ? ui->comboBox_7->currentText().toInt() : 0);
    const QDate dLiv(ui->comboBox_15 ? ui->comboBox_15->currentText().toInt() : 0,
                     ui->comboBox_14 ? ui->comboBox_14->currentText().toInt() : 0,
                     ui->comboBox_13 ? ui->comboBox_13->currentText().toInt() : 0);
    if (!dCmd.isValid() || !dLiv.isValid()) {
        QMessageBox::warning(this, "Modification Commande", "Les dates saisies sont invalides.");
        return;
    }
    if (dLiv < dCmd) {
        QMessageBox::warning(this, "Modification Commande", "La date de livraison doit etre posterieure ou egale a la date de commande.");
        return;
    }

    QString adresseUI = ui->textEdit_2 ? ui->textEdit_2->toPlainText().trimmed() : QString();
    if (m_mapModOrder && m_mapModOrder->rootObject()) {
        QString mapAddr = m_mapModOrder->rootObject()->property("currentAddress").toString().trimmed();
        if (!mapAddr.isEmpty()) adresseUI = mapAddr;
    }
    
    if (adresseUI.isEmpty()) {
        QMessageBox::warning(this, "Modification Commande", "Veuillez choisir un emplacement de livraison sur la carte (ou saisir une adresse).");
        return;
    }
    const QString dCmdStr = QString("%1-%2-%3")
                                .arg(ui->comboBox_7 ? ui->comboBox_7->currentText() : QString())
                                .arg(ui->comboBox_8 ? ui->comboBox_8->currentText() : QString())
                                .arg(ui->comboBox_9 ? ui->comboBox_9->currentText() : QString());
    const QString dLivStr = QString("%1-%2-%3")
                                .arg(ui->comboBox_13 ? ui->comboBox_13->currentText() : QString())
                                .arg(ui->comboBox_14 ? ui->comboBox_14->currentText() : QString())
                                .arg(ui->comboBox_15 ? ui->comboBox_15->currentText() : QString());

    Ctmp.setId(cmdId);
    Ctmp.setRefer(cmdRefer);
    Ctmp.setIdClient(clientId);
    Ctmp.setQte(totalQte);
    Ctmp.setPriorite(prio);
    Ctmp.setStatut(statut);
    Ctmp.setDateCommande(dCmd);
    Ctmp.setDateLivraison(dLiv);
    Ctmp.setDateCmdStr(dCmdStr);
    Ctmp.setDateLivStr(dLivStr);
    Ctmp.setPrixTotal(totalPrix);
    Ctmp.setAdresse(adresseUI);

    // FIX: Store starting location
    if (m_mapModOrder && m_mapModOrder->rootObject()) {
        double sLat = m_mapModOrder->rootObject()->property("startLat").toDouble();
        double sLon = m_mapModOrder->rootObject()->property("startLon").toDouble();
        if (sLat != 0 || sLon != 0) {
            QString startAddr = QString("%1, %2").arg(sLat, 0, 'f', 5).arg(sLon, 0, 'f', 5);
            Ctmp.setStartAdresse(startAddr);
        }
    }

    if (ui->sb_qty_add_2) ui->sb_qty_add_2->setValue(totalQte);
    if (ui->dsb_price_add_2) ui->dsb_price_add_2->setValue(totalPrix);

    QSqlDatabase db = QSqlDatabase::database();
    if (!db.transaction()) {
        QMessageBox::critical(this, "Modification Commande", "Impossible de demarrer la transaction SQL.");
        return;
    }

    QString persistError;
    if (!restoreCommandeBacSelectionsToStock(cmdId, &persistError)) {
        db.rollback();
        QMessageBox::critical(this, "Erreur", "Erreur de restauration du stock: " + persistError);
        return;
    }
    if (!Ctmp.modifier()) {
        db.rollback();
        QMessageBox::critical(this, "Erreur", "Erreur de modification: " + Ctmp.lastError());
        return;
    }
    if (!applyCommandeBacSelections(cmdId, selections, &persistError)) {
        db.rollback();
        QMessageBox::critical(this, "Erreur", "Erreur d'affectation des bacs: " + persistError);
        return;
    }
    if (!db.commit()) {
        db.rollback();
        QMessageBox::critical(this, "Erreur", "La transaction n'a pas pu etre validee.");
        return;
    }

    QMessageBox::information(this, "Succes", "Commande modifiee avec succes.");
    if (m_mapModOrder && m_mapModOrder->rootObject()) {
        QMetaObject::invokeMethod(m_mapModOrder->rootObject(), "resetMap");
    }
    refreshCommandes();
    populateCommandeBacList();
    if (auto *sw = mainStacked()) {
        if (auto *page = sw->findChild<QWidget*>("pageCmdDashboard", Qt::FindDirectChildrenOnly)) {
            sw->setCurrentWidget(page);
        }
    }
    }
    return;
    
    int idCmd = m_lastCmdId;
    QString refer = m_lastCmdRefer; 
    int idClient = cbClientMod->currentData().toInt();
    QList<int> bacIds;
    double totalPrix = 0.0;
    if (ui->lstBacsCmdMod) {
        for (int i = 0; i < ui->lstBacsCmdMod->count(); ++i) {
            QListWidgetItem *item = ui->lstBacsCmdMod->item(i);
            if (!item || item->checkState() != Qt::Checked) continue;
            const int idBac = item->data(Qt::UserRole).toInt();
            if (idBac <= 0) continue;
            bacIds.append(idBac);
            totalPrix += item->data(Qt::UserRole + 1).toDouble();
        }
    }
    if (bacIds.isEmpty()) {
        QMessageBox::warning(this, "Modification Commande", "Veuillez selectionner au moins un bac.");
        return;
    }
    const int qte = bacIds.size();
    QString prio = ui->cb_model_add_2->currentText();
    QString statut = ui->cb_status_add_2->currentText();
    double prix = totalPrix;

    // Reconstruct selected date
    QDate dCmd(ui->comboBox_9->currentText().toInt(), ui->comboBox_8->currentText().toInt(), ui->comboBox_7->currentText().toInt());
    QDate dLiv(ui->comboBox_15->currentText().toInt(), ui->comboBox_14->currentText().toInt(), ui->comboBox_13->currentText().toInt());
    QString adresseUI = ui->textEdit_2 ? ui->textEdit_2->toPlainText() : "";
    
    Ctmp.setId(idCmd);
    Ctmp.setRefer(refer);
    Ctmp.setIdClient(idClient);
    Ctmp.setQte(qte);
    Ctmp.setPriorite(prio);
    Ctmp.setStatut(statut);
    Ctmp.setDateCommande(dCmd);
    Ctmp.setDateLivraison(dLiv);
    
    // Construction corrigee de la date string DD-MM-YYYY pour MODIFY
    // Modif: Jour=7, Mois=8, Annee=9
    QString dCmdStr = ui->comboBox_7->currentText() + "-" + ui->comboBox_8->currentText() + "-" + ui->comboBox_9->currentText();
    // Modif: Jour=13, Mois=14, Annee=15
    QString dLivStr = ui->comboBox_13->currentText() + "-" + ui->comboBox_14->currentText() + "-" + ui->comboBox_15->currentText();
    Ctmp.setDateCmdStr(dCmdStr);
    Ctmp.setDateLivStr(dLivStr);

    Ctmp.setPrixTotal(prix);
    Ctmp.setAdresse(adresseUI);
    
    if (ui->sb_qty_add_2) ui->sb_qty_add_2->setValue(qte);
    if (ui->dsb_price_add_2) ui->dsb_price_add_2->setValue(prix);

    if(Ctmp.modifier()) {
        releaseBacsForCommande(idCmd);
        if (!bacIds.isEmpty()) {
            QSqlQuery q;
            q.prepare("UPDATE BAC_INTEL SET ID_COMMANDE = :id_cmd WHERE ID_BAC = :id_bac");
            for (int idBac : bacIds) {
                q.bindValue(":id_cmd", idCmd);
                q.bindValue(":id_bac", idBac);
                q.exec();
            }
        }
        QMessageBox::information(this, "Succes", "Commande modifiee.");
        if (m_mapModOrder && m_mapModOrder->rootObject()) {
            QMetaObject::invokeMethod(m_mapModOrder->rootObject(), "resetMap");
        }
        refreshCommandes();
        populateCommandeBacList();
        if (auto *sw = mainStacked()) {
            if (auto *page = sw->findChild<QWidget*>("pageCmdDashboard", Qt::FindDirectChildrenOnly)) {
                sw->setCurrentWidget(page);
            }
        }
    } else {
        QMessageBox::critical(this, "Erreur", "Erreur de modification: " + Ctmp.lastError());
    }
}

