// CONTRACT PDF

void MainWindow::exportSingleClientContratPdf() {
    QList<int> checkedRows;
    for (int i = 0; i < ui->tableWidget_Client->rowCount(); ++i) {
        if (ui->tableWidget_Client->isRowHidden(i)) continue;
        QWidget *w = ui->tableWidget_Client->cellWidget(i, 0);
        if (!w) continue;
        QCheckBox *cb = w->findChild<QCheckBox*>();
        if (cb && cb->isChecked()) {
            checkedRows << i;
        }
    }

    QList<int> selectedRows = checkedRows;
    if (selectedRows.isEmpty()) {
        const int currentRow = ui->tableWidget_Client->currentRow();
        if (currentRow >= 0 && !ui->tableWidget_Client->isRowHidden(currentRow)) {
            selectedRows << currentRow;
        }
    }

    if (selectedRows.isEmpty()) {
        QMessageBox::warning(this, "Export PDF", "Veuillez cocher au moins un client (ou selectionner une ligne)." );
        return;
    }

    QString fileName = QFileDialog::getSaveFileName(
        this,
        "Generer Contrats PDF",
        selectedRows.size() == 1 ? "Contrat_Client.pdf" : "Contrats_Selection.pdf",
        "PDF Files (*.pdf)"
    );
    if (fileName.isEmpty()) return;

    QPdfWriter writer(fileName);
    writer.setPageSize(QPageSize::A4);
    writer.setPageMargins(QMarginsF(0, 0, 0, 0));

    QPainter painter(&writer);
    QImage logo(":/WASTEGUARD (1) (1).png");
    if (logo.isNull()) logo.load(":/wasteguard_logo.png");

    auto drawFancySection = [&](int y, QString title, QStringList labels, QStringList values) {
        painter.setFont(QFont("Segoe UI", 14, QFont::Bold));
        painter.setPen(QColor("#0f2b4c"));
        painter.drawText(700, y, title);
        painter.setPen(QPen(QColor("#e2e8f0"), 2));
        painter.drawLine(700, y + 150, 9300, y + 150);
        int currentY = y + 550;
        painter.setFont(QFont("Segoe UI", 11));
        for (int i = 0; i < labels.size(); ++i) {
            painter.setPen(QColor("#0f2b4c"));
            painter.setFont(QFont("Segoe UI", 11, QFont::Bold));
            painter.drawText(1000, currentY, "- " + labels[i] + " :");
            painter.setPen(Qt::black);
            painter.setFont(QFont("Segoe UI", 11));
            painter.drawText(3500, currentY, values[i]);
            currentY += 500;
        }
        return currentY + 100;
    };


    for (int index = 0; index < selectedRows.size(); ++index) {
        const int rowIdx = selectedRows[index];
        if (index > 0) {
            writer.newPage();
        }

        QString matricule = ui->tableWidget_Client->item(rowIdx, 1) ? ui->tableWidget_Client->item(rowIdx, 1)->text().trimmed() : QString();
        QString nom = ui->tableWidget_Client->item(rowIdx, 2) ? ui->tableWidget_Client->item(rowIdx, 2)->text() : QString();
        QString email = ui->tableWidget_Client->item(rowIdx, 3) ? ui->tableWidget_Client->item(rowIdx, 3)->text() : QString();
        QString contrat = ui->tableWidget_Client->item(rowIdx, 4) ? ui->tableWidget_Client->item(rowIdx, 4)->text() : QString();
        QString dateCreation = ui->tableWidget_Client->item(rowIdx, 5) ? ui->tableWidget_Client->item(rowIdx, 5)->text() : QString();
        QString echeance = ui->tableWidget_Client->item(rowIdx, 6) ? ui->tableWidget_Client->item(rowIdx, 6)->text() : QString();
        QString telephone = ui->tableWidget_Client->item(rowIdx, 7) ? ui->tableWidget_Client->item(rowIdx, 7)->text() : QString();

        painter.setPen(Qt::NoPen);
        painter.setBrush(QColor("#0f2b4c"));
        painter.drawRect(0, 0, 10000, 120);

        if (!logo.isNull()) {
            painter.drawImage(QRect(400, 300, 1400, 1400), logo);
        }

        painter.setPen(QColor("#0f2b4c"));
        painter.setFont(QFont("Segoe UI", 26, QFont::Bold));
        painter.drawText(2000, 800, "WasteGuard Intelligent Solutions");

        painter.setFont(QFont("Segoe UI", 12));
        painter.setPen(QColor("#64748b"));
        painter.drawText(2000, 1150, "Expertise en gestion intelligente et tracabilite des dechets");

        painter.setPen(QColor("#1e293b"));
        painter.setFont(QFont("Segoe UI", 10));
        painter.drawText(7800, 600, "Emis le: " + QDate::currentDate().toString("dd/MM/yyyy"));

        painter.setPen(QPen(QColor("#cbd5e1"), 2));
        painter.setBrush(QColor("#f8fafc"));
        painter.drawRect(7200, 800, 2400, 600);
        painter.setPen(QColor("#0f2b4c"));
        painter.setFont(QFont("Segoe UI", 10, QFont::Bold));
        painter.drawText(7350, 1200, "Ref : WG-2026-" + matricule.toUpper());

        painter.setPen(QPen(QColor("#0f2b4c"), 8));
        painter.drawLine(500, 1800, 9500, 1800);

        int curY = 2500;
        curY = drawFancySection(curY, "1. IDENTIFICATION DES PARTIES", {"Prestataire", "Client", "Contact Client"}, {"WasteGuard (Code Green Solutions)", nom, email});
        curY = drawFancySection(curY, "2. OBJET ET SERVICES", {"Service Souscrit", "Innovation"}, {"Gestion intelligente des dechets IoT", "Optimisation AI et Tri selectif"});
        curY = drawFancySection(curY, "3. CONDITIONS TECHNIQUES", {"Modele de Bac", "Connectivite"}, {"SmartBin X1 Connected v4", "Protocol WasteGuard-Mesh Network"});
        curY = drawFancySection(curY, "4. MAINTENANCE ET SUPPORT", {"Support Inclus", "Delai de Garantie"}, {"Maintenance preventive illimitee", "Intervention sous 24h ouvrees"});
        curY = drawFancySection(curY, "5. INFORMATIONS CONTRACTUELLES", {"Type de Contrat", "Date Creation", "Date Expiration", "Telephone"}, {contrat, dateCreation, echeance, telephone});

        painter.setBrush(QColor("#0f2b4c"));
        painter.setPen(Qt::NoPen);
        painter.drawRect(0, 13200, 10000, 800);
        painter.setPen(Qt::white);
        painter.setFont(QFont("Segoe UI", 8));
        painter.drawText(600, 13700, "CONFIDENTIEL - Ce document est certifie electroniquement par le systeme WasteGuard ERP.");
    }

    painter.end();
    QMessageBox::information(this, "Export PDF", QString("Les contrats (%1 client(s)) ont ete generes avec succes.").arg(selectedRows.size()));
    QDesktopServices::openUrl(QUrl::fromLocalFile(fileName));
}

void MainWindow::openEcoScoreInterface() {
    // Switch to the integrated page inside the module
    if (ui->stackedWidget_Client) {
        ui->stackedWidget_Client->setCurrentWidget(ui->page_stats_client); 
        
        // POPURATE CHARTS PROFESSIONALLY
        QSqlQuery q;
        
        // 1. Top 5 Best Performer Bar Chart
        QBarSet *setBar = new QBarSet("Taux de Tri (%)");
        setBar->setColor(QColor("#10b981")); // WasteGuard Green
        QStringList categories;
        q.exec("SELECT NOM, TAUX_TRI FROM CLIENT ORDER BY TAUX_TRI DESC FETCH FIRST 5 ROWS ONLY");
        while(q.next()) {
            *setBar << q.value(1).toInt();
            categories << q.value(0).toString();
        }
        
        QBarSeries *seriesBar = new QBarSeries();
        seriesBar->append(setBar);
        QChart *barChart = new QChart();
        barChart->addSeries(seriesBar);
        barChart->setTitle("Performance Individuelle (Top 5)");
        barChart->setAnimationOptions(QChart::SeriesAnimations);
        
        QBarCategoryAxis *axisX = new QBarCategoryAxis();
        axisX->append(categories);
        barChart->addAxis(axisX, Qt::AlignBottom);
        seriesBar->attachAxis(axisX);
        
        QValueAxis *axisY = new QValueAxis();
        axisY->setRange(0, 100);
        barChart->addAxis(axisY, Qt::AlignLeft);
        seriesBar->attachAxis(axisY);
        
        ui->chartEcoScoreBar->setChart(barChart);
        ui->chartEcoScoreBar->setRenderHint(QPainter::Antialiasing);

        // 2. Global Tiers Pie Chart (A-D Grades)
        QPieSeries *pieSeries = new QPieSeries();
        int gA=0, gB=0, gC=0, gD=0;
        q.exec("SELECT TAUX_TRI FROM CLIENT");
        while(q.next()){
            int s = q.value(0).toInt();
            if(s>=85) gA++; else if(s>=70) gB++; else if(s>=50) gC++; else gD++;
        }
        
        pieSeries->append("Grade A (Excellent)", gA)->setBrush(QColor("#059669"));
        pieSeries->append("Grade B (Bien)", gB)->setBrush(QColor("#2563eb"));
        pieSeries->append("Grade C (Passable)", gC)->setBrush(QColor("#d97706"));
        pieSeries->append("Grade D (A revoir)", gD)->setBrush(QColor("#dc2626"));

        for (auto *slice : pieSeries->slices()) {
            if (slice->value() > 0) {
                double pct = slice->percentage() * 100.0;
                slice->setLabel(QString("%1\n%2%").arg(slice->label()).arg(pct, 0, 'f', 1));
                slice->setLabelVisible(true);
            }
        }
        
        QChart *pieChart = new QChart();
        pieChart->addSeries(pieSeries);
        pieChart->setTitle("Repartition de la Qualite du Tri");
        pieChart->legend()->setAlignment(Qt::AlignRight);
        
        ui->chartEcoScorePie->setChart(pieChart);
        ui->chartEcoScorePie->setRenderHint(QPainter::Antialiasing);

        // 3. Contract Types Distribution Line/Area
        QPieSeries *contratPie = new QPieSeries();
        q.exec("SELECT TYPE_CONTRAT, COUNT(*) FROM CLIENT GROUP BY TYPE_CONTRAT");
        while(q.next()){
            contratPie->append(q.value(0).toString(), q.value(1).toInt());
        }
        for (auto *slice : contratPie->slices()) {
            if (slice->value() > 0) {
                double pct = slice->percentage() * 100.0;
                slice->setLabel(QString("%1\n%2%").arg(slice->label()).arg(pct, 0, 'f', 1));
                slice->setLabelVisible(true);
            }
        }
        QChart *distChart = new QChart();
        distChart->addSeries(contratPie);
        distChart->setTitle("Distribution des Types de Contrat");
        ui->chartContratDist->setChart(distChart);
        ui->chartContratDist->setRenderHint(QPainter::Antialiasing);
    }
}

